def postgres_statement_timeout_ms() -> int:
    raw = os.environ.get("CHILLCRM_POSTGRES_STATEMENT_TIMEOUT_MS", "").strip()
    try:
        timeout_ms = int(raw) if raw else 8_000
    except ValueError:
        timeout_ms = 8_000
    return max(1_000, min(timeout_ms, 60_000))


class PostgresCompatRow(dict):
    """Small row wrapper that behaves like sqlite3.Row for current app code."""

    @staticmethod
    def normalize_value(value: Any) -> Any:
        if isinstance(value, (dict, list)):
            return json.dumps(value, ensure_ascii=False, sort_keys=True)
        return value

    def __init__(self, columns: list[str], values: tuple[Any, ...]):
        normalized_values = tuple(self.normalize_value(value) for value in values)
        super().__init__(zip(columns, normalized_values))
        self._values = normalized_values

    def __getitem__(self, key: Any) -> Any:
        if isinstance(key, int):
            return self._values[key]
        return super().__getitem__(key)


class PostgresCompatCursor:
    def __init__(self, cursor: Any):
        self.cursor = cursor
        self.columns = [column[0] for column in (cursor.description or [])]

    def _row(self, values: tuple[Any, ...] | None) -> PostgresCompatRow | None:
        if values is None:
            return None
        return PostgresCompatRow(self.columns, values)

    def fetchone(self) -> PostgresCompatRow | None:
        return self._row(self.cursor.fetchone())

    def fetchall(self) -> list[PostgresCompatRow]:
        return [self._row(row) for row in self.cursor.fetchall()]

    def close(self) -> None:
        self.cursor.close()

    def __iter__(self) -> Any:
        for row in self.cursor:
            yield self._row(row)


class PostgresCompatConnection:
    def __init__(self, database_url: str, ssl_root_cert: str = ""):
        try:
            import pg8000.dbapi as pg
        except ImportError as exc:
            raise RuntimeError("pg8000 is required for the hosted Postgres adapter.") from exc
        parsed = urllib.parse.urlparse(database_url)
        if not parsed.hostname:
            raise ValueError("DATABASE_URL is missing a hostname.")
        database = (parsed.path or "/postgres").lstrip("/") or "postgres"
        self.conn = pg.connect(
            user=urllib.parse.unquote(parsed.username or ""),
            password=urllib.parse.unquote(parsed.password or ""),
            host=parsed.hostname,
            port=parsed.port or 5432,
            database=database,
            ssl_context=postgres_ssl_context(ssl_root_cert),
            timeout=10,
        )
        cursor = self.conn.cursor()
        try:
            cursor.execute("SET search_path TO crm, public")
            cursor.execute(f"SET statement_timeout TO {postgres_statement_timeout_ms()}")
            cursor.execute("SET idle_in_transaction_session_timeout TO 10000")
        finally:
            cursor.close()

    def execute(self, sql: str, parameters: Any = ()) -> PostgresCompatCursor:
        cursor = self.conn.cursor()
        cursor.execute(translate_sqlite_sql_for_postgres(sql), postgres_parameters_for_sql(sql, parameters))
        return PostgresCompatCursor(cursor)

    def commit(self) -> None:
        self.conn.commit()

    def rollback(self) -> None:
        self.conn.rollback()

    def close(self) -> None:
        self.conn.close()

    def __enter__(self) -> "PostgresCompatConnection":
        return self

    def __exit__(self, exc_type: Any, exc: Any, traceback: Any) -> None:
        try:
            if exc_type:
                self.rollback()
        finally:
            self.close()


def postgres_ssl_context(ssl_root_cert: str = "") -> ssl.SSLContext:
    return ssl.create_default_context(cafile=ssl_root_cert or None)


def hosted_postgres_adapter_enabled_from_env() -> bool:
    database_url_configured = bool(os.environ.get("DATABASE_URL", "").strip())
    adapter = os.environ.get("CHILLCRM_DATABASE_ADAPTER") or os.environ.get("CRM_DATABASE_ADAPTER") or ""
    return database_url_configured and adapter.strip().lower() in POSTGRES_ADAPTER_VALUES


def env_flag(name: str, default: bool = False) -> bool:
    value = os.environ.get(name)
    if value is None:
        return default
    return value.strip().lower() in {"1", "true", "yes", "on", "enabled", "required"}


def b64url_encode(payload: bytes) -> str:
    return base64.urlsafe_b64encode(payload).decode("ascii").rstrip("=")


def b64url_decode(payload: str) -> bytes:
    padding = "=" * (-len(payload) % 4)
    return base64.urlsafe_b64decode((payload + padding).encode("ascii"))


def password_hash(password: str, iterations: int = 260_000) -> str:
    salt = secrets.token_bytes(16)
    digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt, iterations)
    return f"pbkdf2_sha256${iterations}${b64url_encode(salt)}${b64url_encode(digest)}"


def verify_password(password: str, stored_hash: str | None) -> bool:
    if not stored_hash:
        return False
    try:
        algorithm, iteration_text, salt_text, digest_text = stored_hash.split("$", 3)
        if algorithm != "pbkdf2_sha256":
            return False
        iterations = int(iteration_text)
        expected = b64url_decode(digest_text)
        actual = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), b64url_decode(salt_text), iterations)
        return hmac.compare_digest(actual, expected)
    except Exception:
        return False


def json_response_default(value: Any) -> Any:
    if isinstance(value, Decimal):
        if not value.is_finite():
            return str(value)
        return int(value) if value == value.to_integral_value() else float(value)
    if isinstance(value, (date, datetime)):
        return value.isoformat()
    raise TypeError(f"Object of type {value.__class__.__name__} is not JSON serializable")


def signed_session_token(payload: dict[str, Any], secret: str) -> str:
    encoded_payload = b64url_encode(json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8"))
    signature = hmac.new(secret.encode("utf-8"), encoded_payload.encode("ascii"), hashlib.sha256).digest()
    return f"{encoded_payload}.{b64url_encode(signature)}"


def verify_signed_session_token(token: str, secret: str) -> dict[str, Any] | None:
    try:
        encoded_payload, encoded_signature = token.split(".", 1)
        expected = b64url_encode(hmac.new(secret.encode("utf-8"), encoded_payload.encode("ascii"), hashlib.sha256).digest())
        if not hmac.compare_digest(encoded_signature, expected):
            return None
        payload = json.loads(b64url_decode(encoded_payload))
        if int(payload.get("exp") or 0) < int(time.time()):
            return None
        return payload
    except Exception:
        return None


def translate_sqlite_sql_for_postgres(sql: str) -> str:
    translated, _ = translate_sqlite_parameters(sql)
    translated = re.sub(r"\s+COLLATE\s+NOCASE\b", "", translated, flags=re.IGNORECASE)
    translated = re.sub(r"\bifnull\s*\(", "coalesce(", translated, flags=re.IGNORECASE)
    translated = translated.replace("round(sum(d.value), 2)", "round((sum(d.value))::numeric, 2)")
    translated = translated.replace("printf('%.0f', d.value)", "to_char(d.value, 'FM999999999999990')")
    translated = translated.replace("CASE WHEN t.completed THEN", "CASE WHEN t.completed <> 0 THEN")
    translated = translated.replace("CASE WHEN completed THEN", "CASE WHEN completed <> 0 THEN")
    translated = translated.replace(
        "json_array_length(source_json, '$.associated_deal_ids')",
        "jsonb_array_length(coalesce(source_json::jsonb -> 'associated_deal_ids', '[]'::jsonb))",
    )
    translated = translated.replace(
        "group_concat(DISTINCT ta.record_type)",
        "string_agg(DISTINCT ta.record_type::text, ',')",
    )
    translated = translated.replace(
        "group_concat(DISTINCT ta.resource_type)",
        "string_agg(DISTINCT ta.resource_type::text, ',')",
    )
    translated = translated.replace(
        "group_concat(DISTINCT coalesce(t.display_name, ta.source_name, t.normalized_name))",
        "string_agg(DISTINCT coalesce(t.display_name, ta.source_name, t.normalized_name)::text, ',')",
    )
    translated = re.sub(
        r"json_extract\(([^,]+),\s*'\$\.([A-Za-z0-9_]+)'\)",
        lambda match: f"({match.group(1).strip()}::jsonb ->> '{match.group(2)}')",
        translated,
        flags=re.IGNORECASE,
    )
    translated = re.sub(r"\bdate\s*\(\s*'now'\s*,\s*'\+7 days'\s*\)", "(CURRENT_DATE + INTERVAL '7 days')::date", translated, flags=re.IGNORECASE)
    translated = re.sub(r"\bdate\s*\(\s*'now'\s*\)", "CURRENT_DATE", translated, flags=re.IGNORECASE)
    translated = re.sub(r"\bdate\s*\(\s*([A-Za-z_][A-Za-z0-9_.]*)\s*\)", r"CAST(\1 AS date)", translated, flags=re.IGNORECASE)
    translated = re.sub(r"\bdatetime\s*\(\s*'now'\s*\)", "CURRENT_TIMESTAMP", translated, flags=re.IGNORECASE)
    translated = re.sub(r"\bSELECT\s+last_insert_rowid\s*\(\s*\)", "SELECT lastval()", translated, flags=re.IGNORECASE)
    return translated


def postgres_parameters_for_sql(sql: str, parameters: Any) -> Any:
    _, named_parameter_order = translate_sqlite_parameters(sql)
    if isinstance(parameters, dict):
        return [parameters[name] for name in named_parameter_order]
    return parameters


def translate_sqlite_parameters(sql: str) -> tuple[str, list[str]]:
    result: list[str] = []
    named_parameter_order: list[str] = []
    index = 0
    quote: str | None = None
    while index < len(sql):
        char = sql[index]
        if quote:
            result.append(char)
            if char == quote:
                if index + 1 < len(sql) and sql[index + 1] == quote:
                    result.append(sql[index + 1])
                    index += 1
                else:
                    quote = None
            index += 1
            continue
        if char in {"'", '"'}:
            quote = char
            result.append(char)
            index += 1
            continue
        if char == "?":
            result.append("%s")
            index += 1
            continue
        if char == ":" and (index == 0 or sql[index - 1] != ":"):
            name_match = re.match(r":([A-Za-z_][A-Za-z0-9_]*)", sql[index:])
            if name_match:
                result.append("%s")
                named_parameter_order.append(name_match.group(1))
                index += len(name_match.group(0))
                continue
        result.append(char)
        index += 1
    return "".join(result), named_parameter_order


def row_to_dict(row: sqlite3.Row | None) -> dict[str, Any] | None:
    return dict(row) if row is not None else None


def rows_to_dicts(rows: list[sqlite3.Row]) -> list[dict[str, Any]]:
    return [dict(row) for row in rows]


def now_iso() -> str:
    return datetime.now(timezone.utc).isoformat(timespec="seconds")


def normalize_text(value: Any) -> str | None:
    if value is None:
        return None
    text = str(value).strip().lower()
    return text or None


def labelize(value: Any) -> str:
    return " ".join(part.capitalize() for part in str(value or "").replace("_", " ").split())


def archive_review_status_label(status: Any) -> str:
    text = str(status or "unreviewed")
    if text == "unreviewed":
        return "Unreviewed"
    return ARCHIVE_REVIEW_STATUS_LABELS.get(text, labelize(text))


def backup_stamp() -> str:
    return datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%S%fZ")


def ensure_runtime_schema(db_path: Path) -> None:
    conn = sqlite3.connect(db_path)
    try:
        conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS audit_log (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                action TEXT NOT NULL,
                record_type TEXT NOT NULL,
                record_id INTEGER,
                field_name TEXT,
                old_value TEXT,
                new_value TEXT,
                note TEXT,
                app_user_id INTEGER,
                actor_email TEXT,
                actor_roles TEXT,
                permission_action TEXT,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS local_settings (
                key TEXT PRIMARY KEY,
                value TEXT,
                updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS local_addresses (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                record_type TEXT NOT NULL,
                record_id INTEGER NOT NULL,
                address_key TEXT NOT NULL,
                label TEXT NOT NULL,
                line1 TEXT,
                line2 TEXT,
                city TEXT,
                state TEXT,
                postal_code TEXT,
                country TEXT,
                source TEXT NOT NULL DEFAULT 'local',
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(record_type, record_id, address_key)
            );

            CREATE INDEX IF NOT EXISTS idx_local_addresses_record
            ON local_addresses(record_type, record_id);

            CREATE TABLE IF NOT EXISTS local_list_views (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                list_type TEXT NOT NULL,
                name TEXT NOT NULL,
                settings_json TEXT NOT NULL,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(list_type, name)
            );

            CREATE INDEX IF NOT EXISTS idx_local_list_views_type
            ON local_list_views(list_type, name COLLATE NOCASE);

            CREATE TABLE IF NOT EXISTS cleanup_group_decisions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                group_type TEXT NOT NULL,
                group_key TEXT NOT NULL,
                decision TEXT NOT NULL,
                note TEXT,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(group_type, group_key)
            );

            CREATE INDEX IF NOT EXISTS idx_cleanup_group_decisions_type
            ON cleanup_group_decisions(group_type, decision, updated_at DESC);

            CREATE TABLE IF NOT EXISTS project_decisions (
                decision_key TEXT PRIMARY KEY,
                status TEXT NOT NULL DEFAULT 'pending',
                choice TEXT,
                note TEXT,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );

            CREATE INDEX IF NOT EXISTS idx_project_decisions_status
            ON project_decisions(status, updated_at DESC);

            CREATE TABLE IF NOT EXISTS imported_archive_items (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                item_type TEXT NOT NULL,
                source_collection TEXT NOT NULL,
                zendesk_record_id INTEGER,
                record_type TEXT,
                record_id INTEGER,
                related_record_type TEXT,
                related_record_id INTEGER,
                original_resource_type TEXT,
                original_resource_id INTEGER,
                title TEXT,
                body TEXT,
                direction TEXT,
                occurred_at TEXT,
                created_at TEXT,
                updated_at TEXT,
                user_id INTEGER,
                duration_seconds INTEGER,
                phone_number TEXT,
                content_type TEXT,
                size_bytes INTEGER,
                local_file TEXT,
                url TEXT,
                status TEXT,
                source_json TEXT NOT NULL,
                UNIQUE(source_collection, zendesk_record_id)
            );

            CREATE INDEX IF NOT EXISTS idx_imported_archive_record
            ON imported_archive_items(record_type, record_id, occurred_at DESC);

            CREATE INDEX IF NOT EXISTS idx_imported_archive_type
            ON imported_archive_items(item_type, occurred_at DESC);

            CREATE INDEX IF NOT EXISTS idx_imported_archive_related
            ON imported_archive_items(related_record_type, related_record_id, occurred_at DESC);

            CREATE TABLE IF NOT EXISTS archive_review_decisions (
                archive_item_id INTEGER PRIMARY KEY,
                status TEXT NOT NULL,
                note TEXT,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (archive_item_id) REFERENCES imported_archive_items(id)
            );

            CREATE INDEX IF NOT EXISTS idx_archive_review_status
            ON archive_review_decisions(status, updated_at DESC);

            CREATE TABLE IF NOT EXISTS app_users (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                email TEXT NOT NULL UNIQUE,
                display_name TEXT NOT NULL,
                password_hash TEXT,
                password_updated_at TEXT,
                status TEXT NOT NULL DEFAULT 'active',
                last_login_at TEXT,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                deactivated_at TEXT
            );

            CREATE TABLE IF NOT EXISTS app_roles (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                role_key TEXT NOT NULL UNIQUE,
                label TEXT NOT NULL,
                description TEXT,
                system_role INTEGER NOT NULL DEFAULT 1,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );

            CREATE TABLE IF NOT EXISTS app_user_roles (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                app_user_id INTEGER NOT NULL REFERENCES app_users(id),
                app_role_id INTEGER NOT NULL REFERENCES app_roles(id),
                granted_by_user_id INTEGER REFERENCES app_users(id),
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
                revoked_at TEXT,
                UNIQUE(app_user_id, app_role_id, revoked_at)
            );

            CREATE TABLE IF NOT EXISTS app_permissions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                action_key TEXT NOT NULL UNIQUE,
                area TEXT NOT NULL,
                description TEXT NOT NULL,
                owner_allowed INTEGER NOT NULL DEFAULT 1,
                admin_allowed INTEGER NOT NULL DEFAULT 0,
                staff_allowed INTEGER NOT NULL DEFAULT 0,
                read_only_allowed INTEGER NOT NULL DEFAULT 0,
                created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
            );

            CREATE INDEX IF NOT EXISTS idx_app_user_roles_user
            ON app_user_roles(app_user_id, revoked_at);
            """
        )
        columns = {row[1] for row in conn.execute("PRAGMA table_info(review_flags)")}
        if "resolved_at" not in columns:
            conn.execute("ALTER TABLE review_flags ADD COLUMN resolved_at TEXT")
        if "resolution_note" not in columns:
            conn.execute("ALTER TABLE review_flags ADD COLUMN resolution_note TEXT")
        app_user_columns = {row[1] for row in conn.execute("PRAGMA table_info(app_users)")}
        if "password_hash" not in app_user_columns:
            conn.execute("ALTER TABLE app_users ADD COLUMN password_hash TEXT")
        if "password_updated_at" not in app_user_columns:
            conn.execute("ALTER TABLE app_users ADD COLUMN password_updated_at TEXT")
        audit_columns = {row[1] for row in conn.execute("PRAGMA table_info(audit_log)")}
        audit_column_additions = {
            "app_user_id": "ALTER TABLE audit_log ADD COLUMN app_user_id INTEGER",
            "actor_email": "ALTER TABLE audit_log ADD COLUMN actor_email TEXT",
            "actor_roles": "ALTER TABLE audit_log ADD COLUMN actor_roles TEXT",
            "permission_action": "ALTER TABLE audit_log ADD COLUMN permission_action TEXT",
        }
        for column_name, statement in audit_column_additions.items():
            if column_name not in audit_columns:
                try:
                    conn.execute(statement)
                except sqlite3.OperationalError as exc:
                    if "duplicate column" not in str(exc).lower():
                        raise
                audit_columns.add(column_name)
        for role_key, label, description in AUTH_ROLE_SEEDS:
            conn.execute(
                """
                INSERT INTO app_roles (role_key, label, description, system_role)
                VALUES (?, ?, ?, 1)
                ON CONFLICT(role_key)
                DO UPDATE SET label = excluded.label, description = excluded.description
                """,
                (role_key, label, description),
            )
        conn.commit()
    finally:
        conn.close()


