    def log_message(self, format: str, *args: Any) -> None:
        return

    def db(self) -> Any:
        if self.hosted_postgres_adapter_enabled():
            return PostgresCompatConnection(self.database_url(), self.postgres_ssl_root_cert())
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        return conn

    def configured_database_adapter(self) -> str:
        return os.environ.get("CHILLCRM_DATABASE_ADAPTER") or os.environ.get("CRM_DATABASE_ADAPTER") or ""

    def hosted_postgres_adapter_enabled(self) -> bool:
        return hosted_postgres_adapter_enabled_from_env()

    def remote_write_lock_enabled(self) -> bool:
        value = os.environ.get("REMOTE_WRITE_LOCK", "").strip().lower()
        return value in {"1", "true", "yes", "on", "locked"}

    def remote_write_lock_status(self) -> dict[str, Any]:
        enabled = self.remote_write_lock_enabled()
        return {
            "enabled": enabled,
            "mode": "locked" if enabled else "unlocked",
            "env_var": "REMOTE_WRITE_LOCK",
            "locked_post_paths": sorted(self.write_locked_post_paths),
            "message": (
                "Remote write lock is enabled; POST writes are blocked for staging validation."
                if enabled
                else "Remote write lock is off; local CRM writes are available."
            ),
        }

    def local_write_freeze_requested(self) -> bool:
        return env_flag("CHILLCRM_LOCAL_WRITE_FREEZE") or env_flag("LOCAL_WRITE_FREEZE")

    def local_write_freeze_enabled(self) -> bool:
        return self.local_write_freeze_requested() and not self.hosted_postgres_adapter_enabled()

    def local_write_freeze_status(self) -> dict[str, Any]:
        requested = self.local_write_freeze_requested()
        hosted_adapter_enabled = self.hosted_postgres_adapter_enabled()
        enabled = requested and not hosted_adapter_enabled
        if enabled:
            mode = "frozen"
            message = "Local write freeze is enabled; local CRM mutations are blocked for final cutover packaging."
        elif requested and hosted_adapter_enabled:
            mode = "ignored_hosted_adapter"
            message = "Local write freeze is requested but ignored while the hosted Postgres adapter is active."
        else:
            mode = "unfrozen"
            message = "Local write freeze is off; local CRM writes are available."
        return {
            "enabled": enabled,
            "requested": requested,
            "mode": mode,
            "env_var": "CHILLCRM_LOCAL_WRITE_FREEZE",
            "fallback_env_var": "LOCAL_WRITE_FREEZE",
            "applies_to": "local_sqlite",
            "ignored_when_hosted_postgres_adapter_enabled": True,
            "locked_post_paths": sorted(self.local_write_freeze_post_paths),
            "allowed_post_paths": ["/api/backup"],
            "message": message,
        }

    def bulk_package_exports_enabled(self) -> bool:
        value = os.environ.get("EXPORT_PACKAGE_ENABLED")
        if value is None:
            return True
        return value.strip().lower() not in {"0", "false", "no", "off", "locked", "disabled"}

    def bulk_package_export_status(self) -> dict[str, Any]:
        enabled = self.bulk_package_exports_enabled()
        return {
            "enabled": enabled,
            "mode": "enabled" if enabled else "locked",
            "env_var": "EXPORT_PACKAGE_ENABLED",
            "blocked_get_paths": ["/api/export_package", "/api/export_document_files_package"],
            "message": (
                "Bulk package exports are enabled."
                if enabled
                else "Bulk package exports are locked until permissions and staging validation are approved."
            ),
        }

    def document_file_access_enabled(self) -> bool:
        value = os.environ.get("DOCUMENT_FILE_ACCESS_ENABLED")
        if value is None:
            return True
        return value.strip().lower() not in {"0", "false", "no", "off", "locked", "disabled"}

    def document_file_access_status(self) -> dict[str, Any]:
        enabled = self.document_file_access_enabled()
        return {
            "enabled": enabled,
            "mode": "enabled" if enabled else "locked",
            "env_var": "DOCUMENT_FILE_ACCESS_ENABLED",
            "blocked_get_paths": ["/api/archive_file"],
            "message": (
                "Recovered document file access is enabled."
                if enabled
                else "Recovered document file access is locked until private storage and permissions are approved."
            ),
        }

    def supabase_url(self) -> str:
        return os.environ.get("CHILLCRM_SUPABASE_URL", "").strip().rstrip("/")

    def supabase_service_role_key(self) -> str:
        return (
            os.environ.get("CHILLCRM_SUPABASE_SERVICE_ROLE_KEY", "").strip()
            or os.environ.get("SUPABASE_SERVICE_ROLE_KEY", "").strip()
        )

    def storage_signed_url_ttl_seconds(self) -> int:
        raw = os.environ.get("CHILLCRM_STORAGE_SIGNED_URL_TTL_SECONDS", "").strip()
        try:
            ttl = int(raw) if raw else 300
        except ValueError:
            ttl = 300
        return max(30, min(ttl, 3600))

    def auth_required_enabled(self) -> bool:
        return env_flag("CHILLCRM_AUTH_REQUIRED") or env_flag("AUTH_REQUIRED")

    def owner_password_recovery_enabled(self) -> bool:
        return self.auth_required_enabled() and (
            env_flag("CHILLCRM_OWNER_PASSWORD_RECOVERY_ENABLED")
            or env_flag("OWNER_PASSWORD_RECOVERY_ENABLED")
        )

    def session_secret(self) -> str:
        return os.environ.get("CHILLCRM_SESSION_SECRET", "").strip() or os.environ.get("SESSION_SECRET", "").strip()

    def session_ttl_seconds(self) -> int:
        raw = os.environ.get("CHILLCRM_SESSION_TTL_HOURS", "").strip() or os.environ.get("SESSION_TTL_HOURS", "").strip()
        try:
            hours = float(raw) if raw else 12.0
        except ValueError:
            hours = 12.0
        return max(900, min(int(hours * 3600), 60 * 60 * 24 * 14))

    def session_cookie_secure_enabled(self) -> bool:
        value = os.environ.get("SESSION_COOKIE_SECURE")
        if value is not None:
            return value.strip().lower() not in {"0", "false", "no", "off"}
        return self.runtime_environment() != "local"

    def runtime_environment(self) -> str:
        environment = os.environ.get("CRM_ENV", "local").strip().lower() or "local"
        return re.sub(r"[^a-z0-9_-]+", "_", environment).strip("_") or "local"

    def auth_setup_status(self) -> dict[str, Any]:
        bootstrap_password_configured = bool(
            os.environ.get("AUTH_BOOTSTRAP_ADMIN_PASSWORD_HASH", "").strip()
            or os.environ.get("AUTH_BOOTSTRAP_ADMIN_PASSWORD", "").strip()
        )
        return {
            "required": self.auth_required_enabled(),
            "session_secret_configured": bool(self.session_secret()),
            "bootstrap_admin_email_configured": bool(os.environ.get("AUTH_BOOTSTRAP_ADMIN_EMAIL", "").strip()),
            "bootstrap_admin_password_configured": bootstrap_password_configured,
            "owner_password_recovery_enabled": self.owner_password_recovery_enabled(),
            "cookie_secure": self.session_cookie_secure_enabled(),
            "session_ttl_seconds": self.session_ttl_seconds(),
        }

    def seed_auth_roles(self, conn: Any) -> None:
        for role_key, label, description in AUTH_ROLE_SEEDS:
            conn.execute(
                """
                INSERT INTO app_roles (role_key, label, description, system_role)
                VALUES (?, ?, ?, ?)
                ON CONFLICT(role_key)
                DO UPDATE SET label = excluded.label, description = excluded.description
                """,
                (role_key, label, description, True),
            )

    def bootstrap_password_hash(self) -> str | None:
        configured_hash = os.environ.get("AUTH_BOOTSTRAP_ADMIN_PASSWORD_HASH", "").strip()
        if configured_hash:
            return configured_hash
        configured_password = os.environ.get("AUTH_BOOTSTRAP_ADMIN_PASSWORD", "").strip()
        if configured_password:
            return password_hash(configured_password)
        return None

    def ensure_bootstrap_admin(self, conn: Any) -> dict[str, Any] | None:
        self.seed_auth_roles(conn)
        email = os.environ.get("AUTH_BOOTSTRAP_ADMIN_EMAIL", "").strip().lower()
        if not email:
            return None
        configured_hash = self.bootstrap_password_hash()
        display_name = os.environ.get("AUTH_BOOTSTRAP_ADMIN_NAME", "").strip() or email
        user = row_to_dict(conn.execute("SELECT * FROM app_users WHERE lower(email) = lower(?)", (email,)).fetchone())
        if user is None and configured_hash:
            conn.execute(
                """
                INSERT INTO app_users (email, display_name, password_hash, password_updated_at, status)
                VALUES (?, ?, ?, CURRENT_TIMESTAMP, 'active')
                """,
                (email, display_name, configured_hash),
            )
            user_id = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
            user = row_to_dict(conn.execute("SELECT * FROM app_users WHERE id = ?", (user_id,)).fetchone())
        elif user is not None and configured_hash and not user.get("password_hash"):
            conn.execute(
                """
                UPDATE app_users
                SET password_hash = ?, password_updated_at = CURRENT_TIMESTAMP, status = 'active'
                WHERE id = ?
                """,
                (configured_hash, user["id"]),
            )
            user = row_to_dict(conn.execute("SELECT * FROM app_users WHERE id = ?", (user["id"],)).fetchone())
        if user is None:
            return None
        for role_key in ("owner", "admin"):
            role = row_to_dict(conn.execute("SELECT id FROM app_roles WHERE role_key = ?", (role_key,)).fetchone())
            if not role:
                continue
            exists = conn.execute(
                """
                SELECT 1
                FROM app_user_roles
                WHERE app_user_id = ? AND app_role_id = ? AND revoked_at IS NULL
                """,
                (user["id"], role["id"]),
            ).fetchone()
            if not exists:
                conn.execute(
                    "INSERT INTO app_user_roles (app_user_id, app_role_id, granted_by_user_id) VALUES (?, ?, ?)",
                    (user["id"], role["id"], user["id"]),
                )
        return self.load_app_user(conn, int(user["id"]))

    def load_app_user(self, conn: Any, user_id: int) -> dict[str, Any] | None:
        user = row_to_dict(conn.execute("SELECT * FROM app_users WHERE id = ?", (user_id,)).fetchone())
        if not user:
            return None
        roles = rows_to_dicts(
            conn.execute(
                """
                SELECT ar.role_key, ar.label
                FROM app_user_roles aur
                JOIN app_roles ar ON ar.id = aur.app_role_id
                WHERE aur.app_user_id = ? AND aur.revoked_at IS NULL
                ORDER BY ar.role_key
                """,
                (user_id,),
            ).fetchall()
        )
        user["roles"] = [role["role_key"] for role in roles]
        return user

    def load_app_user_by_email(self, conn: Any, email: str) -> dict[str, Any] | None:
        row = conn.execute("SELECT id FROM app_users WHERE lower(email) = lower(?)", (email.strip(),)).fetchone()
        return self.load_app_user(conn, int(row["id"])) if row else None

    def public_auth_user(self, user: dict[str, Any] | None) -> dict[str, Any] | None:
        if not user:
            return None
        return {
            "id": user.get("id"),
            "email": user.get("email"),
            "display_name": user.get("display_name"),
            "status": user.get("status"),
            "roles": user.get("roles") or [],
        }

    def public_app_user(self, user: dict[str, Any] | None) -> dict[str, Any] | None:
        public_user = self.public_auth_user(user)
        if not public_user or not user:
            return public_user
        public_user.update(
            {
                "created_at": user.get("created_at"),
                "last_login_at": user.get("last_login_at"),
                "password_updated_at": user.get("password_updated_at"),
                "deactivated_at": user.get("deactivated_at"),
            }
        )
        return public_user

    def role_keys_for_user(self, user: dict[str, Any] | None) -> set[str]:
        if not user:
            return set()
        return {str(role).strip().lower() for role in (user.get("roles") or []) if str(role).strip()}

    def role_snapshot(self, user: dict[str, Any] | None) -> str:
        return ",".join(sorted(self.role_keys_for_user(user)))

    def audit_log_has_actor_columns(self, conn: Any) -> bool:
        if self.hosted_postgres_adapter_enabled():
            row = conn.execute(
                """
                SELECT count(*) AS column_count
                FROM information_schema.columns
                WHERE table_schema = 'crm'
                  AND table_name = 'audit_log'
                  AND column_name IN ('app_user_id', 'actor_email', 'actor_roles', 'permission_action')
                """
            ).fetchone()
            return int(row["column_count"] if row else 0) >= 4
        columns = {row["name"] for row in conn.execute("PRAGMA table_info(audit_log)").fetchall()}
        return {"app_user_id", "actor_email", "actor_roles", "permission_action"}.issubset(columns)

    def insert_audit_log(
        self,
        conn: Any,
        *,
        action: str,
        record_type: str,
        record_id: int | None = None,
        field_name: str | None = None,
        old_value: Any = None,
        new_value: Any = None,
        note: str | None = None,
        actor_user: dict[str, Any] | None = None,
        permission_action: str | None = None,
    ) -> None:
        old_text = old_value if old_value is None or isinstance(old_value, str) else json.dumps(old_value, ensure_ascii=False, sort_keys=True, default=json_response_default)
        new_text = new_value if new_value is None or isinstance(new_value, str) else json.dumps(new_value, ensure_ascii=False, sort_keys=True, default=json_response_default)
        audit_id: int | None = None
        if self.hosted_postgres_adapter_enabled():
            row = conn.execute("SELECT COALESCE(max(id), 0) + 1 AS next_id FROM audit_log").fetchone()
            audit_id = int(row["next_id"] if row else 1)
        if self.audit_log_has_actor_columns(conn):
            if audit_id is not None:
                conn.execute(
                    """
                    INSERT INTO audit_log (
                        id, action, record_type, record_id, field_name, old_value, new_value, note,
                        app_user_id, actor_email, actor_roles, permission_action
                    )
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        audit_id,
                        action,
                        record_type,
                        record_id,
                        field_name,
                        old_text,
                        new_text,
                        note,
                        actor_user.get("id") if actor_user else None,
                        actor_user.get("email") if actor_user else None,
                        self.role_snapshot(actor_user) if actor_user else None,
                        permission_action,
                    ),
                )
            else:
                conn.execute(
                    """
                    INSERT INTO audit_log (
                        action, record_type, record_id, field_name, old_value, new_value, note,
                        app_user_id, actor_email, actor_roles, permission_action
                    )
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        action,
                        record_type,
                        record_id,
                        field_name,
                        old_text,
                        new_text,
                        note,
                        actor_user.get("id") if actor_user else None,
                        actor_user.get("email") if actor_user else None,
                        self.role_snapshot(actor_user) if actor_user else None,
                        permission_action,
                    ),
                )
        else:
            if audit_id is not None:
                conn.execute(
                    """
                    INSERT INTO audit_log (id, action, record_type, record_id, field_name, old_value, new_value, note)
                    VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                    """,
                    (audit_id, action, record_type, record_id, field_name, old_text, new_text, note),
                )
            else:
                conn.execute(
                    """
                    INSERT INTO audit_log (action, record_type, record_id, field_name, old_value, new_value, note)
                    VALUES (?, ?, ?, ?, ?, ?, ?)
                    """,
                    (action, record_type, record_id, field_name, old_text, new_text, note),
                )

    def record_permission_denial(self, path: str, action_key: str | None, user: dict[str, Any] | None) -> None:
        if not self.auth_required_enabled() or not action_key or not user:
            return
        try:
            with self.db() as conn:
                self.insert_audit_log(
                    conn,
                    action="permission_denied",
                    record_type="security",
                    field_name=path,
                    old_value=None,
                    new_value={"action_key": action_key, "allowed_roles": sorted(self.action_role_permissions.get(action_key, []))},
                    note=f"Denied {path}",
                    actor_user=user,
                    permission_action=action_key,
                )
                conn.commit()
        except Exception:
            return

    def permission_action_for_get(self, path: str) -> str | None:
        if path.startswith("/reports/"):
            return "view_dashboard_reports"
        return self.get_permission_actions.get(path)

    def permission_action_for_post(self, path: str) -> str | None:
        return self.post_permission_actions.get(path)

    def user_can_perform(self, user: dict[str, Any] | None, action_key: str | None) -> bool:
        if not self.auth_required_enabled() or not action_key:
            return True
        allowed_roles = self.action_role_permissions.get(action_key)
        if allowed_roles is None:
            return False
        return bool(self.role_keys_for_user(user) & set(allowed_roles))

    def send_permission_denied(self, path: str, action_key: str | None, user: dict[str, Any] | None) -> None:
        self.record_permission_denial(path, action_key, user)
        self.send_json(
            {
                "ok": False,
                "error": "Your role is not allowed to perform this action.",
                "code": "permission_denied",
                "path": path,
                "action_key": action_key,
                "allowed_roles": sorted(self.action_role_permissions.get(action_key or "", [])),
                "auth": self.auth_status_payload(user),
            },
            403,
        )

    def authenticate_app_user(self, email: str, password: str) -> dict[str, Any] | None:
        with self.db() as conn:
            self.ensure_bootstrap_admin(conn)
            user = self.load_app_user_by_email(conn, email)
            if not user or str(user.get("status") or "").lower() != "active":
                return None
            if not verify_password(password, user.get("password_hash")):
                return None
            conn.execute("UPDATE app_users SET last_login_at = CURRENT_TIMESTAMP WHERE id = ?", (user["id"],))
            conn.commit()
            return self.load_app_user(conn, int(user["id"]))

    def available_app_roles(self, conn: Any) -> list[dict[str, Any]]:
        self.seed_auth_roles(conn)
        return rows_to_dicts(
            conn.execute(
                """
                SELECT role_key, label, description, system_role
                FROM app_roles
                ORDER BY role_key
                """
            ).fetchall()
        )

    def clean_app_role_keys(self, conn: Any, raw_roles: Any, default: list[str] | None = None) -> list[str]:
        available = {str(row["role_key"]) for row in self.available_app_roles(conn)}
        values = raw_roles if isinstance(raw_roles, list) else default if default is not None else []
        cleaned = sorted({str(role).strip().lower() for role in values if str(role).strip().lower() in available})
        return cleaned or (default or ["read_only"])

    def active_owner_count_excluding(self, conn: Any, user_id: int | None = None) -> int:
        values: list[Any] = []
        clause = ""
        if user_id is not None:
            clause = "AND au.id <> ?"
            values.append(user_id)
        row = conn.execute(
            f"""
            SELECT count(*) AS owner_count
            FROM app_users au
            JOIN app_user_roles aur ON aur.app_user_id = au.id AND aur.revoked_at IS NULL
            JOIN app_roles ar ON ar.id = aur.app_role_id
            WHERE ar.role_key = 'owner'
              AND au.status = 'active'
              {clause}
            """,
            values,
        ).fetchone()
        return int(row["owner_count"] if row else 0)

    def sync_app_user_roles(self, conn: Any, user_id: int, desired_role_keys: list[str], actor_user: dict[str, Any] | None) -> None:
        role_rows = rows_to_dicts(conn.execute("SELECT id, role_key FROM app_roles").fetchall())
        role_ids = {str(row["role_key"]): int(row["id"]) for row in role_rows}
        desired_ids = {role_ids[key] for key in desired_role_keys if key in role_ids}
        active_rows = rows_to_dicts(
            conn.execute(
                """
                SELECT aur.id, ar.id AS role_id, ar.role_key
                FROM app_user_roles aur
                JOIN app_roles ar ON ar.id = aur.app_role_id
                WHERE aur.app_user_id = ? AND aur.revoked_at IS NULL
                """,
                (user_id,),
            ).fetchall()
        )
        active_ids = {int(row["role_id"]) for row in active_rows}
        for row in active_rows:
            if int(row["role_id"]) not in desired_ids:
                conn.execute("UPDATE app_user_roles SET revoked_at = CURRENT_TIMESTAMP WHERE id = ?", (row["id"],))
        actor_id = actor_user.get("id") if actor_user else None
        for role_id in sorted(desired_ids - active_ids):
            conn.execute(
                "INSERT INTO app_user_roles (app_user_id, app_role_id, granted_by_user_id) VALUES (?, ?, ?)",
                (user_id, role_id, actor_id),
            )

    def app_users_payload(self) -> dict[str, Any]:
        with self.db() as conn:
            self.ensure_bootstrap_admin(conn)
            users = [
                self.public_app_user(self.load_app_user(conn, int(row["id"])))
                for row in rows_to_dicts(
                    conn.execute(
                        """
                        SELECT id
                        FROM app_users
                        ORDER BY status = 'active' DESC, lower(email)
                        """
                    ).fetchall()
                )
            ]
            return {
                "users": [user for user in users if user],
                "roles": self.available_app_roles(conn),
                "permission_actions": {key: sorted(value) for key, value in sorted(self.action_role_permissions.items())},
            }

    def save_app_user(self, payload: dict[str, Any], actor_user: dict[str, Any] | None = None) -> dict[str, Any]:
        email = str(payload.get("email") or "").strip().lower()
        display_name = str(payload.get("display_name") or "").strip()
        if "@" not in email or "." not in email.rsplit("@", 1)[-1]:
            raise ValueError("A valid email is required.")
        if not display_name:
            display_name = email
        supplied_password = str(payload.get("password") or "")
        generate_password = bool(payload.get("generate_password"))
        temporary_password = ""
        with self.db() as conn:
            self.ensure_bootstrap_admin(conn)
            existing = self.load_app_user_by_email(conn, email)
            default_roles = existing.get("roles") if existing else ["read_only"]
            desired_roles = self.clean_app_role_keys(conn, payload.get("roles"), default=list(default_roles or ["read_only"]))
            if existing and "owner" in (existing.get("roles") or []) and "owner" not in desired_roles and self.active_owner_count_excluding(conn, int(existing["id"])) < 1:
                raise ValueError("At least one active owner account is required.")
            password_to_store = supplied_password
            if not existing and not password_to_store:
                generate_password = True
            if generate_password and not password_to_store:
                password_to_store = secrets.token_urlsafe(18)
                temporary_password = password_to_store
            if existing:
                old_snapshot = self.public_app_user(existing)
                assignments: list[Any] = [display_name, int(existing["id"])]
                password_sql = ""
                if password_to_store:
                    password_sql = ", password_hash = ?, password_updated_at = CURRENT_TIMESTAMP"
                    assignments = [display_name, password_hash(password_to_store), int(existing["id"])]
                conn.execute(
                    f"""
                    UPDATE app_users
                    SET display_name = ?, status = 'active', deactivated_at = NULL{password_sql}
                    WHERE id = ?
                    """,
                    assignments,
                )
                user_id = int(existing["id"])
            else:
                old_snapshot = None
                conn.execute(
                    """
                    INSERT INTO app_users (email, display_name, password_hash, password_updated_at, status)
                    VALUES (?, ?, ?, CURRENT_TIMESTAMP, 'active')
                    """,
                    (email, display_name, password_hash(password_to_store)),
                )
                user_id = int(conn.execute("SELECT id FROM app_users WHERE lower(email) = lower(?)", (email,)).fetchone()["id"])
            self.sync_app_user_roles(conn, user_id, desired_roles, actor_user)
            updated = self.load_app_user(conn, user_id)
            self.insert_audit_log(
                conn,
                action="app_user_save",
                record_type="app_user",
                record_id=user_id,
                field_name="app_user",
                old_value=old_snapshot,
                new_value=self.public_app_user(updated),
                note=f"App user saved for {email}; password_changed={'yes' if password_to_store else 'no'}",
                actor_user=actor_user,
                permission_action="manage_users_roles",
            )
            conn.commit()
        response = {"ok": True, "user": self.public_app_user(updated), "users": self.app_users_payload()["users"]}
        if temporary_password:
            response["temporary_password"] = temporary_password
        return response

    def change_app_user_status(self, payload: dict[str, Any], status: str, actor_user: dict[str, Any] | None = None) -> dict[str, Any]:
        user_id = int(payload.get("id") or payload.get("user_id") or 0)
        if not user_id:
            raise ValueError("user id is required.")
        if status not in {"active", "deactivated"}:
            raise ValueError("Invalid user status.")
        with self.db() as conn:
            self.ensure_bootstrap_admin(conn)
            existing = self.load_app_user(conn, user_id)
            if not existing:
                raise ValueError("User not found.")
            if status == "deactivated" and "owner" in (existing.get("roles") or []) and self.active_owner_count_excluding(conn, user_id) < 1:
                raise ValueError("At least one active owner account is required.")
            old_snapshot = self.public_app_user(existing)
            if status == "active":
                conn.execute("UPDATE app_users SET status = 'active', deactivated_at = NULL WHERE id = ?", (user_id,))
            else:
                conn.execute("UPDATE app_users SET status = 'deactivated', deactivated_at = CURRENT_TIMESTAMP WHERE id = ?", (user_id,))
            updated = self.load_app_user(conn, user_id)
            self.insert_audit_log(
                conn,
                action="app_user_status",
                record_type="app_user",
                record_id=user_id,
                field_name="status",
                old_value=old_snapshot,
                new_value=self.public_app_user(updated),
                note=f"App user {status}: {updated.get('email') if updated else user_id}",
                actor_user=actor_user,
                permission_action="manage_users_roles",
            )
            conn.commit()
        return {"ok": True, "user": self.public_app_user(updated), "users": self.app_users_payload()["users"]}

    def set_app_user_password(self, payload: dict[str, Any], actor_user: dict[str, Any] | None = None) -> dict[str, Any]:
        user_id = int(payload.get("id") or payload.get("user_id") or 0)
        if not user_id:
            raise ValueError("user id is required.")
        supplied_password = str(payload.get("password") or "")
        temporary_password = supplied_password or secrets.token_urlsafe(18)
        with self.db() as conn:
            self.ensure_bootstrap_admin(conn)
            existing = self.load_app_user(conn, user_id)
            if not existing:
                raise ValueError("User not found.")
            conn.execute(
                """
                UPDATE app_users
                SET password_hash = ?, password_updated_at = CURRENT_TIMESTAMP
                WHERE id = ?
                """,
                (password_hash(temporary_password), user_id),
            )
            updated = self.load_app_user(conn, user_id)
            self.insert_audit_log(
                conn,
                action="app_user_password",
                record_type="app_user",
                record_id=user_id,
                field_name="password_hash",
                old_value={"password_configured": bool(existing.get("password_hash"))},
                new_value={"password_configured": True},
                note=f"App user password reset for {updated.get('email') if updated else user_id}.",
                actor_user=actor_user,
                permission_action="manage_users_roles",
            )
            conn.commit()
        response = {"ok": True, "user": self.public_app_user(updated), "temporary_password": temporary_password}
        return response

    def change_current_app_user_password(self, payload: dict[str, Any], actor_user: dict[str, Any] | None = None) -> dict[str, Any]:
        if not actor_user:
            raise ValueError("A signed-in user is required.")
        current_password = str(payload.get("current_password") or "")
        new_password = str(payload.get("new_password") or "")
        if not current_password or not new_password:
            raise ValueError("Current password and new password are required.")
        if len(new_password) < 12:
            raise ValueError("Use at least 12 characters for the new password.")
        user_id = int(actor_user.get("id") or 0)
        with self.db() as conn:
            existing = self.load_app_user(conn, user_id)
            if not existing or str(existing.get("status") or "").lower() != "active":
                raise ValueError("Signed-in user was not found.")
            if not verify_password(current_password, existing.get("password_hash")):
                raise ValueError("Current password is incorrect.")
            conn.execute(
                """
                UPDATE app_users
                SET password_hash = ?, password_updated_at = CURRENT_TIMESTAMP
                WHERE id = ?
                """,
                (password_hash(new_password), user_id),
            )
            updated = self.load_app_user(conn, user_id)
            self.insert_audit_log(
                conn,
                action="app_user_password_self_change",
                record_type="app_user",
                record_id=user_id,
                field_name="password_hash",
                old_value={"password_configured": bool(existing.get("password_hash"))},
                new_value={"password_configured": True},
                note=f"App user changed own password for {updated.get('email') if updated else user_id}.",
                actor_user=updated,
                permission_action="change_own_password",
            )
            conn.commit()
        return {"ok": True, "auth": self.auth_status_payload(updated)}

    def owner_password_recovery_response(self, payload: dict[str, Any]) -> None:
        if not self.auth_required_enabled():
            self.send_json({"ok": False, "error": "Owner recovery is available only when authentication is required.", "code": "owner_recovery_unavailable"}, 404)
            return
        if not self.owner_password_recovery_enabled():
            self.send_json({"ok": False, "error": "Owner password recovery is not currently enabled.", "code": "owner_recovery_disabled"}, 403)
            return
        if not self.session_secret():
            self.send_json({"ok": False, "error": "SESSION_SECRET is required before hosted login is enabled.", "code": "session_secret_missing"}, 503)
            return
        bootstrap_email = os.environ.get("AUTH_BOOTSTRAP_ADMIN_EMAIL", "").strip().lower()
        email = str(payload.get("email") or "").strip().lower()
        new_password = str(payload.get("new_password") or "")
        if not bootstrap_email:
            self.send_json({"ok": False, "error": "Owner recovery needs a configured owner email.", "code": "owner_recovery_owner_missing"}, 503)
            return
        if email != bootstrap_email:
            self.send_json({"ok": False, "error": "Owner recovery is limited to the configured owner account.", "code": "owner_recovery_owner_mismatch"}, 403)
            return
        if len(new_password) < 12:
            self.send_json({"ok": False, "error": "Use at least 12 characters for the new password.", "code": "owner_recovery_password_short"}, 400)
            return

        display_name = os.environ.get("AUTH_BOOTSTRAP_ADMIN_NAME", "").strip() or email
        password_digest = password_hash(new_password)
        with self.db() as conn:
            self.ensure_bootstrap_admin(conn)
            existing = self.load_app_user_by_email(conn, email)
            old_snapshot = self.public_app_user(existing)
            if existing:
                user_id = int(existing["id"])
                conn.execute(
                    """
                    UPDATE app_users
                    SET display_name = ?, password_hash = ?, password_updated_at = CURRENT_TIMESTAMP,
                        status = 'active', deactivated_at = NULL
                    WHERE id = ?
                    """,
                    (display_name or existing.get("display_name") or email, password_digest, user_id),
                )
            else:
                conn.execute(
                    """
                    INSERT INTO app_users (email, display_name, password_hash, password_updated_at, status)
                    VALUES (?, ?, ?, CURRENT_TIMESTAMP, 'active')
                    """,
                    (email, display_name, password_digest),
                )
                user_id = int(conn.execute("SELECT id FROM app_users WHERE lower(email) = lower(?)", (email,)).fetchone()["id"])
            self.sync_app_user_roles(conn, user_id, ["admin", "owner"], {"id": user_id, "email": email, "roles": ["admin", "owner"]})
            updated = self.load_app_user(conn, user_id)
            self.insert_audit_log(
                conn,
                action="owner_password_recovery",
                record_type="app_user",
                record_id=user_id,
                field_name="password_hash",
                old_value={"user": old_snapshot, "password_configured": bool(existing and existing.get("password_hash"))},
                new_value={"user": self.public_app_user(updated), "password_configured": True},
                note="Owner password recovery completed through the controlled hosted recovery path.",
                actor_user=updated,
                permission_action="owner_password_recovery",
            )
            conn.commit()
        token = self.create_session_token(updated)
        self.send_json(
            {"ok": True, "auth": self.auth_status_payload(updated), "recovery": {"owner_password_recovery_enabled": True}},
            headers={"Set-Cookie": self.session_cookie_header(token)},
        )

    def create_session_token(self, user: dict[str, Any]) -> str:
        now = int(time.time())
        ttl = self.session_ttl_seconds()
        payload = {
            "uid": int(user["id"]),
            "email": user.get("email"),
            "roles": user.get("roles") or [],
            "sid": secrets.token_urlsafe(16),
            "iat": now,
            "exp": now + ttl,
        }
        return signed_session_token(payload, self.session_secret())

    def parse_cookies(self) -> dict[str, str]:
        cookies: dict[str, str] = {}
        headers = getattr(self, "headers", {})
        raw_cookie = headers.get("Cookie", "") if hasattr(headers, "get") else ""
        for part in str(raw_cookie).split(";"):
            if "=" not in part:
                continue
            key, value = part.split("=", 1)
            cookies[key.strip()] = value.strip()
        return cookies

    def current_auth_user(self) -> dict[str, Any] | None:
        if not self.auth_required_enabled():
            return None
        secret = self.session_secret()
        if not secret:
            return None
        token = self.parse_cookies().get(AUTH_COOKIE_NAME)
        if not token:
            return None
        payload = verify_signed_session_token(token, secret)
        if not payload:
            return None
        with self.db() as conn:
            user = self.load_app_user(conn, int(payload.get("uid") or 0))
        if not user or str(user.get("status") or "").lower() != "active":
            return None
        return user

    def auth_status_payload(self, user: dict[str, Any] | None = None) -> dict[str, Any]:
        setup = self.auth_setup_status()
        current_user = user if user is not None else self.current_auth_user()
        return {
            "auth_required": setup["required"],
            "authenticated": bool(current_user),
            "user": self.public_auth_user(current_user),
            "setup": setup,
            "owner_password_recovery_enabled": setup["owner_password_recovery_enabled"],
        }

    def session_cookie_header(self, token: str) -> str:
        parts = [
            f"{AUTH_COOKIE_NAME}={token}",
            "Path=/",
            "HttpOnly",
            "SameSite=Lax",
            f"Max-Age={self.session_ttl_seconds()}",
        ]
        if self.session_cookie_secure_enabled():
            parts.append("Secure")
        return "; ".join(parts)

    def clear_session_cookie_header(self) -> str:
        parts = [f"{AUTH_COOKIE_NAME}=", "Path=/", "HttpOnly", "SameSite=Lax", "Max-Age=0"]
        if self.session_cookie_secure_enabled():
            parts.append("Secure")
        return "; ".join(parts)

    def should_require_auth_for_get(self, path: str) -> bool:
        if not self.auth_required_enabled():
            return False
        if path in {"/", "/api/auth/status", "/health", "/api/health"}:
            return False
        if path.startswith("/static/"):
            return False
        return path.startswith("/api/") or path.startswith("/reports/")

    def should_require_auth_for_post(self, path: str) -> bool:
        if not self.auth_required_enabled():
            return False
        return path not in {"/api/auth/login", "/api/auth/logout", "/api/auth/owner_password_recovery"}

    def send_auth_required(self, path: str) -> None:
        self.send_json(
            {
                "ok": False,
                "error": "Sign in is required.",
                "code": "auth_required",
                "path": path,
                "auth": self.auth_status_payload(None),
            },
            401,
        )

    def login_response(self, payload: dict[str, Any]) -> None:
        if not self.auth_required_enabled():
            self.send_json({"ok": True, "auth": self.auth_status_payload(None)})
            return
        if not self.session_secret():
            self.send_json({"ok": False, "error": "SESSION_SECRET is required before hosted login is enabled.", "code": "session_secret_missing"}, 503)
            return
        email = str(payload.get("email") or "").strip().lower()
        password = str(payload.get("password") or "")
        if not email or not password:
            self.send_json({"ok": False, "error": "Email and password are required.", "code": "login_fields_required"}, 400)
            return
        user = self.authenticate_app_user(email, password)
        if not user:
            self.send_json({"ok": False, "error": "Invalid email or password.", "code": "invalid_login"}, 401)
            return
        token = self.create_session_token(user)
        self.send_json({"ok": True, "auth": self.auth_status_payload(user)}, headers={"Set-Cookie": self.session_cookie_header(token)})

    def logout_response(self) -> None:
        self.send_json({"ok": True, "auth": self.auth_status_payload({})}, headers={"Set-Cookie": self.clear_session_cookie_header()})

    def runtime_context(self) -> dict[str, Any]:
        environment = self.runtime_environment()
        database_url_configured = bool(os.environ.get("DATABASE_URL", "").strip())
        hosted_adapter_enabled = self.hosted_postgres_adapter_enabled()
        app_base_url_configured = bool(os.environ.get("APP_BASE_URL", "").strip())
        lock = self.remote_write_lock_status()
        local_freeze = self.local_write_freeze_status()
        bulk_exports = self.bulk_package_export_status()
        document_files = self.document_file_access_status()
        auth_setup = self.auth_setup_status()
        return {
            "environment": environment,
            "environment_label": environment.replace("_", " ").replace("-", " ").title(),
            "database_mode": "hosted_postgres_adapter_enabled" if hosted_adapter_enabled else "hosted_postgres_configured_adapter_pending" if database_url_configured else "local_sqlite",
            "database_adapter": "postgres_compat" if hosted_adapter_enabled else "sqlite",
            "database_adapter_enabled": hosted_adapter_enabled,
            "database_adapter_env": "CHILLCRM_DATABASE_ADAPTER",
            "database_url_configured": database_url_configured,
            "app_base_url_configured": app_base_url_configured,
            "auth": {
                "required": auth_setup["required"],
                "session_secret_configured": auth_setup["session_secret_configured"],
                "cookie_secure": auth_setup["cookie_secure"],
            },
            "health_endpoint": "/health",
            "api_health_endpoint": "/api/health",
            "remote_write_lock": {
                "enabled": lock["enabled"],
                "mode": lock["mode"],
            },
            "local_write_freeze": {
                "enabled": local_freeze["enabled"],
                "requested": local_freeze["requested"],
                "mode": local_freeze["mode"],
            },
            "bulk_package_exports": {
                "enabled": bulk_exports["enabled"],
                "mode": bulk_exports["mode"],
            },
            "document_file_access": {
                "enabled": document_files["enabled"],
                "mode": document_files["mode"],
            },
        }

    def database_url(self) -> str:
        return os.environ.get("DATABASE_URL", "").strip()

    def postgres_ssl_root_cert(self) -> str:
        return os.environ.get("CHILLCRM_SSLROOTCERT", "").strip()

    def hosted_postgres_health_check(self, database_url: str) -> dict[str, Any]:
        parsed = urllib.parse.urlparse(database_url)
        if not parsed.hostname:
            return {
                "status": "invalid_database_url",
                "mode": "hosted_postgres",
                "reachable": False,
                "schema": "unknown",
                "adapter": "enabled_beta" if self.hosted_postgres_adapter_enabled() else "pending",
            }
        try:
            import pg8000.dbapi as pg
        except ImportError:
            return {
                "status": "missing_driver",
                "mode": "hosted_postgres",
                "reachable": False,
                "schema": "unknown",
                "adapter": "enabled_beta" if self.hosted_postgres_adapter_enabled() else "pending",
                "error": "pg8000 is not installed in this runtime.",
            }
        database = (parsed.path or "/postgres").lstrip("/") or "postgres"
        adapter_enabled = self.hosted_postgres_adapter_enabled()
        ssl_context = postgres_ssl_context(self.postgres_ssl_root_cert())
        try:
            conn = pg.connect(
                user=urllib.parse.unquote(parsed.username or ""),
                password=urllib.parse.unquote(parsed.password or ""),
                host=parsed.hostname,
                port=parsed.port or 5432,
                database=database,
                ssl_context=ssl_context,
                timeout=10,
            )
            try:
                cur = conn.cursor()
                try:
                    cur.execute(
                        """
                        SELECT
                            EXISTS (SELECT 1 FROM information_schema.schemata WHERE schema_name = 'crm') AS has_crm_schema,
                            EXISTS (
                                SELECT 1
                                FROM information_schema.tables
                                WHERE table_schema = 'crm'
                                  AND table_name = 'people'
                            ) AS has_people_table,
                            EXISTS (
                                SELECT 1
                                FROM information_schema.tables
                                WHERE table_schema = 'crm'
                                  AND table_name = 'remote_file_objects'
                            ) AS has_remote_file_objects_table
                        """
                    )
                    row = cur.fetchone()
                finally:
                    cur.close()
            finally:
                conn.close()
        except Exception as exc:
            return {
                "status": "error",
                "mode": "hosted_postgres",
                "reachable": False,
                "schema": "unknown",
                "adapter": "enabled_beta" if adapter_enabled else "pending",
                "error": exc.__class__.__name__,
            }
        has_schema = bool(row[0])
        has_people = bool(row[1])
        has_files = bool(row[2])
        return {
            "status": "ok" if has_schema and has_people and has_files else "schema_incomplete",
            "mode": "hosted_postgres",
            "reachable": True,
            "schema": "crm" if has_schema else "missing",
            "required_tables_present": has_people and has_files,
            "adapter": "enabled_beta" if adapter_enabled else "pending",
            "note": (
                "Hosted Postgres is reachable and the guarded app adapter is enabled."
                if adapter_enabled
                else "Hosted Postgres is reachable; enable CHILLCRM_DATABASE_ADAPTER=postgres only for guarded hosted adapter tests."
            ),
        }

    def reports_health_check(self, database_url_configured: bool) -> dict[str, Any]:
        reports_present = REPORTS_DIR.exists() and REPORTS_DIR.is_dir()
        reports_required = env_flag("CHILLCRM_REPORTS_REQUIRED", default=not database_url_configured)
        if reports_present:
            status = "ok"
            note = "Local report artifacts are available in this runtime."
        elif reports_required:
            status = "missing"
            note = "Report artifacts are required for this runtime and were not found."
        else:
            status = "omitted"
            note = "Report artifacts are private local outputs and are intentionally omitted from hosted source deployments."
        return {
            "status": status,
            "present": reports_present,
            "required": reports_required,
            "source": "private_local_artifacts",
            "note": note,
        }

    def health_status(self) -> tuple[dict[str, Any], int]:
        checks: dict[str, dict[str, Any]] = {
            "database": {"status": "checking", "mode": "sqlite", "reachable": False},
            "reports": {"status": "checking", "present": False, "required": True},
        }
        ok = True
        database_url = self.database_url()
        if database_url:
            checks["database"] = self.hosted_postgres_health_check(database_url)
            if checks["database"]["status"] != "ok":
                ok = False
        elif not self.db_path.exists():
            ok = False
            checks["database"] = {"status": "missing", "mode": "sqlite", "reachable": False}
        else:
            try:
                with self.db() as conn:
                    conn.execute("SELECT 1").fetchone()
                checks["database"] = {"status": "ok", "mode": "sqlite", "reachable": True}
            except Exception as exc:
                ok = False
                checks["database"] = {
                    "status": "error",
                    "mode": "sqlite",
                    "reachable": False,
                    "error": exc.__class__.__name__,
                }
        checks["reports"] = self.reports_health_check(bool(database_url))
        if checks["reports"]["status"] == "missing":
            ok = False
        return (
            {
                "ok": ok,
                "status": "ok" if ok else "degraded",
                "service": "local_crm",
                "checked_at": datetime.now(timezone.utc).isoformat(timespec="seconds"),
                "runtime": self.runtime_context(),
                "checks": checks,
                "message": "CRM health check passed." if ok else "CRM health check needs attention.",
            },
            200 if ok else 503,
        )

    def send_bulk_package_export_locked(self, path: str) -> None:
        self.send_json(
            {
                "ok": False,
                "error": "Bulk package exports are locked until permissions and staging validation are approved.",
                "code": "bulk_package_exports_locked",
                "path": path,
                "bulk_export": self.bulk_package_export_status(),
            },
            403,
        )

    def send_document_file_access_locked(self, path: str) -> None:
        self.send_json(
            {
                "ok": False,
                "error": "Recovered document file access is locked until private storage and permissions are approved.",
                "code": "document_file_access_locked",
                "path": path,
                "document_file_access": self.document_file_access_status(),
            },
            403,
        )

    def should_block_remote_write(self, path: str) -> bool:
        return self.remote_write_lock_enabled() and path in self.write_locked_post_paths

    def should_block_local_write(self, path: str) -> bool:
        return self.local_write_freeze_enabled() and path in self.local_write_freeze_post_paths

    def send_remote_write_locked(self, path: str) -> None:
        self.send_json(
            {
                "ok": False,
                "error": "Remote write lock is enabled. Staging writes are blocked until validation intentionally unlocks them.",
                "code": "remote_write_lock_enabled",
                "path": path,
                "remote_write_lock": self.remote_write_lock_status(),
            },
            423,
        )

    def send_local_write_frozen(self, path: str) -> None:
        self.send_json(
            {
                "ok": False,
                "error": "Local write freeze is enabled. Local CRM changes are blocked until the production cutover package and validation window are complete.",
                "code": "local_write_freeze_enabled",
                "path": path,
                "local_write_freeze": self.local_write_freeze_status(),
            },
            423,
        )

    def send_json(self, payload: Any, status: int = 200, headers: dict[str, str] | None = None) -> None:
        encoded = json.dumps(payload, ensure_ascii=False, default=json_response_default).encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        for key, value in (headers or {}).items():
            self.send_header(key, value)
        self.send_header("Content-Length", str(len(encoded)))
        self.end_headers()
        self.wfile.write(encoded)

    def send_text(self, text: str, status: int = 200, content_type: str = "text/plain") -> None:
        encoded = text.encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", f"{content_type}; charset=utf-8")
        self.send_header("Content-Length", str(len(encoded)))
        self.end_headers()
        self.wfile.write(encoded)

    def send_csv(self, filename: str, rows: list[dict[str, Any]]) -> None:
        encoded = self.csv_bytes(rows)
        self.send_response(200)
        self.send_header("Content-Type", "text/csv; charset=utf-8")
        self.send_header("Content-Disposition", f'attachment; filename="{filename}"')
        self.send_header("Content-Length", str(len(encoded)))
        self.end_headers()
        self.wfile.write(encoded)

    def csv_bytes(self, rows: list[dict[str, Any]]) -> bytes:
        output = io.StringIO()
        fieldnames: list[str] = []
        for row in rows:
            for key in row.keys():
                if key not in fieldnames:
                    fieldnames.append(key)
        if not fieldnames:
            fieldnames = ["result"]
        writer = csv.DictWriter(output, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)
        return output.getvalue().encode("utf-8")

    def send_zip(self, filename: str, payload: bytes) -> None:
        self.send_response(200)
        self.send_header("Content-Type", "application/zip")
        self.send_header("Content-Disposition", f'attachment; filename="{filename}"')
        self.send_header("Content-Length", str(len(payload)))
        self.end_headers()
        self.wfile.write(payload)

    def send_file(self, path: Path) -> None:
        if not path.exists() or not path.is_file():
            self.send_text("Not found", 404)
            return
        content_type = mimetypes.guess_type(path.name)[0] or "application/octet-stream"
        payload = path.read_bytes()
        self.send_response(200)
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(len(payload)))
        self.end_headers()
        self.wfile.write(payload)

    def send_redirect(self, url: str, status: int = 302) -> None:
        self.send_response(status)
        self.send_header("Location", url)
        self.send_header("Cache-Control", "no-store")
        self.end_headers()

    def signed_storage_url(self, bucket: str, storage_key: str) -> str:
        supabase_url = self.supabase_url()
        service_key = self.supabase_service_role_key()
        if not supabase_url:
            raise RuntimeError("CHILLCRM_SUPABASE_URL is required for hosted document downloads.")
        if not service_key:
            raise RuntimeError("CHILLCRM_SUPABASE_SERVICE_ROLE_KEY or SUPABASE_SERVICE_ROLE_KEY is required for hosted document downloads.")
        object_path = f"/storage/v1/object/sign/{urllib.parse.quote(bucket, safe='')}/{urllib.parse.quote(storage_key, safe='/')}"
        body = json.dumps({"expiresIn": self.storage_signed_url_ttl_seconds()}).encode("utf-8")
        request = urllib.request.Request(
            f"{supabase_url}{object_path}",
            data=body,
            method="POST",
            headers={
                "Authorization": f"Bearer {service_key}",
                "apikey": service_key,
                "Content-Type": "application/json",
            },
        )
        open_kwargs: dict[str, Any] = {"timeout": 20}
        if supabase_url.startswith("https://"):
            open_kwargs["context"] = ssl.create_default_context()
        try:
            with urllib.request.urlopen(request, **open_kwargs) as response:
                payload = json.loads(response.read().decode("utf-8") or "{}")
        except urllib.error.HTTPError as exc:
            detail = exc.read().decode("utf-8", errors="replace")[:240]
            raise RuntimeError(f"Supabase Storage signing failed: HTTP {exc.code} {detail}") from exc
        signed = payload.get("signedURL") or payload.get("signedUrl") or payload.get("signed_url")
        if not signed:
            raise RuntimeError("Supabase Storage signing response did not include a signed URL.")
        if str(signed).startswith("http://") or str(signed).startswith("https://"):
            return str(signed)
        return f"{supabase_url}{signed}"

    def send_remote_archive_file(self, item_id: int) -> None:
        with self.db() as conn:
            row = row_to_dict(
                conn.execute(
                    """
                    SELECT ai.id, ai.title, ai.content_type,
                           rfo.storage_bucket, rfo.storage_key, rfo.content_type AS remote_content_type
                    FROM imported_archive_items ai
                    JOIN remote_file_objects rfo ON rfo.archive_item_id = ai.id
                    WHERE ai.id = ? AND ai.item_type = 'document'
                    ORDER BY rfo.uploaded_at DESC, rfo.id DESC
                    LIMIT 1
                    """,
                    (item_id,),
                ).fetchone()
            )
        if not row:
            self.send_text("Not found", 404)
            return
        try:
            self.send_redirect(self.signed_storage_url(str(row["storage_bucket"]), str(row["storage_key"])))
        except RuntimeError as exc:
            self.send_json(
                {
                    "ok": False,
                    "error": str(exc),
                    "code": "storage_signing_unavailable",
                    "path": "/api/archive_file",
                },
                503,
            )

    def send_archive_file(self, params: dict[str, list[str]]) -> None:
        if not self.document_file_access_enabled():
            self.send_document_file_access_locked("/api/archive_file")
            return
        item_id = self.optional_int(params.get("id", [""])[0] if params.get("id") else "")
        if not item_id:
            self.send_text("Not found", 404)
            return
        if self.hosted_postgres_adapter_enabled():
            self.send_remote_archive_file(item_id)
            return
        with self.db() as conn:
            row = conn.execute(
                """
                SELECT local_file
                FROM imported_archive_items
                WHERE id = ? AND item_type = 'document'
                """,
                (item_id,),
            ).fetchone()
        if not row or not row["local_file"]:
            self.send_text("Not found", 404)
            return
        path = (PROJECT_ROOT / row["local_file"]).resolve()
        allowed_root = (PROJECT_ROOT / "raw_api_exports").resolve()
        if allowed_root not in path.parents:
            self.send_text("Not found", 404)
            return
        self.send_file(path)

    def do_GET(self) -> None:
        parsed = urllib.parse.urlparse(self.path)
        path = parsed.path
        params = urllib.parse.parse_qs(parsed.query)

        try:
            auth_user = self.current_auth_user()
            if path == "/api/auth/status":
                self.send_json(self.auth_status_payload())
            elif self.should_require_auth_for_get(path) and not auth_user:
                self.send_auth_required(path)
            elif self.should_require_auth_for_get(path) and not self.user_can_perform(auth_user, self.permission_action_for_get(path)):
                self.send_permission_denied(path, self.permission_action_for_get(path), auth_user)
            elif path == "/":
                self.send_file(APP_DIR / "static" / "index.html")
            elif path.startswith("/static/"):
                self.send_file(APP_DIR / path.lstrip("/"))
            elif path == "/api/summary":
                self.send_json(self.summary())
            elif path == "/api/migration_status":
                self.send_json(self.migration_status())
            elif path == "/api/production_gates":
                self.send_json({"production_gates": self.production_gate_status()})
            elif path in {"/health", "/api/health"}:
                payload, status = self.health_status()
                self.send_json(payload, status)
            elif path == "/api/project_decisions":
                self.send_json(self.project_decisions())
            elif path == "/api/list":
                self.send_json(self.list_records(params))
            elif path == "/api/detail":
                self.send_json(self.record_detail(params))
            elif path == "/api/tasks":
                self.send_json(self.tasks(params))
            elif path == "/api/activity":
                self.send_json(self.activity(params))
            elif path == "/api/archive":
                self.send_json(self.archive_items(params))
            elif path == "/api/archive_item":
                self.send_json(self.archive_item_detail(params))
            elif path == "/api/archive_file":
                self.send_archive_file(params)
            elif path == "/api/tags":
                self.send_json(self.tags(params))
            elif path == "/api/custom_fields":
                self.send_json(self.custom_fields(params))
            elif path == "/api/linked_resources":
                self.send_json(self.linked_resources(params))
            elif path == "/api/profile_filters":
                self.send_json(self.profile_filters(params))
            elif path == "/api/create_options":
                self.send_json(self.create_options(params))
            elif path == "/api/saved_views":
                self.send_json(self.saved_views(params))
            elif path == "/api/export_manifest":
                self.send_json(self.export_manifest())
            elif path == "/api/export":
                export = self.export_rows(params)
                self.send_csv(export["filename"], export["rows"])
            elif path == "/api/export_package":
                if not self.bulk_package_exports_enabled():
                    self.send_bulk_package_export_locked(path)
                    return
                package = self.export_package()
                self.send_zip(package["filename"], package["payload"])
            elif path == "/api/export_document_files_package":
                if not self.bulk_package_exports_enabled():
                    self.send_bulk_package_export_locked(path)
                    return
                self.send_document_files_package()
            elif path == "/api/export_list":
                export = self.export_list_rows(params)
                self.send_csv(export["filename"], export["rows"])
            elif path == "/api/export_cleanup_groups":
                export = self.export_cleanup_group_rows(params)
                self.send_csv(export["filename"], export["rows"])
            elif path == "/api/search":
                self.send_json(self.search(params))
            elif path == "/api/cleanup":
                self.send_json(self.cleanup())
            elif path == "/api/cleanup_execution_preview":
                self.send_json(self.cleanup_execution_preview())
            elif path == "/api/cleanup_groups":
                self.send_json(self.cleanup_groups(params))
            elif path == "/api/review_flags":
                self.send_json(self.review_flags(params))
            elif path == "/api/backups":
                self.send_json(self.backups())
            elif path == "/api/app_users":
                self.send_json(self.app_users_payload())
            elif path.startswith("/reports/"):
                self.send_file(REPORTS_DIR / Path(path).name)
            else:
                self.send_text("Not found", 404)
        except Exception as exc:
            self.send_json({"error": str(exc)}, 500)

    def do_POST(self) -> None:
        parsed = urllib.parse.urlparse(self.path)
        path = parsed.path

        try:
            if path == "/api/auth/login":
                self.login_response(self.read_json_body())
                return
            if path == "/api/auth/owner_password_recovery":
                self.owner_password_recovery_response(self.read_json_body())
                return
            if path == "/api/auth/logout":
                self.logout_response()
                return
            auth_user = self.current_auth_user()
            if self.should_require_auth_for_post(path) and not auth_user:
                self.send_auth_required(path)
                return
            action_key = self.permission_action_for_post(path)
            if self.should_require_auth_for_post(path) and not self.user_can_perform(auth_user, action_key):
                self.send_permission_denied(path, action_key, auth_user)
                return
            if self.should_block_remote_write(path):
                self.send_remote_write_locked(path)
                return
            if self.should_block_local_write(path):
                self.send_local_write_frozen(path)
                return
            payload = self.read_json_body()
            if path == "/api/update_record":
                self.send_json(self.update_record(payload, auth_user, action_key))
            elif path == "/api/create_record":
                self.send_json(self.create_record(payload, auth_user, action_key))
            elif path == "/api/update_tags":
                self.send_json(self.update_tags(payload, auth_user, action_key))
            elif path == "/api/update_addresses":
                self.send_json(self.update_addresses(payload, auth_user, action_key))
            elif path == "/api/add_note":
                self.send_json(self.add_note(payload, auth_user, action_key))
            elif path == "/api/update_note":
                self.send_json(self.update_note(payload, auth_user, action_key))
            elif path == "/api/add_task":
                self.send_json(self.add_task(payload, auth_user, action_key))
            elif path == "/api/update_task":
                self.send_json(self.update_task(payload, auth_user, action_key))
            elif path == "/api/copy_imported_task_to_local":
                self.send_json(self.copy_imported_task_to_local(payload, auth_user, action_key))
            elif path == "/api/link_archive_item":
                self.send_json(self.link_archive_item(payload, auth_user, action_key))
            elif path == "/api/save_archive_review":
                self.send_json(self.save_archive_review(payload, auth_user, action_key))
            elif path == "/api/complete_task":
                self.send_json(self.complete_task(payload, auth_user, action_key))
            elif path == "/api/resolve_flag":
                self.send_json(self.resolve_flag(payload, auth_user, action_key))
            elif path == "/api/save_cleanup_decision":
                self.send_json(self.save_cleanup_decision(payload, auth_user, action_key))
            elif path == "/api/save_project_decision":
                self.send_json(self.save_project_decision(payload, auth_user, action_key))
            elif path == "/api/save_view":
                self.send_json(self.save_view(payload))
            elif path == "/api/delete_view":
                self.send_json(self.delete_view(payload))
            elif path == "/api/backup":
                self.send_json({"backup": str(self.create_backup("manual"))})
            elif path == "/api/restore_backup":
                self.send_json(self.restore_backup(payload))
            elif path == "/api/app_users/save":
                self.send_json(self.save_app_user(payload, auth_user))
            elif path == "/api/app_users/deactivate":
                self.send_json(self.change_app_user_status(payload, "deactivated", auth_user))
            elif path == "/api/app_users/reactivate":
                self.send_json(self.change_app_user_status(payload, "active", auth_user))
            elif path == "/api/app_users/set_password":
                self.send_json(self.set_app_user_password(payload, auth_user))
            elif path == "/api/auth/change_password":
                self.send_json(self.change_current_app_user_password(payload, auth_user))
            else:
                self.send_text("Not found", 404)
        except ValueError as exc:
            self.send_json({"error": str(exc)}, 400)
        except Exception as exc:
            self.send_json({"error": str(exc)}, 500)

    def read_json_body(self) -> dict[str, Any]:
        length = int(self.headers.get("Content-Length", "0"))
        if length <= 0:
            return {}
        raw = self.rfile.read(length).decode("utf-8")
        payload = json.loads(raw)
        if not isinstance(payload, dict):
            raise ValueError("Expected a JSON object.")
        return payload

    def saved_views(self, params: dict[str, list[str]]) -> dict[str, Any]:
        list_type = (params.get("type", ["people"])[0] or "people").lower()
        if list_type not in SAVED_VIEW_TYPES:
            raise ValueError("Unknown saved view type.")
        with self.db() as conn:
            rows = rows_to_dicts(
                conn.execute(
                    """
                    SELECT id, list_type, name, settings_json, created_at, updated_at
                    FROM local_list_views
                    WHERE list_type = ?
                    ORDER BY name COLLATE NOCASE
                    """,
                    (list_type,),
                ).fetchall()
            )
        views = []
        for row in rows:
            try:
                settings = json.loads(row["settings_json"])
            except json.JSONDecodeError:
                settings = {}
            views.append(
                {
                    "id": row["id"],
                    "list_type": row["list_type"],
                    "name": row["name"],
                    "settings": settings,
                    "record_count": self.saved_view_record_count(row["list_type"], settings),
                    "created_at": row["created_at"],
                    "updated_at": row["updated_at"],
                }
            )
        return {"type": list_type, "views": views}

    def save_view(self, payload: dict[str, Any]) -> dict[str, Any]:
        list_type = str(payload.get("type") or "people").lower()
        if list_type not in SAVED_VIEW_TYPES:
            raise ValueError("Unknown saved view type.")
        name = " ".join(str(payload.get("name") or "").split())
        if not name:
            raise ValueError("View name is required.")
        if len(name) > 80:
            raise ValueError("View name must be 80 characters or fewer.")
        settings = self.clean_saved_view_settings(list_type, payload.get("settings") or {})
        settings_json = json.dumps(settings, ensure_ascii=False, sort_keys=True)
        with self.db() as conn:
            conn.execute(
                """
                INSERT INTO local_list_views (list_type, name, settings_json, updated_at)
                VALUES (?, ?, ?, CURRENT_TIMESTAMP)
                ON CONFLICT(list_type, name) DO UPDATE SET
                    settings_json = excluded.settings_json,
                    updated_at = CURRENT_TIMESTAMP
                """,
                (list_type, name, settings_json),
            )
            conn.commit()
            row = row_to_dict(
                conn.execute(
                    """
                    SELECT id, list_type, name, settings_json, created_at, updated_at
                    FROM local_list_views
                    WHERE list_type = ? AND name = ?
                    """,
                    (list_type, name),
                ).fetchone()
            )
        return {
            "ok": True,
            "view": {
                **row,
                "settings": settings,
                "record_count": self.saved_view_record_count(list_type, settings),
            }
            if row
            else None,
        }

    def delete_view(self, payload: dict[str, Any]) -> dict[str, Any]:
        view_id = self.optional_int(payload.get("id"))
        if not view_id:
            raise ValueError("View id is required.")
        with self.db() as conn:
            conn.execute("DELETE FROM local_list_views WHERE id = ?", (view_id,))
            deleted = conn.total_changes
            conn.commit()
        return {"ok": True, "deleted": deleted}

    def clean_saved_view_settings(self, list_type: str, settings: Any) -> dict[str, Any]:
        if not isinstance(settings, dict):
            raise ValueError("Saved view settings must be an object.")
        if list_type == "activity":
            return self.clean_activity_saved_view_settings(settings)
        if list_type == "archive":
            return self.clean_archive_saved_view_settings(settings)
        if list_type == "linked_resources":
            return self.clean_linked_resource_saved_view_settings(settings)
        if list_type == "tags":
            return self.clean_tag_saved_view_settings(settings)
        if list_type == "custom_fields":
            return self.clean_custom_field_saved_view_settings(settings)
        if list_type == "tasks":
            return self.clean_task_saved_view_settings(settings)
        sort_field = str(settings.get("sort") or DEFAULT_LIST_SORT["field"]).strip()
        sort_direction = str(settings.get("direction") or DEFAULT_LIST_SORT["direction"]).strip().lower()
        _, sort_field, sort_direction = self.list_order_by(list_type, sort_field, sort_direction)
        status_field = self.clean_optional(settings.get("status_field"))
        status_value = self.clean_optional(settings.get("status_value"))
        status_field, status_value = self.normalize_list_status_filter(list_type, status_field, status_value)
        profile_field = self.clean_optional(settings.get("profile_field"))
        profile_value = self.clean_optional(settings.get("profile_value"))
        if list_type not in {"people", "leads"} or profile_field not in APPLICATION_PROFILE_FILTER_FIELDS or not profile_value:
            profile_field = None
            profile_value = None
        owner_user_id = self.optional_int(settings.get("owner_user_id"))
        if list_type not in {"people", "companies", "leads"}:
            owner_user_id = None
        date_field = self.clean_optional(settings.get("date_field"))
        date_from = self.clean_activity_date_filter(settings.get("date_from"))
        date_to = self.clean_activity_date_filter(settings.get("date_to"))
        date_field, date_from, date_to = self.normalize_list_date_filter(list_type, date_field, date_from, date_to)
        quality_issue = self.clean_optional(settings.get("quality_issue"))
        quality_issue = self.normalize_list_quality_issue(list_type, quality_issue)
        provenance_filter = self.normalize_list_provenance_filter(settings.get("provenance"))
        return {
            "q": str(settings.get("q") or "").strip(),
            "tag_id": str(settings.get("tag_id") or "").strip(),
            "status_field": status_field or "",
            "status_value": status_value or "",
            "profile_field": profile_field or "",
            "profile_value": profile_value or "",
            "owner_user_id": str(owner_user_id or ""),
            "quality_issue": quality_issue or "",
            "date_field": date_field or "",
            "date_from": date_from,
            "date_to": date_to,
            "provenance": provenance_filter or "",
            "sort": sort_field,
            "direction": sort_direction,
        }

    def clean_task_saved_view_settings(self, settings: dict[str, Any]) -> dict[str, Any]:
        status = str(settings.get("status") or "open").strip().lower()
        if status not in {"open", "completed", "all", "overdue", "due_soon"}:
            status = "open"
        record_type = str(settings.get("record_type") or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal", "unlinked"}:
            record_type = ""
        task_source = str(settings.get("source") or "").strip().lower()
        if task_source not in {"", "imported", "local"}:
            task_source = ""
        task_sort = str(settings.get("sort") or "due_date").strip()
        if task_sort not in self.task_sort_fields():
            task_sort = "due_date"
        direction = str(settings.get("direction") or "asc").strip().lower()
        if direction not in {"asc", "desc"}:
            direction = "asc"
        return {
            "status": status,
            "q": str(settings.get("q") or "").strip(),
            "record_type": record_type,
            "source": task_source,
            "sort": task_sort,
            "direction": direction,
        }

    def clean_activity_saved_view_settings(self, settings: dict[str, Any]) -> dict[str, Any]:
        activity_type = str(settings.get("activity_type") or "").strip().lower()
        if activity_type not in {
            "",
            "note",
            "task",
            "task_completed",
            "archive",
            "local_change",
            "cleanup_decision",
            "project_decision",
            "deal",
        }:
            activity_type = ""
        record_type = str(settings.get("record_type") or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal", "cleanup_group", "unlinked"}:
            record_type = ""
        return {
            "q": str(settings.get("q") or "").strip(),
            "activity_type": activity_type,
            "record_type": record_type,
            "date_from": self.clean_activity_date_filter(settings.get("date_from")),
            "date_to": self.clean_activity_date_filter(settings.get("date_to")),
        }

    def clean_archive_saved_view_settings(self, settings: dict[str, Any]) -> dict[str, Any]:
        item_type = str(settings.get("item_type") or "").strip().lower()
        if item_type not in {"", "call", "text_message", "document", "order", "lead_conversion"}:
            item_type = ""
        record_type = str(settings.get("record_type") or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal", "unlinked"}:
            record_type = ""
        preset = str(settings.get("preset") or "").strip().lower()
        if preset != "unlinked_communications":
            preset = ""
        review_status = str(settings.get("review_status") or "").strip().lower()
        if review_status not in {"", "unreviewed", "archive_only", "needs_lookup", "ready_to_link"}:
            review_status = ""
        triage_lane = self.clean_archive_triage_lane(settings.get("triage_lane"))
        if triage_lane:
            preset = "unlinked_communications"
            item_type = ""
            record_type = ""
        return {
            "q": str(settings.get("q") or "").strip(),
            "item_type": item_type,
            "record_type": record_type,
            "preset": preset,
            "review_status": review_status,
            "triage_lane": triage_lane,
            "date_from": self.clean_activity_date_filter(settings.get("date_from")),
            "date_to": self.clean_activity_date_filter(settings.get("date_to")),
        }

    def clean_linked_resource_saved_view_settings(self, settings: dict[str, Any]) -> dict[str, Any]:
        kind = " ".join(str(settings.get("kind") or "").split())
        if kind:
            valid_kinds = {row.get("kind") for row in self.collect_linked_resource_rows()}
            if kind not in valid_kinds:
                kind = ""
        record_type = str(settings.get("record_type") or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal"}:
            record_type = ""
        return {
            "q": str(settings.get("q") or "").strip(),
            "kind": kind,
            "record_type": record_type,
        }

    def clean_tag_saved_view_settings(self, settings: dict[str, Any]) -> dict[str, Any]:
        record_type = str(settings.get("record_type") or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal"}:
            record_type = ""
        return {
            "q": str(settings.get("q") or "").strip(),
            "record_type": record_type,
        }

    def clean_custom_field_saved_view_settings(self, settings: dict[str, Any]) -> dict[str, Any]:
        record_type = str(settings.get("record_type") or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal"}:
            record_type = ""
        return {
            "q": str(settings.get("q") or "").strip(),
            "record_type": record_type,
        }

    def read_report_csv_rows(self, name: str) -> list[dict[str, Any]]:
        path = REPORTS_DIR / name
        if not path.exists():
            return []
        with path.open(newline="", encoding="utf-8") as handle:
            return [dict(row) for row in csv.DictReader(handle)]

    def report_links_for_field(self, value: str) -> list[dict[str, str]]:
        links: list[dict[str, str]] = []
        for part in str(value or "").split(";"):
            report = part.strip()
            if not report.startswith("reports/"):
                continue
            name = Path(report).name
            links.append({"label": name, "url": f"/reports/{name}"})
        return links

