    def dashboard_start_today(self) -> dict[str, Any]:
        project_decisions = self.project_decisions()
        cleanup_execution_preview = self.cleanup_execution_preview(project_decisions)
        recommended_execution_preview = self.recommended_cleanup_execution_preview()
        next_action = self.project_next_action(project_decisions, cleanup_execution_preview, recommended_execution_preview)
        decision_prep = self.project_decision_prep_packet(project_decisions)
        cleanup_starter = self.cleanup_review_starter_packet()
        data_quality = self.data_quality_summary()
        linked_resource_count = len(self.collect_linked_resource_rows())
        work_queue = self.operational_work_queue(next_action, linked_resource_count, data_quality)
        guide = self.daily_operating_guide(
            work_queue,
            next_action,
            decision_prep,
            cleanup_starter,
            self.export_package_status(),
        )
        steps = []
        for step in (guide.get("steps") or [])[:4]:
            steps.append(
                {
                    "order": step.get("order"),
                    "key": step.get("key"),
                    "title": step.get("title"),
                    "status": step.get("status"),
                    "action": step.get("action"),
                    "view": step.get("view"),
                    "preset": step.get("preset"),
                }
            )
        return {
            "title": "Start Today",
            "status": guide.get("status") or "waiting",
            "message": "Begin normal local CRM work from the daily runbook while cleanup decisions stay gated.",
            "view": "migrationStatus",
            "action": "Open Daily Guide",
            "report": guide.get("report"),
            "export_url": guide.get("export_url"),
            "next_action": next_action,
            "steps": steps,
            "step_count": len(guide.get("steps") or []),
        }

    def project_decisions(self) -> dict[str, Any]:
        with self.db() as conn:
            saved = {
                row["decision_key"]: row_to_dict(row)
                for row in conn.execute(
                    """
                    SELECT decision_key, status, choice, note, created_at, updated_at
                    FROM project_decisions
                    """
                ).fetchall()
            }
        impacts = self.project_decision_impacts(saved)
        decisions = []
        status_counts = {key: 0 for key in PROJECT_DECISION_STATUSES}
        sequence_by_key = {
            item["key"]: {**item, "step": index}
            for index, item in enumerate(PROJECT_DECISION_SEQUENCE, start=1)
        }
        for definition in PROJECT_DECISIONS:
            row = saved.get(definition["key"]) or {}
            status = str(row.get("status") or "pending")
            if status not in PROJECT_DECISION_STATUSES:
                status = "pending"
            choice = row.get("choice")
            valid_choices = {option["value"] for option in definition["options"]}
            if choice not in valid_choices:
                choice = None
            status_counts[status] = status_counts.get(status, 0) + 1
            recommended = next(
                (option for option in definition["options"] if option["value"] == definition.get("recommendation")),
                None,
            )
            selected = next((option for option in definition["options"] if option["value"] == choice), None)
            decisions.append(
                {
                    **definition,
                    "status": status,
                    "status_label": PROJECT_DECISION_STATUSES[status],
                    "choice": choice,
                    "choice_label": selected["label"] if selected else "",
                    "selected_option": selected,
                    "recommended_option": recommended,
                    "note": row.get("note") or "",
                    "created_at": row.get("created_at"),
                    "updated_at": row.get("updated_at"),
                    "impact": impacts.get(definition["key"], {}),
                    "sequence": sequence_by_key.get(definition["key"], {}),
                }
            )
        return {
            "statuses": PROJECT_DECISION_STATUSES,
            "status_counts": status_counts,
            "total": len(decisions),
            "decided": status_counts.get("decided", 0),
            "pending": status_counts.get("pending", 0),
            "deferred": status_counts.get("deferred", 0),
            "decisions": decisions,
            "sequence": [
                {
                    **sequence_by_key[item["key"]],
                    "decision": next((decision for decision in decisions if decision["key"] == item["key"]), None),
                }
                for item in PROJECT_DECISION_SEQUENCE
            ],
        }

    def recommended_project_decisions(self) -> dict[str, Any]:
        decisions = []
        for definition in PROJECT_DECISIONS:
            recommended = next(
                (option for option in definition["options"] if option["value"] == definition.get("recommendation")),
                None,
            )
            decisions.append(
                {
                    **definition,
                    "status": "decided",
                    "status_label": PROJECT_DECISION_STATUSES["decided"],
                    "choice": definition.get("recommendation"),
                    "choice_label": recommended["label"] if recommended else "",
                    "selected_option": recommended,
                    "recommended_option": recommended,
                    "note": "Recommended path simulation only. Not saved.",
                    "created_at": None,
                    "updated_at": None,
                }
            )
        return {
            "statuses": PROJECT_DECISION_STATUSES,
            "status_counts": {"pending": 0, "decided": len(decisions), "deferred": 0},
            "total": len(decisions),
            "decided": len(decisions),
            "pending": 0,
            "deferred": 0,
            "decisions": decisions,
        }

    def recommended_cleanup_execution_preview(self) -> dict[str, Any]:
        preview = self.cleanup_execution_preview(self.recommended_project_decisions())
        preview["simulation"] = True
        preview["simulation_label"] = "Recommended path"
        preview["message"] = (
            "If the recommended Project Decision paths were saved, this is the non-destructive cleanup preview."
        )
        return preview

    def project_next_action(
        self,
        project_decisions: dict[str, Any],
        cleanup_execution_preview: dict[str, Any] | None = None,
        recommended_execution_preview: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        cleanup_execution_preview = cleanup_execution_preview or self.cleanup_execution_preview(project_decisions)
        recommended_execution_preview = recommended_execution_preview or self.recommended_cleanup_execution_preview()
        decision_by_key = {decision["key"]: decision for decision in project_decisions.get("decisions", [])}
        sequence_items = project_decisions.get("sequence") or []
        for target_status in ("pending", "deferred"):
            for item in sequence_items:
                decision = item.get("decision") or decision_by_key.get(item.get("key")) or {}
                if decision.get("status") == "decided" and decision.get("choice"):
                    continue
                status = decision.get("status") or "pending"
                if status != target_status:
                    continue
                recommended = decision.get("recommended_option") or {}
                impact = decision.get("impact") or {}
                deferred = status == "deferred"
                choices = self.project_decision_choice_rows(decision)
                return {
                    "kind": "project_decision",
                    "status": "waiting",
                    "eyebrow": f"Step {item.get('step')}: {item.get('phase')}",
                    "title": f"{'Revisit' if deferred else 'Save'} {decision.get('title') or item.get('key')}",
                    "description": item.get("why") or impact.get("summary") or decision.get("question") or "",
                    "why": item.get("after_save") or impact.get("next_step") or "",
                    "recommended_label": recommended.get("label") or "",
                    "recommended_value": decision.get("recommendation") or "",
                    "recommended_code": next(
                        (choice["code"] for choice in choices if choice.get("recommended")),
                        "",
                    ),
                    "choices": choices,
                    "decision_key": decision.get("key") or item.get("key"),
                    "view": "migrationStatus",
                    "related_view": decision.get("view") or "migrationStatus",
                    "report": decision.get("report"),
                    "worksheet_report": decision.get("worksheet_report") or "",
                    "worksheet_export_url": decision.get("worksheet_export_url") or "",
                    "primary_action": "Open Decision",
                    "secondary_action": "Fill Recommended" if not deferred else "",
                    "metrics": [
                        {"label": fact.get("label"), "value": fact.get("value")}
                        for fact in (impact.get("facts") or [])[:4]
                    ],
                }

        gates = cleanup_execution_preview.get("gates") or []
        backup_gate = next((gate for gate in gates if gate.get("key") == "backup_available"), None)
        if backup_gate and backup_gate.get("status") != "ready":
            return {
                "kind": "backup",
                "status": "attention",
                "eyebrow": "Safety Gate",
                "title": "Create a fresh local backup",
                "description": "Cleanup decisions are saved, but execution preview needs a backup before anything can become preview-ready.",
                "why": "A backup gives the local CRM a restore point before future cleanup work.",
                "recommended_label": "",
                "decision_key": "",
                "view": "cleanup",
                "related_view": "cleanup",
                "report": "/reports/cleanup_execution_safety_plan.md",
                "primary_action": "Open Cleanup",
                "secondary_action": "",
                "metrics": [{"label": "Locked gates", "value": cleanup_execution_preview.get("totals", {}).get("blocked_gates", 0)}],
            }

        eligible_actions = [
            action for action in cleanup_execution_preview.get("actions") or [] if action.get("status") == "eligible"
        ]
        if eligible_actions:
            tag_action = next((action for action in eligible_actions if action.get("group_type") == "duplicate_tags"), None)
            action = tag_action or eligible_actions[0]
            return {
                "kind": "cleanup_preview",
                "status": "ready",
                "eyebrow": "Preview Ready",
                "title": action.get("label") or "Review eligible cleanup action",
                "description": action.get("detail") or "A non-destructive cleanup preview has eligible groups.",
                "why": "Review the final counts, create a fresh backup, and require explicit confirmation before any future execution.",
                "recommended_label": action.get("policy_choice_label") or "",
                "decision_key": "",
                "view": "cleanup",
                "related_view": "cleanup",
                "report": "/reports/cleanup_execution_safety_plan.md",
                "primary_action": "Open Cleanup",
                "secondary_action": "",
                "metrics": [
                    {"label": "Eligible groups", "value": action.get("eligible_groups", 0)},
                    {"label": "Eligible records", "value": action.get("eligible_records", 0)},
                    {"label": "Open groups", "value": action.get("open_groups", 0)},
                ],
            }

        waiting_actions = [
            action
            for action in cleanup_execution_preview.get("actions") or []
            if action.get("status") == "waiting_for_group_decisions"
        ]
        if waiting_actions:
            overlap_action = next((action for action in waiting_actions if action.get("group_type") == "lead_person_overlap"), None)
            action = overlap_action or waiting_actions[0]
            return {
                "kind": "group_review",
                "status": "waiting",
                "eyebrow": "Group Review",
                "title": f"Review {action.get('label') or 'cleanup groups'}",
                "description": action.get("detail") or "Project decisions are saved, but specific cleanup groups still need review.",
                "why": "Only groups marked Merge Later can become eligible; draft keepers are decision aids, not automatic merge rules.",
                "recommended_label": action.get("policy_choice_label") or "",
                "decision_key": "",
                "view": "cleanup",
                "related_view": "cleanup",
                "report": "/reports/cleanup_merge_review_pack.md",
                "primary_action": "Open Cleanup",
                "secondary_action": "",
                "metrics": [
                    {"label": "Open groups", "value": action.get("open_groups", 0)},
                    {"label": "Approved groups", "value": action.get("approved_groups", 0)},
                ],
            }

        recommended_totals = recommended_execution_preview.get("totals") or {}
        return {
            "kind": "stabilize",
            "status": "ready",
            "eyebrow": "Functional Design",
            "title": "Functional cleanup rules are documented",
            "description": "No cleanup action is currently eligible under the saved paths.",
            "why": "Continue daily-use refinements or begin the queued Apple-style redesign when the functional CRM shape feels stable.",
            "recommended_label": "",
            "decision_key": "",
            "view": "migrationStatus",
            "related_view": "migrationStatus",
            "report": "/reports/cleanup_execution_safety_plan.md",
            "primary_action": "Open Status",
            "secondary_action": "",
            "metrics": [
                {"label": "Simulated eligible actions", "value": recommended_totals.get("eligible_actions", 0)},
                {"label": "Simulated eligible groups", "value": recommended_totals.get("eligible_groups", 0)},
            ],
        }

    def project_decision_choice_rows(self, decision: dict[str, Any]) -> list[dict[str, Any]]:
        recommendation = decision.get("recommendation")
        choice = decision.get("choice")
        rows = []
        for index, option in enumerate(decision.get("options") or []):
            code = chr(ord("A") + index)
            rows.append(
                {
                    "code": code,
                    "value": option.get("value"),
                    "label": option.get("label"),
                    "description": option.get("description"),
                    "display": f"{code}. {option.get('label')}",
                    "recommended": option.get("value") == recommendation,
                    "current": option.get("value") == choice,
                }
            )
        return rows

    def project_decision_prep_packet(
        self,
        project_decisions: dict[str, Any] | None = None,
    ) -> dict[str, Any]:
        project_decisions = project_decisions or self.project_decisions()
        remaining: list[dict[str, Any]] = []
        pending_remaining: list[dict[str, Any]] = []
        deferred_remaining: list[dict[str, Any]] = []
        for item in project_decisions.get("sequence") or []:
            decision = item.get("decision") or {}
            if decision.get("status") == "decided" and decision.get("choice"):
                continue
            recommended = decision.get("recommended_option") or {}
            impact = decision.get("impact") or {}
            row = {
                "step": item.get("step"),
                "phase": item.get("phase"),
                "recommended_timing": item.get("recommended_timing"),
                "key": decision.get("key") or item.get("key"),
                "title": decision.get("title") or item.get("key"),
                "category": decision.get("category"),
                "status": decision.get("status") or "pending",
                "status_label": decision.get("status_label") or PROJECT_DECISION_STATUSES["pending"],
                "question": decision.get("question"),
                "recommended_value": decision.get("recommendation"),
                "recommended_label": recommended.get("label"),
                "recommended_description": recommended.get("description"),
                "why": item.get("why") or impact.get("summary") or "",
                "after_save": item.get("after_save") or "",
                "impact_readiness": impact.get("readiness"),
                "impact_summary": impact.get("summary"),
                "next_step": impact.get("next_step"),
                "facts": (impact.get("facts") or [])[:6],
                "view": decision.get("view") or "migrationStatus",
                "report": decision.get("report"),
                "worksheet_report": decision.get("worksheet_report") or "",
                "worksheet_export_url": decision.get("worksheet_export_url") or "",
            }
            if row["status"] == "deferred":
                deferred_remaining.append(row)
            else:
                pending_remaining.append(row)
        remaining = pending_remaining + deferred_remaining
        status = "waiting" if remaining else "ready"
        next_decision = remaining[0] if remaining else {}
        pending_count = int(project_decisions.get("pending") or 0)
        deferred_count = int(project_decisions.get("deferred") or 0)
        if pending_count and deferred_count:
            message = (
                f"{pending_count:,} pending major decisions remain; "
                f"{deferred_count:,} deferred decision{'s are' if deferred_count != 1 else ' is'} parked for later review."
            )
        elif pending_count:
            message = f"{pending_count:,} pending major decisions remain. Review the recommended path, impact facts, and evidence before saving each choice."
        elif deferred_count:
            message = f"{deferred_count:,} deferred major decision{'s remain' if deferred_count != 1 else ' remains'} parked for later review."
        else:
            message = "All major project decisions have saved paths."
        return {
            "title": "Decision Prep Packet",
            "status": status,
            "message": message,
            "total_decisions": project_decisions.get("total", 0),
            "remaining_count": len(remaining),
            "pending_count": pending_count,
            "deferred_count": deferred_count,
            "decided_count": project_decisions.get("decided", 0),
            "next_decision_key": next_decision.get("key") or "",
            "next_decision_title": next_decision.get("title") or "",
            "report": "/reports/project_decision_sequence.md",
            "brief_report": "/reports/project_decision_brief.md",
            "export_url": "/api/export?type=decision_prep_packet",
            "decisions": remaining,
        }

    def cleanup_review_starter_packet(self, limit: int = 12) -> dict[str, Any]:
        queue_defs = [
            {
                "group_type": "lead_person_overlap",
                "queue_label": "Lead/Person Overlap",
                "decision_key": "lead_person_overlap_policy",
                "phase": "Start with identity overlaps",
                "why": "These decide whether the person becomes the client record while lead/application history is preserved.",
                "starter_limit": 5,
            },
            {
                "group_type": "duplicate_people",
                "queue_label": "Duplicate People",
                "decision_key": "duplicate_people_merge_policy",
                "phase": "Then review high-priority people",
                "why": "Same-email people affect the working client list and should use guided review before any merge path is eligible.",
                "starter_limit": 5,
            },
            {
                "group_type": "duplicate_leads",
                "queue_label": "Duplicate Leads",
                "decision_key": "duplicate_leads_merge_policy",
                "phase": "Then review high-priority leads",
                "why": "Same-email leads may represent separate funnel or application history, so they stay review-only until policy and group decisions are saved.",
                "starter_limit": 2,
            },
        ]
        groups: list[dict[str, Any]] = []
        queue_summaries: list[dict[str, Any]] = []
        for definition in queue_defs:
            export = self.export_cleanup_group_rows(
                {
                    "type": [definition["group_type"]],
                    "status": ["open"],
                    "decision": ["review_remaining"],
                    "sort": ["policy"],
                }
            )
            rows = export.get("rows") or []
            queue_summaries.append(
                {
                    **definition,
                    "review_remaining": len(rows),
                    "high_priority": sum(1 for row in rows if str(row.get("priority") or "").lower() == "high"),
                    "export_url": f"/api/export_cleanup_groups?type={definition['group_type']}&status=open&decision=review_remaining&sort=policy",
                }
            )
            for row in rows[: int(definition.get("starter_limit") or limit)]:
                if len(groups) >= limit:
                    break
                groups.append(
                    {
                        **definition,
                        "review_order": len(groups) + 1,
                        "group_key": row.get("group_key") or "",
                        "group_label": row.get("group_label") or row.get("group_key") or "",
                        "priority": row.get("priority") or "",
                        "review_score": row.get("review_score"),
                        "record_count": int(row.get("record_count") or 0),
                        "flag_count": int(row.get("flag_count") or 0),
                        "sample_names": row.get("sample_names") or "",
                        "draft_keeper": row.get("draft_keeper") or "",
                        "draft_keeper_type": row.get("draft_keeper_type") or "",
                        "draft_blank_field_suggestions": int(row.get("draft_blank_field_suggestions") or 0),
                        "draft_manual_review_fields": int(row.get("draft_manual_review_fields") or 0),
                        "draft_history_records": int(row.get("draft_history_records") or 0),
                        "draft_history_signals": int(row.get("draft_history_signals") or 0),
                        "policy_lane": row.get("policy_lane") or "",
                        "policy_lane_label": row.get("policy_lane_label") or "",
                        "headline": row.get("headline") or "",
                        "reasons": row.get("reasons") or "",
                    }
                )
            if len(groups) >= limit:
                break
        return {
            "title": "Cleanup Starter Packet",
            "status": "waiting" if groups else "ready",
            "message": (
                "A read-only first batch for cleanup review after the related Project Decisions are saved. Opening a group does not merge, delete, resolve, or rewrite records."
                if groups
                else "No cleanup review groups are waiting in the starter queues."
            ),
            "limit": limit,
            "group_count": len(groups),
            "queue_summaries": queue_summaries,
            "groups": groups,
            "report": "/reports/cleanup_review_starter_packet.md",
            "csv": "/reports/cleanup_review_starter_packet.csv",
            "export_url": "/api/export?type=cleanup_starter_packet",
            "merge_review_report": "/reports/cleanup_merge_review_pack.md",
        }

    def project_decision_impacts(self, saved: dict[str, dict[str, Any]] | None = None) -> dict[str, dict[str, Any]]:
        saved = saved or {}
        cleanup_summary = self.cleanup_merge_policy_summary()
        queue_by_type = {queue["group_type"]: queue for queue in cleanup_summary.get("queues", [])}
        execution_preview = self.cleanup_execution_preview_from_saved(saved)
        action_by_type = {action["action_type"]: action for action in execution_preview.get("actions", [])}

        with self.db() as conn:
            archive_counts = {
                row["item_type"]: dict(row)
                for row in rows_to_dicts(
                    conn.execute(
                        """
                        SELECT item_type, count(*) AS count, sum(record_id IS NOT NULL) AS linked
                        FROM imported_archive_items
                        GROUP BY item_type
                        """
                    ).fetchall()
                )
            }
            profile_counts = {
                row["record_type"]: dict(row)
                for row in rows_to_dicts(
                    conn.execute(
                        f"""
                        SELECT record_type, count(DISTINCT record_id) AS record_count, count(*) AS value_count
                        FROM custom_field_values
                        WHERE field_name IN ({",".join("?" for _ in APPLICATION_PROFILE_FIELDS)})
                        GROUP BY record_type
                        """,
                        APPLICATION_PROFILE_FIELDS,
                    ).fetchall()
                )
            }

        pending_cleanup_decisions = sum(
            1
            for key in [
                "duplicate_people_merge_policy",
                "duplicate_leads_merge_policy",
                "lead_person_overlap_policy",
                "duplicate_tag_policy",
            ]
            if (saved.get(key) or {}).get("status") != "decided" or not (saved.get(key) or {}).get("choice")
        )
        unlinked_calls = int(archive_counts.get("call", {}).get("count") or 0) - int(archive_counts.get("call", {}).get("linked") or 0)
        unlinked_texts = int(archive_counts.get("text_message", {}).get("count") or 0) - int(archive_counts.get("text_message", {}).get("linked") or 0)

        def cleanup_impact(group_type: str, action_type: str, summary: str, next_step: str) -> dict[str, Any]:
            queue = queue_by_type.get(group_type, {})
            action = action_by_type.get(action_type, {})
            return {
                "summary": summary,
                "readiness": "ready" if action.get("status") == "eligible" else "waiting",
                "next_step": next_step,
                "facts": [
                    {"label": "Open groups", "value": int(queue.get("groups") or 0)},
                    {"label": "High priority", "value": int(queue.get("high") or 0)},
                    {"label": "Medium priority", "value": int(queue.get("medium") or 0)},
                    {"label": "Eligible now", "value": int(action.get("eligible_groups") or 0)},
                ],
            }

        return {
            "duplicate_people_merge_policy": cleanup_impact(
                "duplicate_people",
                "merge_duplicate_people",
                "Controls whether reviewed same-email people can later merge into one client record.",
                "Save the policy, then mark individual people groups Merge Later after review.",
            ),
            "duplicate_leads_merge_policy": cleanup_impact(
                "duplicate_leads",
                "merge_duplicate_leads",
                "Controls whether same-email leads can merge or stay separate to preserve application histories.",
                "Save the policy, then review duplicate lead groups before marking any Merge Later.",
            ),
            "lead_person_overlap_policy": cleanup_impact(
                "lead_person_overlap",
                "merge_lead_person_overlaps",
                "Controls how records are represented when a lead and person share the same identity.",
                "Save the keeper policy, then review each overlap group before marking any Merge Later.",
            ),
            "duplicate_tag_policy": cleanup_impact(
                "duplicate_tags",
                "mark_duplicate_tags_handled",
                "Controls whether already-normalized duplicate tag definitions can be accepted as handled in a batch.",
                "Save the policy, then use Cleanup Execution Preview for a final spot-check count.",
            ),
            "application_profile_editability": {
                "summary": "Controls whether promoted application fields stay read-only or become editable CRM fields.",
                "readiness": "waiting" if pending_cleanup_decisions else "ready",
                "next_step": "Keep read-only until merge policies are saved, then decide which fields deserve editable local columns.",
                "facts": [
                    {"label": "Lead profile records", "value": int(profile_counts.get("lead", {}).get("record_count") or 0)},
                    {"label": "Person profile records", "value": int(profile_counts.get("person", {}).get("record_count") or 0)},
                    {"label": "Profile values", "value": sum(int(row.get("value_count") or 0) for row in profile_counts.values())},
                    {"label": "Cleanup policies pending", "value": pending_cleanup_decisions},
                ],
            },
            "unlinked_archive_matching": {
                "summary": "Controls whether unlinked calls and texts remain archive-only or get a later manual matching pass.",
                "readiness": "ready",
                "next_step": "Keep uncertain call/text items searchable in Archive unless a manual matching pass is worth the time.",
                "facts": [
                    {"label": "Unlinked calls", "value": max(0, unlinked_calls)},
                    {"label": "Unlinked texts", "value": max(0, unlinked_texts)},
                    {"label": "Linked archive items", "value": sum(int(row.get("linked") or 0) for row in archive_counts.values())},
                    {"label": "Total archive items", "value": sum(int(row.get("count") or 0) for row in archive_counts.values())},
                ],
            },
            "apple_native_redesign_timing": {
                "summary": "Controls when the current functional CRM is visually restructured into the later native Apple-style interface.",
                "readiness": "waiting" if pending_cleanup_decisions else "ready",
                "next_step": "Keep this queued until the chosen timing condition is met and daily CRM workflow has stabilized.",
                "facts": [
                    {"label": "Cleanup policies pending", "value": pending_cleanup_decisions},
                    {"label": "Open cleanup groups", "value": int(cleanup_summary.get("totals", {}).get("open_groups") or 0)},
                    {"label": "Preview eligible actions", "value": int(execution_preview.get("totals", {}).get("eligible_actions") or 0)},
                    {"label": "Redesign queued", "value": "Yes"},
                ],
            },
        }

    def cleanup_execution_preview_from_saved(self, saved: dict[str, dict[str, Any]]) -> dict[str, Any]:
        status_counts = {key: 0 for key in PROJECT_DECISION_STATUSES}
        decisions = []
        for definition in PROJECT_DECISIONS:
            row = saved.get(definition["key"]) or {}
            status = str(row.get("status") or "pending")
            if status not in PROJECT_DECISION_STATUSES:
                status = "pending"
            choice = row.get("choice")
            selected = next((option for option in definition["options"] if option["value"] == choice), None)
            if not selected:
                choice = None
            status_counts[status] = status_counts.get(status, 0) + 1
            decisions.append(
                {
                    **definition,
                    "status": status,
                    "choice": choice,
                    "choice_label": selected["label"] if selected else "",
                }
            )
        return self.cleanup_execution_preview(
            {
                "status_counts": status_counts,
                "total": len(decisions),
                "decided": status_counts.get("decided", 0),
                "pending": status_counts.get("pending", 0),
                "deferred": status_counts.get("deferred", 0),
                "decisions": decisions,
            }
        )

