    def attach_quality_summaries(self, record_type: str, records: list[dict[str, Any]]) -> None:
        for record in records:
            record["quality_issues"] = self.record_quality_issues(record_type, record)

    def clean_record_with_quality(self, record_type: str, record: dict[str, Any]) -> dict[str, Any]:
        clean = self.clean_record(record)
        clean["quality_issues"] = self.record_quality_issues(record_type, clean)
        return clean

    def record_quality_issues(self, record_type: str, record: dict[str, Any]) -> list[dict[str, str]]:
        issues: list[dict[str, str]] = []

        def blank(value: Any) -> bool:
            return not str(value or "").strip()

        if record_type == "people":
            if blank(record.get("email")) and blank(record.get("phone")) and blank(record.get("mobile")):
                issues.append({"issue": "missing_contact", "label": "No contact", "tone": "coral"})
            else:
                if blank(record.get("email")):
                    issues.append({"issue": "missing_email", "label": "Missing email", "tone": "gold"})
                if blank(record.get("phone")) and blank(record.get("mobile")):
                    issues.append({"issue": "missing_phone", "label": "Missing phone", "tone": "gold"})
            if record.get("owner_user_id") is None:
                issues.append({"issue": "missing_owner", "label": "Missing owner", "tone": "gold"})
        elif record_type == "companies":
            if blank(record.get("email")) and blank(record.get("phone")):
                issues.append({"issue": "missing_contact", "label": "No contact", "tone": "coral"})
            else:
                if blank(record.get("email")):
                    issues.append({"issue": "missing_email", "label": "Missing email", "tone": "gold"})
                if blank(record.get("phone")):
                    issues.append({"issue": "missing_phone", "label": "Missing phone", "tone": "gold"})
            if record.get("owner_user_id") is None:
                issues.append({"issue": "missing_owner", "label": "Missing owner", "tone": "gold"})
        elif record_type == "leads":
            if blank(record.get("email")) and blank(record.get("phone")) and blank(record.get("mobile")):
                issues.append({"issue": "missing_contact", "label": "No contact", "tone": "coral"})
            else:
                if blank(record.get("email")):
                    issues.append({"issue": "missing_email", "label": "Missing email", "tone": "gold"})
                if blank(record.get("phone")) and blank(record.get("mobile")):
                    issues.append({"issue": "missing_phone", "label": "Missing phone", "tone": "gold"})
            if record.get("owner_user_id") is None:
                issues.append({"issue": "missing_owner", "label": "Missing owner", "tone": "gold"})
        elif record_type == "deals":
            if not record.get("value"):
                issues.append({"issue": "missing_value", "label": "Missing value", "tone": "coral"})
            if blank(record.get("stage_name")):
                issues.append({"issue": "missing_stage", "label": "Missing stage", "tone": "gold"})
            has_relationship = (
                not blank(record.get("contact_name"))
                or not blank(record.get("organization_name"))
                or record.get("person_id") is not None
                or record.get("company_id") is not None
            )
            if not has_relationship:
                issues.append({"issue": "missing_relationship", "label": "No contact/company", "tone": "gold"})
        return issues

    def tasks(self, params: dict[str, list[str]]) -> dict[str, Any]:
        status = (params.get("status", ["open"])[0] or "open").lower()
        q = (params.get("q", [""])[0] or "").strip()
        record_type = (params.get("record_type", [""])[0] or "").lower()
        task_source = (params.get("source", [""])[0] or "").lower()
        task_sort = (params.get("sort", ["due_date"])[0] or "due_date").strip()
        direction = (params.get("direction", ["asc"])[0] or "asc").lower()
        page = max(int(params.get("page", ["1"])[0]), 1)
        page_size = min(max(int(params.get("page_size", ["50"])[0]), 10), 100)
        offset = (page - 1) * page_size
        if status not in {"open", "completed", "all", "overdue", "due_soon"}:
            status = "open"
        if direction not in {"asc", "desc"}:
            direction = "asc"
        if record_type not in {"", "person", "company", "lead", "deal", "unlinked"}:
            record_type = ""
        if task_source not in {"", "imported", "local"}:
            task_source = ""
        with self.db() as conn:
            where, values = self.task_filter_where(status, q, record_type, task_source)
            source_where, source_values = self.task_filter_where(status, q, record_type, "")
            total = conn.execute(
                f"""
                SELECT count(*)
                FROM tasks t
                LEFT JOIN people p ON t.record_type = 'person' AND p.id = t.record_id
                LEFT JOIN companies c ON t.record_type = 'company' AND c.id = t.record_id
                LEFT JOIN leads l ON t.record_type = 'lead' AND l.id = t.record_id
                LEFT JOIN deals d ON t.record_type = 'deal' AND d.id = t.record_id
                WHERE {where}
                """,
                values,
            ).fetchone()[0]
            source_count_rows = rows_to_dicts(
                conn.execute(
                    f"""
                    SELECT CASE WHEN t.zendesk_task_id IS NULL THEN 'local' ELSE 'imported' END AS source,
                           count(*) AS count
                    FROM tasks t
                    LEFT JOIN people p ON t.record_type = 'person' AND p.id = t.record_id
                    LEFT JOIN companies c ON t.record_type = 'company' AND c.id = t.record_id
                    LEFT JOIN leads l ON t.record_type = 'lead' AND l.id = t.record_id
                    LEFT JOIN deals d ON t.record_type = 'deal' AND d.id = t.record_id
                    WHERE {source_where}
                    GROUP BY CASE WHEN t.zendesk_task_id IS NULL THEN 'local' ELSE 'imported' END
                    """,
                    source_values,
                ).fetchall()
            )
            source_counts = {"imported": 0, "local": 0}
            for row in source_count_rows:
                source_counts[str(row.get("source") or "")] = int(row.get("count") or 0)
            records = self.task_rows(conn, status, page_size, offset, q, task_sort, direction, record_type, task_source)
        transition_plan = self.followup_transition_plan()
        return {
            "status": status,
            "q": q,
            "record_type": record_type,
            "source": task_source,
            "sort": task_sort if task_sort in self.task_sort_fields() else "due_date",
            "direction": direction,
            "page": page,
            "page_size": page_size,
            "total": total,
            "source_counts": source_counts,
            "transition_plan": transition_plan,
            "tasks": records,
        }

    def followup_transition_plan(self) -> dict[str, Any]:
        with self.db() as conn:
            counts = row_to_dict(
                conn.execute(
                    """
                    SELECT
                        sum(CASE WHEN completed = 0 THEN 1 ELSE 0 END) AS open_total,
                        sum(CASE WHEN completed = 0 AND zendesk_task_id IS NOT NULL THEN 1 ELSE 0 END) AS open_imported,
                        sum(CASE WHEN completed = 0 AND zendesk_task_id IS NULL THEN 1 ELSE 0 END) AS open_local,
                        sum(CASE WHEN completed = 0 AND zendesk_task_id IS NOT NULL AND due_date IS NOT NULL AND date(due_date) < date('now') THEN 1 ELSE 0 END) AS overdue_imported,
                        sum(CASE WHEN completed = 0 AND zendesk_task_id IS NOT NULL AND due_date IS NOT NULL AND date(due_date) BETWEEN date('now') AND date('now', '+7 days') THEN 1 ELSE 0 END) AS due_soon_imported,
                        sum(CASE WHEN completed = 0 AND zendesk_task_id IS NOT NULL AND due_date IS NULL THEN 1 ELSE 0 END) AS imported_without_due,
                        sum(CASE WHEN completed = 0 AND zendesk_task_id IS NOT NULL AND record_type IS NOT NULL AND record_id IS NOT NULL THEN 1 ELSE 0 END) AS linked_imported,
                        sum(CASE WHEN completed = 0 AND zendesk_task_id IS NOT NULL AND (record_type IS NULL OR record_type = '' OR record_id IS NULL) THEN 1 ELSE 0 END) AS unlinked_imported
                    FROM tasks
                    """
                ).fetchone()
            )
            imported_open_tasks = self.task_rows(conn, "open", 25, 0, "", "due_date", "asc", "", "imported")

        open_imported = int(counts.get("open_imported") or 0)
        open_local = int(counts.get("open_local") or 0)
        overdue_imported = int(counts.get("overdue_imported") or 0)
        imported_without_due = int(counts.get("imported_without_due") or 0)
        status = "attention" if open_imported else "ready" if open_local else "waiting"
        if open_imported:
            message = (
                f"{open_imported:,} open tasks are imported Zendesk reminders. Review them before treating the local CRM follow-up queue as clean."
            )
        elif open_local:
            message = f"{open_local:,} local CRM follow-ups are active and no imported open tasks remain."
        else:
            message = "No open imported or local follow-ups are waiting."
        steps = [
            {
                "key": "review_imported",
                "title": "Review Imported Open Tasks",
                "status": "attention" if open_imported else "ready",
                "description": "Decide which old Zendesk reminders are still useful and which are historical.",
                "preset": "followup_imported_open",
                "action": "Show Imported Open",
                "count": open_imported,
            },
            {
                "key": "review_overdue",
                "title": "Check Overdue Imported Tasks",
                "status": "attention" if overdue_imported else "ready",
                "description": "Start with dated reminders from Zendesk that are already overdue.",
                "preset": "followup_imported_overdue",
                "action": "Show Overdue Imported",
                "count": overdue_imported,
            },
            {
                "key": "create_local",
                "title": "Create Local Follow-Ups",
                "status": "waiting" if open_imported else "ready",
                "description": "For reminders that still matter, use Copy Local to create a separate local follow-up with a fresh due date.",
                "preset": "followup_local_open",
                "action": "Show Local Follow-Ups",
                "count": open_local,
            },
        ]
        return {
            "title": "Follow Up Transition Plan",
            "status": status,
            "message": message,
            "report": "/reports/followup_transition_plan.md",
            "csv": "/reports/followup_transition_plan.csv",
            "export_url": "/api/export?type=followup_transition_plan",
            "counts": {
                "open_total": int(counts.get("open_total") or 0),
                "open_imported": open_imported,
                "open_local": open_local,
                "overdue_imported": overdue_imported,
                "due_soon_imported": int(counts.get("due_soon_imported") or 0),
                "imported_without_due": imported_without_due,
                "linked_imported": int(counts.get("linked_imported") or 0),
                "unlinked_imported": int(counts.get("unlinked_imported") or 0),
            },
            "steps": steps,
            "imported_open_tasks": imported_open_tasks,
            "safety": "Reviewing or exporting this plan does not complete tasks or create local follow-ups. Task changes still require explicit local actions.",
        }

    def task_status_where(self, status: str) -> str:
        if status == "completed":
            return "t.completed = 1"
        if status == "all":
            return "1 = 1"
        if status == "overdue":
            return "t.completed = 0 AND t.due_date IS NOT NULL AND date(t.due_date) < date('now')"
        if status == "due_soon":
            return "t.completed = 0 AND t.due_date IS NOT NULL AND date(t.due_date) BETWEEN date('now') AND date('now', '+7 days')"
        return "t.completed = 0"

    def task_filter_where(self, status: str, q: str = "", record_type: str = "", task_source: str = "") -> tuple[str, list[Any]]:
        where = self.task_status_where(status)
        values: list[Any] = []
        if record_type == "unlinked":
            where += " AND (t.record_type IS NULL OR t.record_type = '' OR t.record_id IS NULL)"
        elif record_type in {"person", "company", "lead", "deal"}:
            where += " AND t.record_type = ?"
            values.append(record_type)
        if task_source == "imported":
            where += " AND t.zendesk_task_id IS NOT NULL"
        elif task_source == "local":
            where += " AND t.zendesk_task_id IS NULL"
        if q:
            like = f"%{q}%"
            where += """
                AND (
                    t.content LIKE ?
                    OR p.name LIKE ? OR p.email LIKE ?
                    OR c.name LIKE ? OR c.email LIKE ?
                    OR l.name LIKE ? OR l.email LIKE ? OR l.organization_name LIKE ?
                    OR d.name LIKE ?
                )
            """
            values.extend([like] * 9)
        return where, values

    def task_sort_fields(self) -> set[str]:
        return {"due_date", "task", "record", "status", "created_at", "updated_at"}

    def task_order_by(self, task_sort: str, direction: str) -> str:
        direction = "DESC" if direction == "desc" else "ASC"
        if task_sort == "task":
            return f"t.content COLLATE NOCASE {direction}, date(t.due_date) ASC, t.updated_at DESC"
        if task_sort == "record":
            return f"record_name COLLATE NOCASE {direction}, date(t.due_date) ASC, t.updated_at DESC"
        if task_sort == "status":
            return f"t.completed {direction}, date(t.due_date) ASC, t.updated_at DESC"
        if task_sort == "created_at":
            return f"t.created_at {direction}, date(t.due_date) ASC"
        if task_sort == "updated_at":
            return f"t.updated_at {direction}, date(t.due_date) ASC"
        return f"CASE WHEN t.due_date IS NULL THEN 1 ELSE 0 END, date(t.due_date) {direction}, t.updated_at DESC"

    def task_rows(
        self,
        conn: sqlite3.Connection,
        status: str,
        page_size: int,
        offset: int,
        q: str = "",
        task_sort: str = "due_date",
        direction: str = "asc",
        record_type: str = "",
        task_source: str = "",
    ) -> list[dict[str, Any]]:
        where, values = self.task_filter_where(status, q, record_type, task_source)
        if task_sort not in self.task_sort_fields():
            task_sort = "due_date"
        if direction not in {"asc", "desc"}:
            direction = "asc"
        order_by = self.task_order_by(task_sort, direction)
        return rows_to_dicts(
            conn.execute(
                f"""
                SELECT t.id AS source_id, t.zendesk_task_id, t.content, t.completed, t.completed_at,
                       t.due_date, t.remind_at, t.overdue, t.record_type, t.record_id,
                       t.created_at, t.updated_at,
                       CASE WHEN t.zendesk_task_id IS NULL THEN 'local' ELSE 'imported' END AS task_source,
                       CASE WHEN t.zendesk_task_id IS NULL THEN 'Local' ELSE 'Imported' END AS task_source_label,
                       CASE
                         WHEN t.record_type = 'person' THEN p.name
                         WHEN t.record_type = 'company' THEN c.name
                         WHEN t.record_type = 'lead' THEN l.name
                         WHEN t.record_type = 'deal' THEN d.name
                         ELSE NULL
                       END AS record_name
                FROM tasks t
                LEFT JOIN people p ON t.record_type = 'person' AND p.id = t.record_id
                LEFT JOIN companies c ON t.record_type = 'company' AND c.id = t.record_id
                LEFT JOIN leads l ON t.record_type = 'lead' AND l.id = t.record_id
                LEFT JOIN deals d ON t.record_type = 'deal' AND d.id = t.record_id
                WHERE {where}
                ORDER BY {order_by}
                LIMIT ? OFFSET ?
                """,
                values + [page_size, offset],
            ).fetchall()
        )

    def activity(self, params: dict[str, list[str]]) -> dict[str, Any]:
        record_type = (params.get("type", [""])[0] or "").lower()
        record_id_raw = params.get("id", [""])[0]
        q = (params.get("q", [""])[0] or "").strip()
        activity_type = (params.get("activity_type", [""])[0] or "").strip().lower()
        record_type_filter = (params.get("record_type", [""])[0] or "").strip().lower()
        date_from = self.clean_activity_date_filter(params.get("date_from", [""])[0])
        date_to = self.clean_activity_date_filter(params.get("date_to", [""])[0])
        limit = min(max(int(params.get("limit", ["100"])[0]), 10), 5000)
        with self.db() as conn:
            if record_type and record_id_raw:
                rows = self.activity_for(conn, record_type, int(record_id_raw), limit)
            else:
                rows = self.global_activity(
                    conn,
                    5000 if (q or activity_type or record_type_filter or date_from or date_to or limit > 250) else limit,
                )
        filtered_rows = self.filter_activity_rows(rows, q, activity_type, record_type_filter, date_from, date_to)
        return {
            "activity": filtered_rows[:limit],
            "total": len(filtered_rows),
            "limit": limit,
            "q": q,
            "activity_type": activity_type,
            "record_type": record_type_filter,
            "date_from": date_from,
            "date_to": date_to,
            "type": record_type or None,
            "id": int(record_id_raw) if record_id_raw else None,
        }

    def filter_activity_rows(
        self, rows: list[dict[str, Any]], q: str, activity_type: str, record_type: str, date_from: str, date_to: str
    ) -> list[dict[str, Any]]:
        needle = q.casefold()
        return [
            row
            for row in rows
            if self.activity_type_matches(row, activity_type)
            and self.activity_record_type_matches(row, record_type)
            and self.activity_date_matches(row, date_from, date_to)
            and self.activity_search_matches(row, needle)
        ]

    def clean_activity_date_filter(self, value: Any) -> str:
        text = str(value or "").strip()
        return text if re.fullmatch(r"\d{4}-\d{2}-\d{2}", text) else ""

    def activity_date_matches(self, row: dict[str, Any], date_from: str, date_to: str) -> bool:
        if not date_from and not date_to:
            return True
        occurred_at = str(row.get("occurred_at") or "")
        row_date = occurred_at[:10] if re.match(r"\d{4}-\d{2}-\d{2}", occurred_at) else ""
        if not row_date:
            return False
        if date_from and row_date < date_from:
            return False
        if date_to and row_date > date_to:
            return False
        return True

    def activity_type_matches(self, row: dict[str, Any], activity_type: str) -> bool:
        if not activity_type:
            return True
        row_type = str(row.get("activity_type") or "").lower()
        if activity_type == "archive":
            return row_type.startswith("archive_")
        if activity_type == "local_change":
            return row_type in {"audit", "cleanup_decision", "project_decision"}
        return row_type == activity_type

    def activity_record_type_matches(self, row: dict[str, Any], record_type: str) -> bool:
        if not record_type:
            return True
        row_type = str(row.get("record_type") or "").lower()
        if record_type == "unlinked":
            return not row_type or not row.get("record_id")
        return row_type == record_type

    def activity_search_matches(self, row: dict[str, Any], needle: str) -> bool:
        if not needle:
            return True
        archive_item = row.get("archive_item") if isinstance(row.get("archive_item"), dict) else {}
        values = [
            row.get("activity_type"),
            row.get("record_type"),
            row.get("record_name"),
            row.get("summary"),
            row.get("occurred_at"),
            archive_item.get("item_type"),
            archive_item.get("title"),
            archive_item.get("body"),
            archive_item.get("phone_number"),
            archive_item.get("url"),
        ]
        return needle in " ".join(str(value or "") for value in values).casefold()

    def archive_item_detail(self, params: dict[str, list[str]] | int) -> dict[str, Any]:
        if isinstance(params, int):
            item_id = params
        else:
            item_id = int(params.get("id", ["0"])[0] or 0)
        if not item_id:
            raise ValueError("Archive item id is required.")
        with self.db() as conn:
            item = row_to_dict(
                conn.execute(
                    f"""
                    {self.archive_select_sql()}
                    WHERE ai.id = ?
                    """,
                    (item_id,),
                ).fetchone()
            )
        if not item:
            raise ValueError(f"Archive item {item_id} not found.")
        return {"item": self.format_archive_item(item)}

    def archive_items(self, params: dict[str, list[str]]) -> dict[str, Any]:
        q = (params.get("q", [""])[0] or "").strip()
        item_type = (params.get("item_type", [""])[0] or "").strip()
        record_type = (params.get("record_type", [""])[0] or "").strip()
        preset = (params.get("preset", [""])[0] or "").strip()
        review_status = (params.get("review_status", [""])[0] or "").strip()
        if review_status not in {"", "unreviewed", *ARCHIVE_REVIEW_STATUS_LABELS.keys()}:
            review_status = ""
        triage_lane = self.clean_archive_triage_lane(params.get("triage_lane", [""])[0])
        if triage_lane:
            preset = "unlinked_communications"
            item_type = ""
            record_type = ""
        date_from = self.clean_activity_date_filter(params.get("date_from", [""])[0])
        date_to = self.clean_activity_date_filter(params.get("date_to", [""])[0])
        page = max(1, int(params.get("page", ["1"])[0] or 1))
        page_size = min(100, max(10, int(params.get("page_size", ["50"])[0] or 50)))
        offset = (page - 1) * page_size
        with self.db() as conn:
            clauses, values = self.archive_filter_clauses(q, item_type, record_type, preset, date_from, date_to, review_status)
            where = f"WHERE {' AND '.join(clauses)}" if clauses else ""
            if triage_lane:
                triage_rows = self.enrich_archive_triage_rows(
                    conn,
                    rows_to_dicts(
                        conn.execute(
                            f"""
                            {self.archive_select_sql()}
                            {where}
                            ORDER BY ai.occurred_at DESC, ai.id DESC
                            """,
                            values,
                        ).fetchall()
                    ),
                )
                filtered_rows = [row for row in triage_rows if row.get("triage_lane") == triage_lane]
                total = len(filtered_rows)
                items = filtered_rows[offset : offset + page_size]
            else:
                total = conn.execute(
                    f"""
                    SELECT count(*)
                    FROM imported_archive_items ai
                    LEFT JOIN people p ON ai.record_type = 'person' AND p.id = ai.record_id
                    LEFT JOIN companies c ON ai.record_type = 'company' AND c.id = ai.record_id
                    LEFT JOIN leads l ON ai.record_type = 'lead' AND l.id = ai.record_id
                    LEFT JOIN deals d ON ai.record_type = 'deal' AND d.id = ai.record_id
                    LEFT JOIN archive_review_decisions ard ON ard.archive_item_id = ai.id
                    {where}
                    """,
                    values,
                ).fetchone()[0]
                items = rows_to_dicts(
                    conn.execute(
                        f"""
                        {self.archive_select_sql()}
                        {where}
                        ORDER BY ai.occurred_at DESC, ai.id DESC
                        LIMIT ? OFFSET ?
                        """,
                        values + [page_size, offset],
                    ).fetchall()
                )
            item_counts = rows_to_dicts(
                conn.execute(
                    """
                    SELECT item_type AS value, count(*) AS count
                    FROM imported_archive_items
                    GROUP BY item_type
                    ORDER BY count DESC, item_type COLLATE NOCASE
                    """
                ).fetchall()
            )
            record_counts = rows_to_dicts(
                conn.execute(
                    """
                    SELECT coalesce(record_type, 'unlinked') AS value, count(*) AS count
                    FROM imported_archive_items
                    GROUP BY coalesce(record_type, 'unlinked')
                    ORDER BY count DESC, value COLLATE NOCASE
                    """
                ).fetchall()
            )
            review_counts = self.archive_review_counts(conn)
            unlinked_communications = self.unlinked_archive_communications_summary(conn)
            archive_triage = self.archive_review_triage_summary(conn)
            association = self.archive_association_audit_summary(conn)
        return {
            "items": [self.format_archive_item(item) for item in items],
            "total": total,
            "page": page,
            "page_size": page_size,
            "q": q,
            "item_type": item_type,
            "record_type": record_type,
            "preset": preset,
            "review_status": review_status,
            "triage_lane": triage_lane,
            "date_from": date_from,
            "date_to": date_to,
            "item_type_counts": item_counts,
            "record_type_counts": record_counts,
            "review_status_counts": review_counts,
            "unlinked_communications": unlinked_communications,
            "archive_triage": archive_triage,
            "association": association,
        }

    def archive_filter_clauses(
        self,
        q: str,
        item_type: str,
        record_type: str,
        preset: str = "",
        date_from: str = "",
        date_to: str = "",
        review_status: str = "",
    ) -> tuple[list[str], list[Any]]:
        clauses: list[str] = []
        values: list[Any] = []
        if preset == "unlinked_communications":
            clauses.append("ai.record_id IS NULL")
            clauses.append("ai.item_type IN ('call', 'text_message')")
        elif item_type:
            clauses.append("ai.item_type = ?")
            values.append(item_type)
        if record_type:
            if record_type == "unlinked":
                clauses.append("ai.record_id IS NULL")
            else:
                clauses.append("ai.record_type = ?")
                values.append(record_type)
        if review_status:
            if review_status == "unreviewed":
                clauses.append("ard.archive_item_id IS NULL")
            elif review_status in {"archive_only", "needs_lookup", "ready_to_link"}:
                clauses.append("ard.status = ?")
                values.append(review_status)
        if q:
            like = f"%{q}%"
            clauses.append(
                """
                (
                    ai.title LIKE ? OR ai.body LIKE ? OR ai.phone_number LIKE ?
                    OR ai.local_file LIKE ? OR p.name LIKE ? OR c.name LIKE ?
                    OR l.name LIKE ? OR d.name LIKE ?
                )
                """
            )
            values.extend([like, like, like, like, like, like, like, like])
        if date_from or date_to:
            archive_date_sql = "substr(coalesce(ai.occurred_at, ai.created_at, ai.updated_at, ''), 1, 10)"
            clauses.append(f"{archive_date_sql} GLOB '[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9]'")
            if date_from:
                clauses.append(f"{archive_date_sql} >= ?")
                values.append(date_from)
            if date_to:
                clauses.append(f"{archive_date_sql} <= ?")
                values.append(date_to)
        return clauses, values

    def clean_archive_triage_lane(self, value: Any) -> str:
        text = str(value or "").strip()
        return text if text in ARCHIVE_TRIAGE_LANES else ""

    def archive_phone_group_counts(self, conn: sqlite3.Connection) -> dict[tuple[str, str], int]:
        rows = rows_to_dicts(
            conn.execute(
                """
                SELECT item_type, phone_number, count(*) AS count
                FROM imported_archive_items
                WHERE record_id IS NULL
                  AND item_type IN ('call', 'text_message')
                GROUP BY item_type, phone_number
                """
            ).fetchall()
        )
        return {
            (str(row.get("item_type") or ""), str(row.get("phone_number") or "")): int(row.get("count") or 0)
            for row in rows
        }

    def enrich_archive_triage_rows(
        self,
        conn: sqlite3.Connection,
        rows: list[dict[str, Any]],
    ) -> list[dict[str, Any]]:
        if not rows:
            return []
        phone_index = self.archive_phone_index(conn)
        phone_counts = self.archive_phone_group_counts(conn)
        enriched_rows: list[dict[str, Any]] = []
        for row in rows:
            phone_key = self.normalize_phone_key(row.get("phone_number"))
            matches = phone_index.get(phone_key or "", [])
            classification = self.unlinked_archive_classification(phone_key, matches)
            group_count = phone_counts.get((str(row.get("item_type") or ""), str(row.get("phone_number") or "")), 0)
            triage = self.archive_review_triage_for_item(row, classification, group_count)
            enriched_rows.append(
                {
                    **row,
                    **triage,
                    "classification": classification,
                    "phone_group_count": group_count,
                }
            )
        return enriched_rows

    def normalize_phone_key(self, value: Any) -> str | None:
        digits = re.sub(r"\D", "", str(value or ""))
        if len(digits) < 7:
            return None
        return digits[-10:] if len(digits) >= 10 else digits

    def archive_phone_index(self, conn: sqlite3.Connection) -> dict[str, list[dict[str, Any]]]:
        index: dict[str, list[dict[str, Any]]] = {}
        sources = [
            ("people", "person", ["phone", "mobile"], "name", "email"),
            ("companies", "company", ["phone"], "name", "email"),
            ("leads", "lead", ["phone", "mobile"], "name", "email"),
        ]
        for table_name, record_type, fields, name_field, email_field in sources:
            field_sql = ", ".join(["id", name_field, email_field, *fields])
            for row in conn.execute(f"SELECT {field_sql} FROM {table_name}"):
                for field in fields:
                    key = self.normalize_phone_key(row[field])
                    if not key:
                        continue
                    index.setdefault(key, []).append(
                        {
                            "record_type": record_type,
                            "record_id": row["id"],
                            "record_name": row[name_field],
                            "email": row[email_field],
                            "phone_field": field,
                            "phone_value": row[field],
                        }
                    )
        return index

    def unlinked_archive_classification(self, phone_key: str | None, matches: list[dict[str, Any]]) -> str:
        if phone_key is None:
            return "short_or_non_contact_number"
        unique_records = {(match["record_type"], match["record_id"]) for match in matches}
        if len(unique_records) == 1:
            return "exact_unique_candidate"
        if len(unique_records) > 1:
            return "ambiguous_exact_candidates"
        return "no_crm_phone_match"

    def archive_review_counts(self, conn: sqlite3.Connection) -> list[dict[str, Any]]:
        rows = rows_to_dicts(
            conn.execute(
                """
                SELECT coalesce(ard.status, 'unreviewed') AS value, count(*) AS count
                FROM imported_archive_items ai
                LEFT JOIN archive_review_decisions ard ON ard.archive_item_id = ai.id
                WHERE ai.record_id IS NULL
                  AND ai.item_type IN ('call', 'text_message')
                GROUP BY coalesce(ard.status, 'unreviewed')
                ORDER BY
                  CASE coalesce(ard.status, 'unreviewed')
                    WHEN 'unreviewed' THEN 1
                    WHEN 'needs_lookup' THEN 2
                    WHEN 'ready_to_link' THEN 3
                    WHEN 'archive_only' THEN 4
                    ELSE 5
                  END
                """
            ).fetchall()
        )
        existing = {row["value"] for row in rows}
        for value in ["unreviewed", "needs_lookup", "ready_to_link", "archive_only"]:
            if value not in existing:
                rows.append({"value": value, "count": 0})
        return rows

    def unlinked_archive_communications_summary(self, conn: sqlite3.Connection) -> dict[str, Any]:
        phone_index = self.archive_phone_index(conn)
        rows = rows_to_dicts(
            conn.execute(
                """
                SELECT ai.id, ai.item_type, ai.phone_number, ai.occurred_at, ard.status AS review_status
                FROM imported_archive_items ai
                LEFT JOIN archive_review_decisions ard ON ard.archive_item_id = ai.id
                WHERE ai.record_id IS NULL
                  AND ai.item_type IN ('call', 'text_message')
                ORDER BY ai.occurred_at DESC, ai.id DESC
                """
            ).fetchall()
        )
        class_counts: dict[str, int] = {
            "exact_unique_candidate": 0,
            "ambiguous_exact_candidates": 0,
            "no_crm_phone_match": 0,
            "short_or_non_contact_number": 0,
        }
        phone_groups: dict[tuple[str, str, str], dict[str, Any]] = {}
        for row in rows:
            phone_key = self.normalize_phone_key(row.get("phone_number"))
            matches = phone_index.get(phone_key or "", [])
            row_class = self.unlinked_archive_classification(phone_key, matches)
            class_counts[row_class] = class_counts.get(row_class, 0) + 1
            group_key = (str(row.get("item_type") or ""), row_class, str(row.get("phone_number") or ""))
            group = phone_groups.setdefault(
                group_key,
                {
                    "item_type": row.get("item_type"),
                    "classification": row_class,
                    "phone_number": row.get("phone_number"),
                    "count": 0,
                    "first_at": row.get("occurred_at"),
                    "last_at": row.get("occurred_at"),
                    "reviewed_count": 0,
                },
            )
            group["count"] += 1
            occurred_at = row.get("occurred_at")
            if occurred_at:
                if not group.get("first_at") or occurred_at < group["first_at"]:
                    group["first_at"] = occurred_at
                if not group.get("last_at") or occurred_at > group["last_at"]:
                    group["last_at"] = occurred_at
            if row.get("review_status"):
                group["reviewed_count"] += 1
        type_counts = {
            "call": sum(1 for row in rows if row.get("item_type") == "call"),
            "text_message": sum(1 for row in rows if row.get("item_type") == "text_message"),
        }
        top_numbers = sorted(
            list(phone_groups.values()),
            key=lambda row: (-int(row["count"]), str(row["item_type"]), str(row["phone_number"])),
        )[:12]
        return {
            "total": len(rows),
            "type_counts": type_counts,
            "classification_counts": class_counts,
            "review_status_counts": self.archive_review_counts(conn),
            "crm_phone_keys": len(phone_index),
            "recommendation": "Archive-only for now",
            "reason": "No remaining unlinked calls/texts have an exact CRM phone candidate; uncertain items stay searchable without forcing weak matches.",
            "preset": "unlinked_communications",
            "report": "/reports/unlinked_archive_matching_candidates.md",
            "top_numbers": top_numbers,
        }

    def archive_review_triage_for_item(
        self,
        item: dict[str, Any],
        classification: str,
        phone_group_count: int = 0,
    ) -> dict[str, Any]:
        item_type = str(item.get("item_type") or "")
        body = str(item.get("body") or "")
        title = str(item.get("title") or "")
        text = f"{title} {body}".casefold()
        duration = int(item.get("duration_seconds") or 0)
        has_url = bool(item.get("url"))
        body_words = re.findall(r"[A-Za-z0-9]+", body)

        def result(lane: str, suggested_status: str, reason: str, signals: list[str]) -> dict[str, Any]:
            lane_def = ARCHIVE_TRIAGE_LANES.get(lane, {})
            return {
                "triage_lane": lane,
                "triage_lane_label": lane_def.get("label") or labelize(lane),
                "triage_sort": lane_def.get("sort", 99),
                "suggested_status": suggested_status,
                "suggested_status_label": archive_review_status_label(suggested_status),
                "reason": reason,
                "signals": "; ".join(signal for signal in signals if signal),
                "suggested_action": lane_def.get("action") or "Inspect the item before saving a review status.",
            }

        if classification == "exact_unique_candidate":
            return result(
                "ready_to_link_candidate",
                "ready_to_link",
                "One local CRM record shares the normalized phone number.",
                ["exact unique phone candidate"],
            )
        if classification == "ambiguous_exact_candidates":
            return result(
                "needs_lookup",
                "needs_lookup",
                "More than one local CRM record shares the normalized phone number.",
                ["ambiguous exact phone candidates"],
            )
        if classification == "short_or_non_contact_number":
            return result(
                "batch_archive_only",
                "archive_only",
                "The number looks like a short code or service sender, not a client phone.",
                ["short or non-contact number", f"{phone_group_count} related items" if phone_group_count else ""],
            )

        marketing_patterns = [
            "reply stop",
            "stop to opt",
            "opt out",
            "http://",
            "https://",
            "www.",
            " use code ",
            "20% off",
            "save you money",
            "better rate",
            "compare rates",
            "health plan",
            "health insurance",
            "freedom life",
            "us health",
            "coverage options",
            "offer",
            "discount",
            "promo",
            "quote",
        ]
        marketing_hits = [pattern.strip() for pattern in marketing_patterns if pattern in text]
        if item_type == "text_message" and marketing_hits:
            return result(
                "batch_archive_only",
                "archive_only",
                "Message body has promotional, opt-out, quote, or service-language signals and no exact CRM phone match.",
                [", ".join(marketing_hits[:3]), f"{phone_group_count} related items" if phone_group_count else ""],
            )
        if item_type == "text_message" and phone_group_count >= 3 and len(body_words) >= 8:
            return result(
                "batch_archive_only",
                "archive_only",
                "Repeated same-number text thread has no exact CRM phone match; review as an archive-only batch unless the body identifies a client.",
                [f"{phone_group_count} related items", "no exact CRM phone match"],
            )
        if item_type == "text_message" and (len(body_words) <= 8 or "?" in body):
            return result(
                "needs_lookup",
                "needs_lookup",
                "Short or conversational text may contain human context, but the phone does not match a local CRM record.",
                ["short/conversational text", "no exact CRM phone match"],
            )
        if item_type == "call":
            if has_url and duration >= 10:
                return result(
                    "needs_lookup",
                    "needs_lookup",
                    "Call has a preserved recording URL and enough duration to deserve listening before any link.",
                    ["recording URL", f"{duration} seconds"],
                )
            if duration >= 30:
                return result(
                    "needs_lookup",
                    "needs_lookup",
                    "Call duration is long enough that outside context or recording review may identify the caller.",
                    [f"{duration} seconds", "no exact CRM phone match"],
                )
            return result(
                "batch_archive_only",
                "archive_only",
                "Missed call has no exact CRM phone match and no strong identity evidence in the local CRM.",
                [
                    "missed call",
                    "no exact CRM phone match",
                    f"{phone_group_count} related calls" if phone_group_count else "",
                ],
            )

        return result(
            "manual_review",
            "needs_lookup",
            "No exact CRM phone match; inspect manually before saving a review status.",
            ["no exact CRM phone match"],
        )

    def archive_review_triage_summary(self, conn: sqlite3.Connection) -> dict[str, Any]:
        phone_index = self.archive_phone_index(conn)
        rows = rows_to_dicts(
            conn.execute(
                """
                SELECT ai.id, ai.item_type, ai.title, ai.body, ai.direction, ai.occurred_at,
                       ai.phone_number, ai.url, ai.status, ai.duration_seconds,
                       ard.status AS review_status, ard.note AS review_note
                FROM imported_archive_items ai
                LEFT JOIN archive_review_decisions ard ON ard.archive_item_id = ai.id
                WHERE ai.record_id IS NULL
                  AND ai.item_type IN ('call', 'text_message')
                ORDER BY ai.occurred_at DESC, ai.id DESC
                """
            ).fetchall()
        )
        phone_counts: dict[tuple[str, str], int] = {}
        for row in rows:
            key = (str(row.get("item_type") or ""), str(row.get("phone_number") or ""))
            phone_counts[key] = phone_counts.get(key, 0) + 1

        lane_counts = {key: 0 for key in ARCHIVE_TRIAGE_LANES}
        suggested_status_counts = {key: 0 for key in ARCHIVE_REVIEW_STATUS_LABELS}
        review_counts = {row.get("value"): int(row.get("count") or 0) for row in self.archive_review_counts(conn)}
        triaged_items: list[dict[str, Any]] = []
        group_lookup: dict[tuple[str, str, str, str, str], dict[str, Any]] = {}
        for row in rows:
            phone_key = self.normalize_phone_key(row.get("phone_number"))
            matches = phone_index.get(phone_key or "", [])
            classification = self.unlinked_archive_classification(phone_key, matches)
            group_count = phone_counts.get((str(row.get("item_type") or ""), str(row.get("phone_number") or "")), 0)
            triage = self.archive_review_triage_for_item(row, classification, group_count)
            lane = triage["triage_lane"]
            suggested = triage["suggested_status"]
            lane_counts[lane] = lane_counts.get(lane, 0) + 1
            suggested_status_counts[suggested] = suggested_status_counts.get(suggested, 0) + 1
            item = {
                **row,
                **triage,
                "classification": classification,
                "phone_group_count": group_count,
                "review_status": row.get("review_status") or "unreviewed",
                "review_status_label": archive_review_status_label(row.get("review_status") or "unreviewed"),
                "body_excerpt": " ".join(str(row.get("body") or "").split())[:220],
            }
            triaged_items.append(item)
            group_key = (
                lane,
                suggested,
                str(row.get("item_type") or ""),
                str(row.get("phone_number") or ""),
                classification,
            )
            group = group_lookup.setdefault(
                group_key,
                {
                    "triage_lane": lane,
                    "triage_lane_label": triage["triage_lane_label"],
                    "suggested_status": suggested,
                    "suggested_status_label": triage["suggested_status_label"],
                    "item_type": row.get("item_type"),
                    "phone_number": row.get("phone_number"),
                    "classification": classification,
                    "reason": triage["reason"],
                    "signals": triage["signals"],
                    "count": 0,
                    "reviewed_count": 0,
                    "first_at": row.get("occurred_at"),
                    "last_at": row.get("occurred_at"),
                    "sample_archive_item_id": row.get("id"),
                    "sample_body": item["body_excerpt"],
                },
            )
            group["count"] += 1
            if item["review_status"] != "unreviewed":
                group["reviewed_count"] += 1
            occurred_at = row.get("occurred_at")
            if occurred_at:
                if not group.get("first_at") or occurred_at < group["first_at"]:
                    group["first_at"] = occurred_at
                if not group.get("last_at") or occurred_at > group["last_at"]:
                    group["last_at"] = occurred_at

        sorted_groups = sorted(
            group_lookup.values(),
            key=lambda row: (
                ARCHIVE_TRIAGE_LANES.get(str(row.get("triage_lane") or ""), {}).get("sort", 99),
                -int(row.get("count") or 0),
                str(row.get("item_type") or ""),
                str(row.get("phone_number") or ""),
            ),
        )
        sorted_items = sorted(
            triaged_items,
            key=lambda row: (
                int(row.get("triage_sort") or 99),
                str(row.get("review_status") or "") != "unreviewed",
                str(row.get("occurred_at") or ""),
                int(row.get("id") or 0),
            ),
            reverse=False,
        )
        lane_rows = [
            {
                "triage_lane": key,
                "triage_lane_label": definition["label"],
                "count": lane_counts.get(key, 0),
                "suggested_action": definition["action"],
            }
            for key, definition in sorted(ARCHIVE_TRIAGE_LANES.items(), key=lambda item: item[1]["sort"])
        ]
        status_rows = [
            {
                "suggested_status": key,
                "suggested_status_label": label,
                "count": suggested_status_counts.get(key, 0),
            }
            for key, label in ARCHIVE_REVIEW_STATUS_LABELS.items()
        ]
        return {
            "title": "Archive Review Triage",
            "status": "attention" if review_counts.get("unreviewed", 0) else "ready",
            "message": "Suggested review lanes for unlinked calls/texts. This is evidence only; it does not save review status, link archive items, or change records.",
            "total": len(rows),
            "unreviewed": review_counts.get("unreviewed", 0),
            "lane_counts": lane_rows,
            "suggested_status_counts": status_rows,
            "top_groups": sorted_groups[:12],
            "sample_items": sorted_items[:12],
            "report": "/reports/archive_review_triage.md",
            "csv": "/reports/archive_review_triage.csv",
            "export_url": "/api/export?type=archive_review_triage",
            "safety": "Read-only triage; saving still happens only from the Archive inspector.",
        }

    def archive_association_audit_summary(self, conn: sqlite3.Connection) -> dict[str, Any]:
        type_rows = rows_to_dicts(
            conn.execute(
                """
                SELECT item_type,
                       count(*) AS total,
                       sum(CASE WHEN record_id IS NOT NULL THEN 1 ELSE 0 END) AS linked,
                       sum(CASE WHEN record_id IS NULL THEN 1 ELSE 0 END) AS unlinked,
                       sum(CASE WHEN original_resource_type IS NOT NULL AND original_resource_type != '' THEN 1 ELSE 0 END) AS has_original_resource,
                       sum(CASE WHEN related_record_id IS NOT NULL THEN 1 ELSE 0 END) AS has_related_record,
                       sum(CASE WHEN local_file IS NOT NULL AND local_file != '' THEN 1 ELSE 0 END) AS downloaded_files,
                       sum(CASE WHEN url IS NOT NULL AND url != '' THEN 1 ELSE 0 END) AS external_urls
                FROM imported_archive_items
                GROUP BY item_type
                ORDER BY total DESC, item_type COLLATE NOCASE
                """
            ).fetchall()
        )
        communication_rows = rows_to_dicts(
            conn.execute(
                """
                SELECT item_type,
                       count(*) AS total,
                       count(DISTINCT phone_number) AS distinct_numbers,
                       sum(CASE WHEN json_extract(source_json, '$.resource_id') IS NOT NULL THEN 1 ELSE 0 END) AS has_resource_id,
                       sum(CASE WHEN json_extract(source_json, '$.resource_type') IS NOT NULL THEN 1 ELSE 0 END) AS has_resource_type,
                       sum(CASE WHEN coalesce(json_array_length(source_json, '$.associated_deal_ids'), 0) > 0 THEN 1 ELSE 0 END) AS has_associated_deals,
                       sum(CASE WHEN url IS NOT NULL AND url != '' THEN 1 ELSE 0 END) AS has_external_url,
                       sum(CASE WHEN direction = 'incoming' THEN 1 ELSE 0 END) AS incoming_items,
                       sum(CASE WHEN status = 'missed' THEN 1 ELSE 0 END) AS missed_items
                FROM imported_archive_items
                WHERE record_id IS NULL
                  AND item_type IN ('call', 'text_message')
                GROUP BY item_type
                ORDER BY item_type
                """
            ).fetchall()
        )
        communication_summary = self.unlinked_archive_communications_summary(conn)
        type_lookup = {row["item_type"]: row for row in type_rows}
        exact_candidates = int((communication_summary.get("classification_counts") or {}).get("exact_unique_candidate") or 0)
        unlinked_calls = int((type_lookup.get("call") or {}).get("unlinked") or 0)
        unlinked_texts = int((type_lookup.get("text_message") or {}).get("unlinked") or 0)
        linked_documents = int((type_lookup.get("document") or {}).get("linked") or 0)
        total_archive = sum(int(row.get("total") or 0) for row in type_rows)
        linked_archive = sum(int(row.get("linked") or 0) for row in type_rows)
        unlinked_archive = sum(int(row.get("unlinked") or 0) for row in type_rows)
        document_total = int((type_lookup.get("document") or {}).get("total") or 0)
        review_counts = {row.get("value"): int(row.get("count") or 0) for row in communication_summary.get("review_status_counts") or []}
        reviewed_call_texts = sum(review_counts.get(value, 0) for value in ["archive_only", "needs_lookup", "ready_to_link"])
        return {
            "summary": {
                "total_archive_items": total_archive,
                "linked_archive_items": linked_archive,
                "unlinked_archive_items": unlinked_archive,
                "link_coverage_percent": round((linked_archive / total_archive) * 100, 1) if total_archive else 0,
                "linked_documents": linked_documents,
                "document_total": document_total,
                "document_file_coverage_percent": round((linked_documents / document_total) * 100, 1) if document_total else 0,
                "unlinked_calls": unlinked_calls,
                "unlinked_texts": unlinked_texts,
                "unlinked_call_texts": unlinked_calls + unlinked_texts,
                "unlinked_reviewed_call_texts": reviewed_call_texts,
                "unlinked_unreviewed_call_texts": review_counts.get("unreviewed", 0),
                "ready_to_link_call_texts": review_counts.get("ready_to_link", 0),
                "needs_lookup_call_texts": review_counts.get("needs_lookup", 0),
                "archive_only_call_texts": review_counts.get("archive_only", 0),
                "exact_phone_candidates": exact_candidates,
                "distinct_unlinked_numbers": sum(int(row.get("distinct_numbers") or 0) for row in communication_rows),
                "unlinked_call_recording_urls": int((next((row for row in communication_rows if row.get("item_type") == "call"), {}) or {}).get("has_external_url") or 0),
                "recommendation": "Do not auto-link remaining calls/texts.",
                "reason": "Remaining unlinked communications have no Zendesk resource IDs, no associated deals, and no exact local CRM phone candidates.",
            },
            "type_rows": type_rows,
            "communication_rows": communication_rows,
            "communication_summary": communication_summary,
            "report": "/reports/archive_association_audit.md",
            "export_url": "/api/export?type=archive_association_audit",
        }

    def archive_select_sql(self) -> str:
        return """
            SELECT ai.id, ai.item_type, ai.source_collection, ai.zendesk_record_id,
                   ai.record_type, ai.record_id, ai.related_record_type, ai.related_record_id,
                   ai.original_resource_type, ai.original_resource_id, ai.title, ai.body,
                   ai.direction, ai.occurred_at, ai.created_at, ai.updated_at, ai.user_id,
                   ai.duration_seconds, ai.phone_number, ai.content_type, ai.size_bytes,
                   ai.local_file, ai.url, ai.status, u.name AS user_name, u.email AS user_email,
                   ard.status AS review_status, ard.note AS review_note,
                   ard.created_at AS review_created_at, ard.updated_at AS review_updated_at,
                   CASE
                     WHEN ai.record_type = 'person' THEN p.name
                     WHEN ai.record_type = 'company' THEN c.name
                     WHEN ai.record_type = 'lead' THEN l.name
                     WHEN ai.record_type = 'deal' THEN d.name
                     ELSE NULL
                   END AS record_name
            FROM imported_archive_items ai
            LEFT JOIN users u ON u.zendesk_user_id = ai.user_id
            LEFT JOIN people p ON ai.record_type = 'person' AND p.id = ai.record_id
            LEFT JOIN companies c ON ai.record_type = 'company' AND c.id = ai.record_id
            LEFT JOIN leads l ON ai.record_type = 'lead' AND l.id = ai.record_id
            LEFT JOIN deals d ON ai.record_type = 'deal' AND d.id = ai.record_id
            LEFT JOIN archive_review_decisions ard ON ard.archive_item_id = ai.id
        """

    def format_archive_item(self, item: dict[str, Any]) -> dict[str, Any]:
        item = dict(item)
        item["label"] = self.archive_item_label(item.get("item_type"))
        item["file_url"] = f"/api/archive_file?id={item['id']}" if item.get("local_file") else None
        item["size_label"] = self.size_label(item.get("size_bytes"))
        return item

    def link_archive_item(self, payload: dict[str, Any], actor_user: dict[str, Any] | None = None, permission_action: str | None = "link_archive_item") -> dict[str, Any]:
        item_id = int(payload.get("id", 0))
        record_type = str(payload.get("record_type") or "").lower().strip()
        record_id = int(payload.get("record_id", 0))
        if not item_id:
            raise ValueError("Archive item id is required.")
        if record_type not in {"person", "company", "lead", "deal"}:
            raise ValueError("Choose a supported record type.")
        if not record_id:
            raise ValueError("Record id is required.")
        if not self.record_exists(record_type, record_id):
            raise ValueError(f"{record_type} {record_id} not found.")
        with self.db() as conn:
            item = conn.execute(
                """
                SELECT id, item_type, title, body, phone_number, record_type, record_id
                FROM imported_archive_items
                WHERE id = ?
                """,
                (item_id,),
            ).fetchone()
            if not item:
                raise ValueError(f"Archive item {item_id} not found.")
            if item["record_type"] and item["record_id"]:
                raise ValueError("This archive item is already linked. Relinking is intentionally separate.")
            old_target = {"record_type": item["record_type"], "record_id": item["record_id"]}

        backup_path = self.create_backup(f"before_archive_link_{item_id}")
        new_target = {"record_type": record_type, "record_id": record_id, "archive_item_id": item_id}
        with self.db() as conn:
            item = conn.execute(
                """
                SELECT id, item_type, title, body, phone_number, record_type, record_id
                FROM imported_archive_items
                WHERE id = ?
                """,
                (item_id,),
            ).fetchone()
            if not item:
                raise ValueError(f"Archive item {item_id} not found.")
            if item["record_type"] and item["record_id"]:
                raise ValueError("This archive item is already linked. Relinking is intentionally separate.")
            conn.execute(
                """
                UPDATE imported_archive_items
                SET record_type = ?, record_id = ?
                WHERE id = ?
                """,
                (record_type, record_id, item_id),
            )
            self.insert_audit_log(
                conn,
                action="link_archive_item",
                record_type=record_type,
                record_id=record_id,
                field_name="archive_item.link",
                old_value=old_target,
                new_value=new_target,
                note=f"Backup: {backup_path.name}; archive_item_id={item_id}; item_type={item['item_type']}",
                actor_user=actor_user,
                permission_action=permission_action,
            )
            conn.commit()
        return {
            "ok": True,
            "backup": str(backup_path),
            "archive_item": self.archive_item_detail(item_id)["item"],
            "detail": self.record_detail({"type": [record_type], "id": [str(record_id)]}),
        }

    def save_archive_review(self, payload: dict[str, Any], actor_user: dict[str, Any] | None = None, permission_action: str | None = "archive_review_status") -> dict[str, Any]:
        item_id = int(payload.get("id", 0))
        status = str(payload.get("status") or "").strip().lower()
        note = self.clean_optional(payload.get("note"))
        if not item_id:
            raise ValueError("Archive item id is required.")
        if status not in ARCHIVE_REVIEW_STATUS_LABELS:
            raise ValueError("Choose a supported archive review status.")
        with self.db() as conn:
            item = conn.execute(
                """
                SELECT id, item_type, title, record_type, record_id
                FROM imported_archive_items
                WHERE id = ?
                """,
                (item_id,),
            ).fetchone()
            if not item:
                raise ValueError(f"Archive item {item_id} not found.")
            existing = conn.execute(
                """
                SELECT status, note
                FROM archive_review_decisions
                WHERE archive_item_id = ?
                """,
                (item_id,),
            ).fetchone()
            if existing and existing["status"] == status and (existing["note"] or None) == note:
                return {"ok": True, "backup": None, "archive_item": self.archive_item_detail(item_id)["item"]}
            old_value = (
                json.dumps({"status": existing["status"], "note": existing["note"]}, ensure_ascii=False, sort_keys=True)
                if existing
                else None
            )

        backup_path = self.create_backup(f"before_archive_review_{item_id}")
        new_value = json.dumps({"status": status, "note": note}, ensure_ascii=False, sort_keys=True)
        with self.db() as conn:
            item = conn.execute(
                """
                SELECT id, item_type, title
                FROM imported_archive_items
                WHERE id = ?
                """,
                (item_id,),
            ).fetchone()
            if not item:
                raise ValueError(f"Archive item {item_id} not found.")
            conn.execute(
                """
                INSERT INTO archive_review_decisions (archive_item_id, status, note, updated_at)
                VALUES (?, ?, ?, CURRENT_TIMESTAMP)
                ON CONFLICT(archive_item_id) DO UPDATE SET
                    status = excluded.status,
                    note = excluded.note,
                    updated_at = CURRENT_TIMESTAMP
                """,
                (item_id, status, note),
            )
            self.insert_audit_log(
                conn,
                action="save_archive_review",
                record_type="archive_item",
                record_id=item_id,
                field_name="archive_review.status",
                old_value=old_value,
                new_value=new_value,
                note=f"Backup: {backup_path.name}; archive_item_id={item_id}; item_type={item['item_type']}",
                actor_user=actor_user,
                permission_action=permission_action,
            )
            conn.commit()
        return {"ok": True, "backup": str(backup_path), "archive_item": self.archive_item_detail(item_id)["item"]}

    def archive_item_label(self, item_type: Any) -> str:
        return {
            "call": "Call",
            "text_message": "Text Message",
            "document": "Document",
            "order": "Order",
            "lead_conversion": "Lead Conversion",
        }.get(str(item_type or ""), labelize(str(item_type or "archive")))

    def size_label(self, size: Any) -> str | None:
        if size is None:
            return None
        try:
            value = float(size)
        except (TypeError, ValueError):
            return None
        if value >= 1024 * 1024:
            return f"{value / (1024 * 1024):.1f} MB"
        return f"{round(value / 1024):,} KB"

    def activity_for(self, conn: sqlite3.Connection, record_type: str, record_id: int, limit: int) -> list[dict[str, Any]]:
        items: list[dict[str, Any]] = []
        items.extend(
            {
                "activity_type": "note",
                "record_type": record_type,
                "record_id": record_id,
                "record_name": None,
                "summary": row["content"],
                "occurred_at": row["created_at"],
            }
            for row in conn.execute(
                """
                SELECT content, created_at
                FROM notes
                WHERE record_type = ? AND record_id = ?
                """,
                (record_type, record_id),
            ).fetchall()
        )
        items.extend(
            {
                "activity_type": "task_completed" if row["completed"] else "task",
                "record_type": record_type,
                "record_id": record_id,
                "record_name": None,
                "summary": row["content"],
                "occurred_at": row["completed_at"] or row["due_date"] or row["created_at"],
            }
            for row in conn.execute(
                """
                SELECT content, completed, completed_at, due_date, created_at
                FROM tasks
                WHERE record_type = ? AND record_id = ?
                """,
                (record_type, record_id),
            ).fetchall()
        )
        items.extend(
            self.audit_activity_item(row)
            for row in conn.execute(
                """
                SELECT action, record_type, record_id, field_name, old_value, new_value, note, created_at,
                       app_user_id, actor_email, actor_roles, permission_action
                FROM audit_log
                WHERE record_type = ? AND record_id = ?
                """,
                (record_type, record_id),
            ).fetchall()
        )
        items.extend(self.related_record_activity(conn, record_type, record_id, limit))
        items.extend(self.archive_activity_for(conn, record_type, record_id, limit))
        if record_type in {"person", "company"}:
            deal_clause = "person_id = ?" if record_type == "person" else "company_id = ?"
            items.extend(
                {
                    "activity_type": "deal",
                    "record_type": "deal",
                    "record_id": row["id"],
                    "record_name": row["name"],
                    "summary": f"{row['name']} ({row['stage_name'] or 'No stage'})",
                    "occurred_at": row["updated_at"] or row["created_at"],
                }
                for row in conn.execute(
                    f"""
                    SELECT d.id, d.name, d.created_at, d.updated_at, s.name AS stage_name
                    FROM deals d
                    LEFT JOIN stages s ON s.id = d.stage_id
                    WHERE d.{deal_clause}
                    """,
                    (record_id,),
                ).fetchall()
            )
        return sorted(items, key=lambda item: item.get("occurred_at") or "", reverse=True)[:limit]

    def related_record_activity(
        self, conn: sqlite3.Connection, record_type: str, record_id: int, limit: int
    ) -> list[dict[str, Any]]:
        items: list[dict[str, Any]] = []
        if record_type == "person":
            items.extend(
                self.note_task_activity_for_related_records(
                    conn,
                    "deal",
                    """
                    SELECT DISTINCT d.id AS source_id, d.name
                    FROM deals d
                    LEFT JOIN people p ON p.id = ?
                    WHERE d.person_id = ?
                       OR (p.company_id IS NOT NULL AND d.company_id = p.company_id)
                    """,
                    (record_id, record_id),
                    limit,
                )
            )
        elif record_type == "company":
            items.extend(
                self.note_task_activity_for_related_records(
                    conn,
                    "person",
                    """
                    SELECT id AS source_id, name
                    FROM people
                    WHERE company_id = ?
                    """,
                    (record_id,),
                    limit,
                )
            )
            items.extend(
                self.note_task_activity_for_related_records(
                    conn,
                    "deal",
                    """
                    SELECT id AS source_id, name
                    FROM deals
                    WHERE company_id = ?
                    """,
                    (record_id,),
                    limit,
                )
            )
        elif record_type == "lead":
            items.extend(
                self.note_task_activity_for_related_records(
                    conn,
                    "person",
                    """
                    SELECT p.id AS source_id, p.name
                    FROM leads l
                    JOIN people p ON p.id = l.possible_person_id
                    WHERE l.id = ?
                    """,
                    (record_id,),
                    limit,
                )
            )
        elif record_type == "deal":
            items.extend(
                self.note_task_activity_for_related_records(
                    conn,
                    "person",
                    """
                    SELECT p.id AS source_id, p.name
                    FROM deals d
                    JOIN people p ON p.id = d.person_id
                    WHERE d.id = ?
                    """,
                    (record_id,),
                    limit,
                )
            )
            items.extend(
                self.note_task_activity_for_related_records(
                    conn,
                    "company",
                    """
                    SELECT c.id AS source_id, c.name
                    FROM deals d
                    JOIN companies c ON c.id = d.company_id
                    WHERE d.id = ?
                    """,
                    (record_id,),
                    limit,
                )
            )
        return items

    def note_task_activity_for_related_records(
        self,
        conn: sqlite3.Connection,
        related_type: str,
        related_sql: str,
        values: tuple[Any, ...],
        limit: int,
    ) -> list[dict[str, Any]]:
        return rows_to_dicts(
            conn.execute(
                f"""
                WITH related_records AS (
                    {related_sql}
                )
                SELECT 'note' AS activity_type, ? AS record_type,
                       rr.source_id AS record_id, rr.name AS record_name,
                       n.content AS summary, n.created_at AS occurred_at
                FROM related_records rr
                JOIN notes n ON n.record_type = ? AND n.record_id = rr.source_id
                UNION ALL
                SELECT CASE WHEN t.completed THEN 'task_completed' ELSE 'task' END AS activity_type,
                       ? AS record_type, rr.source_id AS record_id, rr.name AS record_name,
                       t.content AS summary, coalesce(t.completed_at, t.due_date, t.created_at) AS occurred_at
                FROM related_records rr
                JOIN tasks t ON t.record_type = ? AND t.record_id = rr.source_id
                ORDER BY occurred_at DESC
                LIMIT ?
                """,
                (*values, related_type, related_type, related_type, related_type, limit),
            ).fetchall()
        )

    def global_activity(self, conn: sqlite3.Connection, limit: int) -> list[dict[str, Any]]:
        items = rows_to_dicts(
            conn.execute(
                """
                SELECT 'note' AS activity_type, n.record_type, n.record_id,
                       n.content AS summary, n.created_at AS occurred_at,
                       CASE
                         WHEN n.record_type = 'person' THEN p.name
                         WHEN n.record_type = 'company' THEN c.name
                         WHEN n.record_type = 'lead' THEN l.name
                         WHEN n.record_type = 'deal' THEN d.name
                         ELSE NULL
                       END AS record_name
                FROM notes n
                LEFT JOIN people p ON n.record_type = 'person' AND p.id = n.record_id
                LEFT JOIN companies c ON n.record_type = 'company' AND c.id = n.record_id
                LEFT JOIN leads l ON n.record_type = 'lead' AND l.id = n.record_id
                LEFT JOIN deals d ON n.record_type = 'deal' AND d.id = n.record_id
                UNION ALL
                SELECT CASE WHEN t.completed THEN 'task_completed' ELSE 'task' END AS activity_type,
                       t.record_type, t.record_id, t.content AS summary,
                       coalesce(t.completed_at, t.due_date, t.created_at) AS occurred_at,
                       CASE
                         WHEN t.record_type = 'person' THEN p.name
                         WHEN t.record_type = 'company' THEN c.name
                         WHEN t.record_type = 'lead' THEN l.name
                         WHEN t.record_type = 'deal' THEN d.name
                         ELSE NULL
                       END AS record_name
                FROM tasks t
                LEFT JOIN people p ON t.record_type = 'person' AND p.id = t.record_id
                LEFT JOIN companies c ON t.record_type = 'company' AND c.id = t.record_id
                LEFT JOIN leads l ON t.record_type = 'lead' AND l.id = t.record_id
                LEFT JOIN deals d ON t.record_type = 'deal' AND d.id = t.record_id
                ORDER BY occurred_at DESC
                LIMIT ?
                """,
                (limit,),
            ).fetchall()
        )
        items.extend(
            self.audit_activity_item(row, record_name=row["record_name"])
            for row in conn.execute(
                """
                SELECT a.action, a.record_type, a.record_id, a.field_name,
                       a.old_value, a.new_value, a.note, a.created_at,
                       a.app_user_id, a.actor_email, a.actor_roles, a.permission_action,
                       CASE
                         WHEN a.record_type = 'person' THEN p.name
                         WHEN a.record_type = 'company' THEN c.name
                         WHEN a.record_type = 'lead' THEN l.name
                         WHEN a.record_type = 'deal' THEN d.name
                         ELSE NULL
                       END AS record_name
                FROM audit_log a
                LEFT JOIN people p ON a.record_type = 'person' AND p.id = a.record_id
                LEFT JOIN companies c ON a.record_type = 'company' AND c.id = a.record_id
                LEFT JOIN leads l ON a.record_type = 'lead' AND l.id = a.record_id
                LEFT JOIN deals d ON a.record_type = 'deal' AND d.id = a.record_id
                ORDER BY a.created_at DESC
                LIMIT ?
                """,
                (limit,),
            ).fetchall()
        )
        items.extend(self.archive_activity_global(conn, limit))
        return sorted(items, key=lambda item: item.get("occurred_at") or "", reverse=True)[:limit]

    def archive_activity_for(self, conn: sqlite3.Connection, record_type: str, record_id: int, limit: int) -> list[dict[str, Any]]:
        rows = rows_to_dicts(
            conn.execute(
                f"""
                {self.archive_select_sql()}
                WHERE (ai.record_type = ? AND ai.record_id = ?)
                   OR (ai.related_record_type = ? AND ai.related_record_id = ?)
                ORDER BY ai.occurred_at DESC, ai.id DESC
                LIMIT ?
                """,
                (record_type, record_id, record_type, record_id, limit),
            ).fetchall()
        )
        return [self.archive_activity_item(row) for row in rows]

    def archive_activity_global(self, conn: sqlite3.Connection, limit: int) -> list[dict[str, Any]]:
        rows = rows_to_dicts(
            conn.execute(
                f"""
                {self.archive_select_sql()}
                ORDER BY ai.occurred_at DESC, ai.id DESC
                LIMIT ?
                """,
                (limit,),
            ).fetchall()
        )
        return [self.archive_activity_item(row) for row in rows]

    def archive_activity_item(self, row: dict[str, Any]) -> dict[str, Any]:
        item = self.format_archive_item(row)
        return {
            "activity_type": f"archive_{item.get('item_type')}",
            "record_type": item.get("record_type"),
            "record_id": item.get("record_id"),
            "record_name": item.get("record_name"),
            "summary": self.archive_activity_summary(item),
            "occurred_at": item.get("occurred_at"),
            "archive_item": item,
        }

    def archive_activity_summary(self, item: dict[str, Any]) -> str:
        title = item.get("title") or item.get("label") or "Imported archive item"
        body = item.get("body") or ""
        if item.get("item_type") == "document" and item.get("size_label"):
            body = " · ".join(part for part in [body, item.get("size_label")] if part)
        return f"{title}: {body}" if body else title

    def audit_activity_item(self, row: sqlite3.Row, record_name: str | None = None) -> dict[str, Any]:
        action = row["action"]
        item = {
            "activity_type": "project_decision"
            if action == "save_project_decision"
            else "cleanup_decision"
            if action in {"resolve_flag", "save_cleanup_decision"}
            else "audit",
            "record_type": row["record_type"],
            "record_id": row["record_id"],
            "record_name": record_name,
            "summary": self.audit_activity_summary(row),
            "occurred_at": row["created_at"],
        }
        row_keys = set(row.keys())
        if "app_user_id" in row_keys:
            item["app_user_id"] = row["app_user_id"]
        if "actor_email" in row_keys:
            item["actor_email"] = row["actor_email"]
        if "actor_roles" in row_keys:
            item["actor_roles"] = row["actor_roles"]
        if "permission_action" in row_keys:
            item["permission_action"] = row["permission_action"]
        return item

    def audit_activity_summary(self, row: sqlite3.Row) -> str:
        action = row["action"]
        if action == "resolve_flag":
            status = str(row["new_value"] or "updated").lower()
            status_labels = {"resolved": "resolved", "ignored": "ignored", "open": "reopened"}
            label = status_labels.get(status, status)
            flag_id = self.audit_note_metadata(row["note"], "flag_id")
            note = self.audit_user_note(row["note"])
            flag_text = f" #{flag_id}" if flag_id else ""
            note_text = f": {note}" if note else ""
            return f"Cleanup flag{flag_text} {label}{note_text}"
        if action == "save_cleanup_decision":
            decision = str(row["new_value"] or "needs_review")
            label = CLEANUP_GROUP_DECISIONS.get(decision, decision.replace("_", " ").title())
            note = self.audit_user_note(row["note"])
            note_text = f": {note}" if note else ""
            return f"Cleanup group decision: {label}{note_text}"
        if action == "save_project_decision":
            key = str(row["field_name"] or "")
            definition = next((item for item in PROJECT_DECISIONS if item["key"] == key), None)
            decision_title = definition["title"] if definition else labelize(key)
            choice = str(row["new_value"] or "")
            option = next((item for item in (definition or {}).get("options", []) if item["value"] == choice), None)
            status = self.audit_note_metadata(row["note"], "status")
            note = self.audit_user_note(row["note"])
            choice_text = option["label"] if option else labelize(choice or status or "updated")
            note_text = f": {note}" if note else ""
            return f"Project decision saved: {decision_title} · {choice_text}{note_text}"
        field = row["field_name"] or ""
        if action == "update_record" and field:
            return f"Updated {field}"
        if action == "update_tags":
            return "Updated tags"
        if action == "update_address":
            return "Updated address"
        if action == "add_note":
            return "Added note"
        if action == "update_note":
            return "Updated note"
        if action == "add_task":
            return "Added task"
        if action == "create_record":
            return "Created record"
        if action == "update_task":
            return "Updated task"
        if action == "complete_task":
            return "Reopened task" if row["new_value"] == "0" else "Completed task"
        if action == "link_archive_item":
            item_id = self.audit_note_metadata(row["note"], "archive_item_id")
            item_text = f" #{item_id}" if item_id else ""
            return f"Linked archive item{item_text}"
        if action == "save_archive_review":
            item_id = self.audit_note_metadata(row["note"], "archive_item_id")
            item_text = f" #{item_id}" if item_id else ""
            try:
                value = json.loads(row["new_value"] or "{}")
            except json.JSONDecodeError:
                value = {}
            status = str(value.get("status") or "")
            label = ARCHIVE_REVIEW_STATUS_LABELS.get(status, labelize(status or "reviewed"))
            return f"Archive item{item_text} marked {label}"
        if action == "restore_backup":
            return "Restored local backup"
        return f"{action} {field}".strip()

    def audit_note_metadata(self, note: Any, key: str) -> str | None:
        prefix = f"{key}="
        for part in str(note or "").split(";"):
            text = part.strip()
            if text.startswith(prefix):
                return text[len(prefix) :].strip() or None
        return None

    def audit_user_note(self, note: Any) -> str | None:
        user_parts = []
        for part in str(note or "").split(";"):
            text = part.strip()
            if (
                not text
                or text.startswith("flag_id=")
                or text.startswith("archive_item_id=")
                or text.startswith("item_type=")
                or text.lower().startswith("backup:")
            ):
                continue
            user_parts.append(text)
        return "; ".join(user_parts) or None

    def tags(self, params: dict[str, list[str]]) -> dict[str, Any]:
        tag_id = int(params.get("id", ["0"])[0] or 0)
        page = max(1, int(params.get("page", ["1"])[0] or 1))
        page_size = min(100, max(10, int(params.get("page_size", ["50"])[0] or 50)))
        offset = (page - 1) * page_size
        q = (params.get("q", [""])[0] or "").strip()
        record_type = (params.get("record_type", [""])[0] or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal"}:
            record_type = ""
        with self.db() as conn:
            if tag_id:
                return self.tag_detail(conn, tag_id, page, page_size, offset, record_type)

            filtered = self.filtered_tag_rows(conn, q, record_type)
            rows = filtered["rows"][offset : offset + page_size]
            total_assignments = filtered["total_assignments"]
            record_type_counts = self.tag_record_type_counts(conn, q)
        for row in rows:
            row["record_types"] = sorted(filter(None, str(row["record_types"]).split(",")))
        return {
            "q": q,
            "record_type": record_type,
            "page": page,
            "page_size": page_size,
            "total": len(filtered["rows"]),
            "total_assignments": total_assignments,
            "record_type_counts": record_type_counts,
            "tags": rows,
        }

    def filtered_tag_rows(self, conn: sqlite3.Connection, q: str, record_type: str) -> dict[str, Any]:
        where_clauses: list[str] = []
        where_values: list[Any] = []
        if q:
            like = f"%{q}%"
            where_clauses.append("(t.display_name LIKE ? OR t.normalized_name LIKE ?)")
            where_values.extend([like, like])
        if record_type:
            where_clauses.append(
                """
                EXISTS (
                    SELECT 1
                    FROM tag_assignments ta_filter
                    WHERE ta_filter.tag_id = t.id
                      AND ta_filter.record_type = ?
                )
                """
            )
            where_values.append(record_type)
        where = f"WHERE {' AND '.join(where_clauses)}" if where_clauses else ""
        join_filter = "AND ta.record_type = ?" if record_type else ""
        join_values = [record_type] if record_type else []
        rows = rows_to_dicts(
            conn.execute(
                f"""
                SELECT t.id AS source_id, t.display_name, t.normalized_name, t.definition_count,
                       count(ta.id) AS assignment_count,
                       coalesce(group_concat(DISTINCT ta.record_type), '') AS record_types
                FROM tags t
                LEFT JOIN tag_assignments ta ON ta.tag_id = t.id {join_filter}
                {where}
                GROUP BY t.id
                ORDER BY assignment_count DESC, t.display_name COLLATE NOCASE
                """,
                (*join_values, *where_values),
            ).fetchall()
        )
        assignment_where = where
        assignment_values = list(where_values)
        if record_type:
            if assignment_where:
                assignment_where = f"{assignment_where} AND ta.record_type = ?"
            else:
                assignment_where = "WHERE ta.record_type = ?"
            assignment_values.append(record_type)
        total_assignments = conn.execute(
            f"""
            SELECT count(*)
            FROM tag_assignments ta
            JOIN tags t ON t.id = ta.tag_id
            {assignment_where}
            """,
            assignment_values,
        ).fetchone()[0]
        return {"rows": rows, "total_assignments": total_assignments}

    def tag_record_type_counts(self, conn: sqlite3.Connection, q: str = "") -> list[dict[str, Any]]:
        where = ""
        values: list[Any] = []
        if q:
            like = f"%{q}%"
            where = "WHERE t.display_name LIKE ? OR t.normalized_name LIKE ?"
            values.extend([like, like])
        return rows_to_dicts(
            conn.execute(
                f"""
                SELECT ta.record_type AS value, count(DISTINCT ta.tag_id) AS count
                FROM tag_assignments ta
                JOIN tags t ON t.id = ta.tag_id
                {where}
                GROUP BY ta.record_type
                ORDER BY count DESC, value COLLATE NOCASE
                """,
                values,
            ).fetchall()
        )

    def tag_detail(
        self, conn: sqlite3.Connection, tag_id: int, page: int, page_size: int, offset: int, record_type: str = ""
    ) -> dict[str, Any]:
        tag = row_to_dict(
            conn.execute(
                "SELECT id AS source_id, display_name, normalized_name, definition_count FROM tags WHERE id = ?",
                (tag_id,),
            ).fetchone()
        )
        if not tag:
            return {"error": "Tag not found"}
        filter_sql = " AND ta.record_type = ?" if record_type else ""
        values: list[Any] = [tag_id]
        if record_type:
            values.append(record_type)
        total = conn.execute(f"SELECT count(*) FROM tag_assignments ta WHERE ta.tag_id = ?{filter_sql}", values).fetchone()[0]
        records = rows_to_dicts(
            conn.execute(
                f"""
                SELECT ta.record_type, ta.record_id AS source_id, ta.source_name,
                       CASE
                         WHEN ta.record_type = 'person' THEN p.name
                         WHEN ta.record_type = 'company' THEN c.name
                         WHEN ta.record_type = 'lead' THEN l.name
                         WHEN ta.record_type = 'deal' THEN d.name
                         ELSE NULL
                       END AS name,
                       CASE
                         WHEN ta.record_type = 'person' THEN p.email
                         WHEN ta.record_type = 'company' THEN c.email
                         WHEN ta.record_type = 'lead' THEN l.email
                         WHEN ta.record_type = 'deal' THEN s.name
                         ELSE NULL
                       END AS secondary,
                       CASE
                         WHEN ta.record_type = 'person' THEN p.updated_at
                         WHEN ta.record_type = 'company' THEN c.updated_at
                         WHEN ta.record_type = 'lead' THEN l.updated_at
                         WHEN ta.record_type = 'deal' THEN d.updated_at
                         ELSE NULL
                       END AS updated_at
                FROM tag_assignments ta
                LEFT JOIN people p ON ta.record_type = 'person' AND p.id = ta.record_id
                LEFT JOIN companies c ON ta.record_type = 'company' AND c.id = ta.record_id
                LEFT JOIN leads l ON ta.record_type = 'lead' AND l.id = ta.record_id
                LEFT JOIN deals d ON ta.record_type = 'deal' AND d.id = ta.record_id
                LEFT JOIN stages s ON s.id = d.stage_id
                WHERE ta.tag_id = ?{filter_sql}
                ORDER BY ta.record_type, name COLLATE NOCASE
                LIMIT ? OFFSET ?
                """,
                (*values, page_size, offset),
            ).fetchall()
        )
        return {"tag": tag, "records": records, "total": total, "page": page, "page_size": page_size, "record_type": record_type}

    def profile_filters(self, params: dict[str, list[str]]) -> dict[str, Any]:
        list_type = (params.get("type", ["leads"])[0] or "leads").lower()
        record_type = {"people": "person", "person": "person", "leads": "lead", "lead": "lead"}.get(list_type)
        if not record_type:
            return {"record_type": list_type, "fields": []}
        with self.db() as conn:
            fields = [field for field in self.application_profile_segments(conn, record_type) if field["values"]]
        return {"record_type": record_type, "fields": fields}

    def profile_filter_sort_key(self, field_name: str, row: dict[str, Any]) -> tuple[int, int, str]:
        value = row["value"]
        ordered_values = PROFILE_FILTER_VALUE_ORDER.get(field_name, [])
        if value in ordered_values:
            return (0, ordered_values.index(value), value)
        return (1, -int(row["count"] or 0), value.lower())

    def attach_profile_summaries(
        self, conn: sqlite3.Connection, record_type: str, records: list[dict[str, Any]]
    ) -> None:
        if not records:
            return
        record_ids = [record["source_id"] for record in records]
        placeholders = ",".join("?" for _ in record_ids)
        field_placeholders = ",".join("?" for _ in APPLICATION_PROFILE_FILTER_FIELDS)
        rows = rows_to_dicts(
            conn.execute(
                f"""
                SELECT record_id, field_name, field_value
                FROM custom_field_values
                WHERE record_type = ?
                  AND record_id IN ({placeholders})
                  AND field_name IN ({field_placeholders})
                  AND coalesce(trim(field_value), '') <> ''
                """,
                (record_type, *record_ids, *APPLICATION_PROFILE_FILTER_FIELDS),
            ).fetchall()
        )
        by_record: dict[int, dict[str, str]] = {}
        for row in rows:
            by_record.setdefault(row["record_id"], {})[row["field_name"]] = row["field_value"]
        for record in records:
            values = by_record.get(record["source_id"], {})
            record["profile_summary"] = [
                {"field_name": field_name, "field_value": values[field_name]}
                for field_name in APPLICATION_PROFILE_FILTER_FIELDS
                if field_name in values
            ]

    def application_profile_segments(self, conn: sqlite3.Connection, record_type: str) -> list[dict[str, Any]]:
        placeholders = ",".join("?" for _ in APPLICATION_PROFILE_FILTER_FIELDS)
        rows = rows_to_dicts(
            conn.execute(
                f"""
                SELECT field_name, trim(field_value) AS field_value, count(DISTINCT record_id) AS count
                FROM custom_field_values
                WHERE record_type = ?
                  AND field_name IN ({placeholders})
                  AND coalesce(trim(field_value), '') <> ''
                GROUP BY field_name, trim(field_value)
                """,
                (record_type, *APPLICATION_PROFILE_FILTER_FIELDS),
            ).fetchall()
        )
        by_field: dict[str, list[dict[str, Any]]] = {field_name: [] for field_name in APPLICATION_PROFILE_FILTER_FIELDS}
        for row in rows:
            by_field[row["field_name"]].append({"value": row["field_value"], "count": row["count"]})
        segments = []
        for field_name in APPLICATION_PROFILE_FILTER_FIELDS:
            values = by_field[field_name]
            values.sort(key=lambda row: self.profile_filter_sort_key(field_name, row))
            segments.append({"field_name": field_name, "values": values})
        return segments

    def application_profile_decision_summary(self, conn: sqlite3.Connection) -> dict[str, Any]:
        placeholders = ",".join("?" for _ in APPLICATION_PROFILE_FIELDS)
        rows = rows_to_dicts(
            conn.execute(
                f"""
                SELECT record_type, count(DISTINCT record_id) AS record_count, count(*) AS value_count
                FROM custom_field_values
                WHERE field_name IN ({placeholders})
                GROUP BY record_type
                """,
                APPLICATION_PROFILE_FIELDS,
            ).fetchall()
        )
        by_type = {row["record_type"]: row for row in rows}
        examples_path = REPORTS_DIR / "application_profile_cleanup_examples.csv"
        conflict_groups = 0
        fill_gap_groups = 0
        if examples_path.exists():
            with examples_path.open(newline="", encoding="utf-8") as handle:
                for row in csv.DictReader(handle):
                    if (row.get("conflict_fields") or "").strip():
                        conflict_groups += 1
                    if (row.get("fill_gap_fields") or "").strip():
                        fill_gap_groups += 1
        read_only_fields = [field for field in APPLICATION_PROFILE_FIELDS if field not in APPLICATION_PROFILE_FILTER_FIELDS]
        return {
            "recommendation": "Read-only until cleanup",
            "reason": "Application Profile is already useful as a promoted view and filter surface. Make editable CRM fields only after duplicate/overlap cleanup rules are settled.",
            "lead_profile_records": int(by_type.get("lead", {}).get("record_count") or 0),
            "person_profile_records": int(by_type.get("person", {}).get("record_count") or 0),
            "value_rows": sum(int(row.get("value_count") or 0) for row in rows),
            "editable_after_cleanup_fields": APPLICATION_PROFILE_FILTER_FIELDS,
            "read_only_history_fields": read_only_fields,
            "cleanup_conflict_groups": conflict_groups,
            "cleanup_fill_gap_groups": fill_gap_groups,
            "report": "/reports/application_profile_editability_review.md",
        }

    def custom_fields(self, params: dict[str, list[str]]) -> dict[str, Any]:
        field_name = (params.get("field_name", [""])[0] or "").strip()
        record_type = (params.get("record_type", [""])[0] or "").strip().lower()
        if record_type not in {"", "person", "company", "lead", "deal"}:
            record_type = ""
        page = max(1, int(params.get("page", ["1"])[0] or 1))
        page_size = min(100, max(10, int(params.get("page_size", ["50"])[0] or 50)))
        offset = (page - 1) * page_size
        q = (params.get("q", [""])[0] or "").strip()
        with self.db() as conn:
            if field_name and record_type:
                return self.custom_field_detail(conn, record_type, field_name, page, page_size, offset)

            clauses: list[str] = []
            values: list[Any] = []
            if q:
                clauses.append("(field_name LIKE ? OR field_value LIKE ? OR record_type LIKE ?)")
                like = f"%{q}%"
                values.extend([like, like, like])
            if record_type:
                clauses.append("record_type = ?")
                values.append(record_type)
            where = f"WHERE {' AND '.join(clauses)}" if clauses else ""

            total = conn.execute(
                f"SELECT count(*) FROM (SELECT 1 FROM custom_field_values {where} GROUP BY record_type, field_name)",
                values,
            ).fetchone()[0]
            fields = rows_to_dicts(
                conn.execute(
                    f"""
                    SELECT record_type, field_name,
                           count(*) AS value_count,
                           count(DISTINCT record_id) AS record_count,
                           count(DISTINCT NULLIF(trim(coalesce(field_value, '')), '')) AS distinct_values,
                           sum(CASE WHEN field_value IS NULL OR trim(field_value) = '' THEN 1 ELSE 0 END) AS blank_count
                    FROM custom_field_values
                    {where}
                    GROUP BY record_type, field_name
                    ORDER BY value_count DESC, field_name COLLATE NOCASE
                    LIMIT ? OFFSET ?
                    """,
                    (*values, page_size, offset),
                ).fetchall()
            )
            definition_map = self.custom_field_definition_map(conn)
            for field in fields:
                definition = definition_map.get((field["record_type"], field["field_name"]))
                field["field_type"] = definition.get("field_type") if definition else None
                field["resource_type"] = definition.get("resource_type") if definition else None
                field["sample_values"] = self.custom_field_sample_values(conn, field["record_type"], field["field_name"], 3)
            application_profile_decision = self.application_profile_decision_summary(conn)
            record_type_counts = self.custom_field_record_type_counts(conn, q)
        return {
            "q": q,
            "record_type": record_type,
            "page": page,
            "page_size": page_size,
            "total": total,
            "fields": fields,
            "record_type_counts": record_type_counts,
            "application_profile_decision": application_profile_decision,
        }

    def custom_field_record_type_counts(self, conn: sqlite3.Connection, q: str = "") -> list[dict[str, Any]]:
        where = ""
        values: list[Any] = []
        if q:
            like = f"%{q}%"
            where = "WHERE field_name LIKE ? OR field_value LIKE ? OR record_type LIKE ?"
            values.extend([like, like, like])
        return rows_to_dicts(
            conn.execute(
                f"""
                SELECT record_type AS value, count(DISTINCT field_name) AS count
                FROM custom_field_values
                {where}
                GROUP BY record_type
                ORDER BY count DESC, value COLLATE NOCASE
                """,
                values,
            ).fetchall()
        )

    def custom_field_definition_map(self, conn: sqlite3.Connection) -> dict[tuple[str, str], dict[str, Any]]:
        definitions: dict[tuple[str, str], dict[str, Any]] = {}
        for row in rows_to_dicts(
            conn.execute(
                """
                SELECT resource_type, name AS field_name, field_type
                FROM custom_field_definitions
                ORDER BY resource_type, name COLLATE NOCASE
                """
            ).fetchall()
        ):
            resource_type = row["resource_type"]
            if resource_type == "lead":
                definitions[("lead", row["field_name"])] = row
            elif resource_type == "contact":
                definitions[("person", row["field_name"])] = row
                definitions[("company", row["field_name"])] = row
        return definitions

    def custom_field_sample_values(
        self, conn: sqlite3.Connection, record_type: str, field_name: str, limit: int
    ) -> list[dict[str, Any]]:
        return rows_to_dicts(
            conn.execute(
                """
                SELECT field_value, count(*) AS count
                FROM custom_field_values
                WHERE record_type = ? AND field_name = ? AND field_value IS NOT NULL AND trim(field_value) != ''
                GROUP BY field_value
                ORDER BY count DESC, field_value COLLATE NOCASE
                LIMIT ?
                """,
                (record_type, field_name, limit),
            ).fetchall()
        )

    def custom_field_detail(
        self,
        conn: sqlite3.Connection,
        record_type: str,
        field_name: str,
        page: int,
        page_size: int,
        offset: int,
    ) -> dict[str, Any]:
        if record_type not in {"person", "company", "lead", "deal"}:
            raise ValueError("Unsupported custom field record type.")
        total = conn.execute(
            "SELECT count(*) FROM custom_field_values WHERE record_type = ? AND field_name = ?",
            (record_type, field_name),
        ).fetchone()[0]
        records = rows_to_dicts(
            conn.execute(
                """
                SELECT cfv.record_type, cfv.record_id AS source_id, cfv.field_name, cfv.field_value,
                       CASE
                         WHEN cfv.record_type = 'person' THEN p.name
                         WHEN cfv.record_type = 'company' THEN c.name
                         WHEN cfv.record_type = 'lead' THEN l.name
                         WHEN cfv.record_type = 'deal' THEN d.name
                         ELSE NULL
                       END AS name,
                       CASE
                         WHEN cfv.record_type = 'person' THEN p.email
                         WHEN cfv.record_type = 'company' THEN c.email
                         WHEN cfv.record_type = 'lead' THEN l.email
                         WHEN cfv.record_type = 'deal' THEN s.name
                         ELSE NULL
                       END AS secondary,
                       CASE
                         WHEN cfv.record_type = 'person' THEN p.updated_at
                         WHEN cfv.record_type = 'company' THEN c.updated_at
                         WHEN cfv.record_type = 'lead' THEN l.updated_at
                         WHEN cfv.record_type = 'deal' THEN d.updated_at
                         ELSE NULL
                       END AS updated_at
                FROM custom_field_values cfv
                LEFT JOIN people p ON cfv.record_type = 'person' AND p.id = cfv.record_id
                LEFT JOIN companies c ON cfv.record_type = 'company' AND c.id = cfv.record_id
                LEFT JOIN leads l ON cfv.record_type = 'lead' AND l.id = cfv.record_id
                LEFT JOIN deals d ON cfv.record_type = 'deal' AND d.id = cfv.record_id
                LEFT JOIN stages s ON s.id = d.stage_id
                WHERE cfv.record_type = ? AND cfv.field_name = ?
                ORDER BY updated_at DESC, name COLLATE NOCASE
                LIMIT ? OFFSET ?
                """,
                (record_type, field_name, page_size, offset),
            ).fetchall()
        )
        definition = self.custom_field_definition_map(conn).get((record_type, field_name))
        summary = {
            "record_type": record_type,
            "field_name": field_name,
            "value_count": total,
            "record_count": conn.execute(
                "SELECT count(DISTINCT record_id) FROM custom_field_values WHERE record_type = ? AND field_name = ?",
                (record_type, field_name),
            ).fetchone()[0],
            "distinct_values": conn.execute(
                """
                SELECT count(DISTINCT NULLIF(trim(coalesce(field_value, '')), ''))
                FROM custom_field_values
                WHERE record_type = ? AND field_name = ?
                """,
                (record_type, field_name),
            ).fetchone()[0],
            "field_type": definition.get("field_type") if definition else None,
            "resource_type": definition.get("resource_type") if definition else None,
            "sample_values": self.custom_field_sample_values(conn, record_type, field_name, 12),
        }
        return {"field": summary, "records": records, "total": total, "page": page, "page_size": page_size}

