    def export_package_status(self) -> dict[str, Any]:
        manifest = self.export_manifest()
        package = manifest.get("package") or {}
        document_package = manifest.get("document_package") or {}
        bulk_export = manifest.get("bulk_export") or self.bulk_package_export_status()
        bulk_enabled = bool(bulk_export.get("enabled"))
        package_ready = bool(package.get("url")) and bulk_enabled
        document_ready = bool(document_package.get("available")) and bulk_enabled
        total_count = 2
        ready_count = int(package_ready) + int(document_ready)
        return {
            "status": "complete" if ready_count == total_count else "locked" if not bulk_enabled else "attention",
            "ready_count": ready_count,
            "total_count": total_count,
            "bulk_export": bulk_export,
            "core_package": {
                "label": package.get("label"),
                "url": package.get("url"),
                "filename": package.get("filename"),
                "ready": package_ready,
                "enabled": bulk_enabled,
            },
            "document_package": {
                "label": document_package.get("label"),
                "url": document_package.get("url"),
                "filename": document_package.get("filename"),
                "ready": document_ready,
                "enabled": bulk_enabled,
                "file_count": int(document_package.get("file_count") or 0),
                "bytes": int(document_package.get("bytes") or 0),
            },
        }

    def document_file_package_entries(self) -> list[dict[str, Any]]:
        allowed_root = (PROJECT_ROOT / "raw_api_exports").resolve()
        entries: list[dict[str, Any]] = []
        with self.db() as conn:
            rows = rows_to_dicts(
                conn.execute(
                    """
                    SELECT id, source_collection, zendesk_record_id, item_type, title,
                           record_type, record_id, local_file, occurred_at
                    FROM imported_archive_items
                    WHERE item_type = 'document'
                      AND local_file IS NOT NULL
                      AND local_file != ''
                    ORDER BY id
                    """
                ).fetchall()
            )
        for row in rows:
            path = (PROJECT_ROOT / str(row.get("local_file") or "")).resolve()
            if allowed_root not in path.parents or not path.exists() or not path.is_file():
                continue
            safe_name = re.sub(r"[^A-Za-z0-9._ -]+", "_", path.name).strip(" .") or f"document_{row['id']}"
            archive_path = f"document_files/{row['id']}_{safe_name}"
            entries.append(
                {
                    "id": row["id"],
                    "title": row.get("title"),
                    "record_type": row.get("record_type"),
                    "record_id": row.get("record_id"),
                    "source_collection": row.get("source_collection"),
                    "zendesk_record_id": row.get("zendesk_record_id"),
                    "occurred_at": row.get("occurred_at"),
                    "local_file": row.get("local_file"),
                    "archive_path": archive_path,
                    "path": path,
                    "bytes": path.stat().st_size,
                }
            )
        return entries

    def document_file_package_summary(self) -> dict[str, Any]:
        entries = self.document_file_package_entries()
        return {
            "file_count": len(entries),
            "bytes": sum(int(entry.get("bytes") or 0) for entry in entries),
        }

    def document_file_package_manifest_rows(self, entries: list[dict[str, Any]]) -> list[dict[str, Any]]:
        return [
            {
                "archive_item_id": entry["id"],
                "title": entry.get("title"),
                "record_type": entry.get("record_type"),
                "record_id": entry.get("record_id"),
                "source_collection": entry.get("source_collection"),
                "zendesk_record_id": entry.get("zendesk_record_id"),
                "occurred_at": entry.get("occurred_at"),
                "local_file": entry.get("local_file"),
                "package_path": entry.get("archive_path"),
                "bytes": entry.get("bytes"),
            }
            for entry in entries
        ]

    def send_document_files_package(self) -> None:
        entries = self.document_file_package_entries()
        stamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
        filename = f"local_crm_document_files_{stamp}.zip"
        package_manifest = {
            "generated_at": datetime.now(timezone.utc).replace(microsecond=0).isoformat(),
            "source": "Local CRM downloaded Zendesk document files",
            "file_count": len(entries),
            "bytes": sum(int(entry.get("bytes") or 0) for entry in entries),
            "documents": self.document_file_package_manifest_rows(entries),
        }
        self.send_response(200)
        self.send_header("Content-Type", "application/zip")
        self.send_header("Content-Disposition", f'attachment; filename="{filename}"')
        self.end_headers()
        with zipfile.ZipFile(self.wfile, "w", compression=zipfile.ZIP_STORED) as archive:
            archive.writestr("document_files_manifest.csv", self.csv_bytes(package_manifest["documents"]))
            archive.writestr("package_manifest.json", json.dumps(package_manifest, indent=2, ensure_ascii=False))
            for entry in entries:
                archive.write(entry["path"], entry["archive_path"])

    def export_package(self) -> dict[str, Any]:
        generated_at = datetime.now(timezone.utc).replace(microsecond=0).isoformat()
        stamp = datetime.now(timezone.utc).strftime("%Y%m%dT%H%M%SZ")
        filename = f"local_crm_complete_package_{stamp}.zip"
        manifest = self.export_manifest()
        package_manifest: dict[str, Any] = {
            "generated_at": generated_at,
            "source": "Local CRM",
            "database": None,
            "csv_exports": [],
            "reports": [],
            "docs": [],
        }
        buffer = io.BytesIO()
        with zipfile.ZipFile(buffer, "w", compression=zipfile.ZIP_DEFLATED) as archive:
            if self.db_path.exists():
                database_name = "database/local_crm.sqlite"
                archive.write(self.db_path, database_name)
                package_manifest["database"] = {
                    "path": database_name,
                    "bytes": self.db_path.stat().st_size,
                }

            for item in manifest.get("exports", []):
                export_type = item.get("type")
                if not export_type:
                    continue
                export = self.export_rows({"type": [str(export_type)]})
                export_path = f"csv/{export['filename']}"
                archive.writestr(export_path, self.csv_bytes(export["rows"]))
                package_manifest["csv_exports"].append(
                    {
                        "type": export_type,
                        "label": item.get("label"),
                        "path": export_path,
                        "rows": len(export["rows"]),
                    }
                )

            for report_path in sorted(REPORTS_DIR.glob("*")):
                if report_path.is_file() and report_path.suffix.lower() in {".md", ".csv", ".sql"}:
                    archive_name = f"reports/{report_path.name}"
                    archive.write(report_path, archive_name)
                    package_manifest["reports"].append({"path": archive_name, "bytes": report_path.stat().st_size})

            for doc_path in [PROJECT_ROOT / "README.md", PROJECT_ROOT / "docs" / "operating_notes.md", PROJECT_ROOT / "docs" / "project_status.md", PROJECT_ROOT / "docs" / "design_pipeline.md"]:
                if doc_path.exists() and doc_path.is_file():
                    archive_name = str(doc_path.relative_to(PROJECT_ROOT))
                    archive.write(doc_path, archive_name)
                    package_manifest["docs"].append({"path": archive_name, "bytes": doc_path.stat().st_size})

            archive.writestr("package_manifest.json", json.dumps(package_manifest, indent=2, ensure_ascii=False))
        return {"filename": filename, "payload": buffer.getvalue(), "manifest": package_manifest}

