    def export_project_decision_rows(self) -> list[dict[str, Any]]:
        data = self.project_decisions()
        recommended_preview = self.recommended_cleanup_execution_preview()
        recommended_action_by_type = {
            action.get("group_type"): action for action in recommended_preview.get("actions", [])
        }
        decision_action_type = {
            "duplicate_people_merge_policy": "duplicate_people",
            "duplicate_leads_merge_policy": "duplicate_leads",
            "lead_person_overlap_policy": "lead_person_overlap",
            "duplicate_tag_policy": "duplicate_tags",
        }
        rows = []
        for decision in data.get("decisions", []):
            impact = decision.get("impact") or {}
            sequence = decision.get("sequence") or {}
            simulated_action = recommended_action_by_type.get(decision_action_type.get(decision.get("key"))) or {}
            row = {
                "key": decision.get("key"),
                "title": decision.get("title"),
                "category": decision.get("category"),
                "sequence_step": sequence.get("step"),
                "sequence_phase": sequence.get("phase"),
                "sequence_timing": sequence.get("recommended_timing"),
                "status": decision.get("status"),
                "status_label": decision.get("status_label"),
                "choice": decision.get("choice"),
                "choice_label": decision.get("choice_label"),
                "recommended_choice": decision.get("recommendation"),
                "recommended_label": (decision.get("recommended_option") or {}).get("label"),
                "question": decision.get("question"),
                "impact_readiness": impact.get("readiness"),
                "impact_summary": impact.get("summary"),
                "next_step": impact.get("next_step"),
                "after_save": sequence.get("after_save"),
                "save_creates_backup": "yes",
                "save_records": PROJECT_DECISION_SAVE_RECORDS,
                "save_does_not": PROJECT_DECISION_SAVE_DOES_NOT,
                "save_safety": PROJECT_DECISION_SAVE_SAFETY,
                "restore_path": PROJECT_DECISION_RESTORE_PATH,
                "note": decision.get("note"),
                "updated_at": decision.get("updated_at"),
                "report": decision.get("report"),
                "worksheet_report": decision.get("worksheet_report"),
                "worksheet_export_url": decision.get("worksheet_export_url"),
                "view": decision.get("view"),
                "recommended_path_simulated_status": simulated_action.get("status"),
                "recommended_path_simulated_eligible_groups": simulated_action.get("eligible_groups"),
                "recommended_path_simulated_eligible_records": simulated_action.get("eligible_records"),
            }
            for fact in impact.get("facts") or []:
                label = re.sub(r"[^a-z0-9]+", "_", str(fact.get("label") or "").strip().lower()).strip("_")
                if label:
                    row[f"impact_{label}"] = fact.get("value")
            rows.append(row)
        return rows

    def export_project_decision_ballot_rows(self) -> list[dict[str, Any]]:
        data = self.project_decisions()
        rows: list[dict[str, Any]] = [
            {
                "row_type": "summary",
                "total_decisions": data.get("total"),
                "pending": data.get("pending"),
                "decided": data.get("decided"),
                "deferred": data.get("deferred"),
                "recommended_use": "Review each recommended path, write your intended choice, then save decisions one at a time in Status.",
                "safety": PROJECT_DECISION_SAVE_SAFETY,
                "records_to": PROJECT_DECISION_SAVE_RECORDS,
                "does_not": PROJECT_DECISION_SAVE_DOES_NOT,
                "restore_path": PROJECT_DECISION_RESTORE_PATH,
                "report": "/reports/project_decision_ballot.md",
                "export_url": "/api/export?type=project_decision_ballot",
            }
        ]
        sequence_items = data.get("sequence") or []
        for item in sequence_items:
            decision = item.get("decision") or {}
            options = decision.get("options") or []
            option_code_by_value = {
                option.get("value"): chr(ord("A") + index)
                for index, option in enumerate(options)
            }
            recommended = decision.get("recommended_option") or {}
            impact = decision.get("impact") or {}
            facts = impact.get("facts") or []
            rows.append(
                {
                    "row_type": "decision",
                    "step": item.get("step"),
                    "phase": item.get("phase"),
                    "recommended_timing": item.get("recommended_timing"),
                    "key": decision.get("key") or item.get("key"),
                    "title": decision.get("title") or item.get("key"),
                    "category": decision.get("category"),
                    "current_status": decision.get("status"),
                    "current_status_label": decision.get("status_label"),
                    "current_choice": decision.get("choice"),
                    "current_choice_code": option_code_by_value.get(decision.get("choice")),
                    "current_choice_label": decision.get("choice_label"),
                    "question": decision.get("question"),
                    "recommended_choice": decision.get("recommendation"),
                    "recommended_code": option_code_by_value.get(decision.get("recommendation")),
                    "recommended_label": recommended.get("label"),
                    "recommended_display": ". ".join(
                        part
                        for part in [
                            option_code_by_value.get(decision.get("recommendation")),
                            recommended.get("label"),
                        ]
                        if part
                    ),
                    "recommended_description": recommended.get("description"),
                    "why_now": item.get("why") or impact.get("summary"),
                    "after_save": item.get("after_save") or impact.get("next_step"),
                    "impact_readiness": impact.get("readiness"),
                    "impact_summary": impact.get("summary"),
                    "fact_summary": "; ".join(f"{fact.get('label')}: {fact.get('value')}" for fact in facts[:6]),
                    "evidence_report": decision.get("report"),
                    "worksheet_report": decision.get("worksheet_report"),
                    "worksheet_export_url": decision.get("worksheet_export_url"),
                    "view": decision.get("view"),
                    "your_status": "",
                    "your_choice": "",
                    "your_note": "",
                    "save_boundary": "Save only from Status after review; this ballot does not save anything.",
                }
            )
            for index, option in enumerate(options):
                option_code = chr(ord("A") + index)
                rows.append(
                    {
                        "row_type": "option",
                        "step": item.get("step"),
                        "key": decision.get("key") or item.get("key"),
                        "title": decision.get("title") or item.get("key"),
                        "option_code": option_code,
                        "option_value": option.get("value"),
                        "option_label": option.get("label"),
                        "option_display": f"{option_code}. {option.get('label')}",
                        "option_description": option.get("description"),
                        "recommended": "yes" if option.get("value") == decision.get("recommendation") else "",
                        "current_choice": "yes" if option.get("value") == decision.get("choice") else "",
                        "your_selection": "",
                    }
                )
        return rows

    def export_project_decision_option_matrix_rows(self) -> list[dict[str, Any]]:
        data = self.project_decisions()
        sequence_items = data.get("sequence") or []
        remaining_items = [
            item
            for item in sequence_items
            if (item.get("decision") or {}).get("status") != "decided"
        ]
        rows: list[dict[str, Any]] = [
            {
                "row_type": "summary",
                "remaining_decisions": len(remaining_items),
                "pending": data.get("pending"),
                "deferred": data.get("deferred"),
                "decided": data.get("decided"),
                "recommended_use": "Use this matrix to compare A/B/C choices before saving one Project Decision at a time in Status.",
                "safety": PROJECT_DECISION_SAVE_SAFETY,
                "report": "/reports/project_decision_option_matrix.md",
                "export_url": "/api/export?type=project_decision_option_matrix",
            }
        ]
        for item in remaining_items:
            decision = item.get("decision") or {}
            impact = decision.get("impact") or {}
            facts = impact.get("facts") or []
            recommended_value = decision.get("recommendation")
            current_value = decision.get("choice")
            option_count = len(decision.get("options") or [])
            for index, option in enumerate(decision.get("options") or []):
                option_code = chr(ord("A") + index)
                recommended = option.get("value") == recommended_value
                current = option.get("value") == current_value
                rows.append(
                    {
                        "row_type": "option",
                        "step": item.get("step"),
                        "phase": item.get("phase"),
                        "recommended_timing": item.get("recommended_timing"),
                        "decision_key": decision.get("key") or item.get("key"),
                        "decision_title": decision.get("title") or item.get("key"),
                        "category": decision.get("category"),
                        "status": decision.get("status"),
                        "status_label": decision.get("status_label"),
                        "question": decision.get("question"),
                        "option_code": option_code,
                        "option_count": option_count,
                        "option_value": option.get("value"),
                        "option_label": option.get("label"),
                        "option_display": f"{option_code}. {option.get('label')}",
                        "recommended": "yes" if recommended else "",
                        "current_choice": "yes" if current else "",
                        "choice_position": "recommended" if recommended else "alternative",
                        "tradeoff": option.get("description"),
                        "why_recommended": item.get("why") if recommended else "",
                        "after_save": item.get("after_save") or impact.get("next_step"),
                        "impact_summary": impact.get("summary"),
                        "fact_summary": "; ".join(f"{fact.get('label')}: {fact.get('value')}" for fact in facts[:6]),
                        "evidence_report": decision.get("report"),
                        "worksheet_report": decision.get("worksheet_report"),
                        "worksheet_export_url": decision.get("worksheet_export_url"),
                        "view": decision.get("view"),
                        "save_boundary": "Matrix only; save one explicit decision from Status after review.",
                    }
                )
        return rows

