    def export_archive_review_worklist_rows(self) -> list[dict[str, Any]]:
        with self.db() as conn:
            summary = self.unlinked_archive_communications_summary(conn)
            items = rows_to_dicts(
                conn.execute(
                    f"""
                    {self.archive_select_sql()}
                    WHERE ai.record_id IS NULL
                      AND ai.item_type IN ('call', 'text_message')
                    ORDER BY
                      CASE coalesce(ard.status, 'unreviewed')
                        WHEN 'unreviewed' THEN 1
                        WHEN 'needs_lookup' THEN 2
                        WHEN 'ready_to_link' THEN 3
                        WHEN 'archive_only' THEN 4
                        ELSE 5
                      END,
                      ai.occurred_at DESC,
                      ai.id DESC
                    """
                ).fetchall()
            )
        counts = {row.get("value"): row.get("count") for row in summary.get("review_status_counts") or []}
        rows: list[dict[str, Any]] = [
            {
                "row_type": "summary",
                "total": summary.get("total"),
                "unreviewed": counts.get("unreviewed", 0),
                "needs_lookup": counts.get("needs_lookup", 0),
                "ready_to_link": counts.get("ready_to_link", 0),
                "archive_only": counts.get("archive_only", 0),
                "recommendation": summary.get("recommendation"),
                "reason": summary.get("reason"),
                "report": summary.get("report"),
                "archive_url": "/api/archive?preset=unlinked_communications",
                "export_url": "/api/export?type=archive_review_worklist",
            }
        ]
        for group in summary.get("top_numbers") or []:
            rows.append(
                {
                    "row_type": "top_number",
                    "item_type": group.get("item_type"),
                    "phone_number": group.get("phone_number"),
                    "classification": group.get("classification"),
                    "item_count": group.get("count"),
                    "reviewed_count": group.get("reviewed_count"),
                    "first_at": group.get("first_at"),
                    "last_at": group.get("last_at"),
                    "archive_preset": "unlinked_communications",
                    "archive_search": group.get("phone_number"),
                }
            )
        for item in [self.format_archive_item(row) for row in items]:
            status = item.get("review_status") or "unreviewed"
            rows.append(
                {
                    "row_type": "archive_item",
                    "archive_item_id": item.get("id"),
                    "review_status": status,
                    "review_status_label": archive_review_status_label(status),
                    "review_note": item.get("review_note"),
                    "item_type": item.get("item_type"),
                    "label": item.get("label"),
                    "phone_number": item.get("phone_number"),
                    "occurred_at": item.get("occurred_at"),
                    "title": item.get("title"),
                    "body": item.get("body"),
                    "direction": item.get("direction"),
                    "duration_seconds": item.get("duration_seconds"),
                    "user_name": item.get("user_name"),
                    "source_collection": item.get("source_collection"),
                    "zendesk_record_id": item.get("zendesk_record_id"),
                    "recommended_action": self.archive_review_row_action(status),
                }
            )
        return rows

    def export_archive_review_triage_rows(self) -> list[dict[str, Any]]:
        with self.db() as conn:
            triage = self.archive_review_triage_summary(conn)
            phone_index = self.archive_phone_index(conn)
            items = rows_to_dicts(
                conn.execute(
                    """
                    SELECT ai.id, ai.item_type, ai.title, ai.body, ai.direction, ai.occurred_at,
                           ai.phone_number, ai.url, ai.status, ai.duration_seconds,
                           ai.source_collection, ai.zendesk_record_id, ai.user_id,
                           ard.status AS review_status, ard.note AS review_note
                    FROM imported_archive_items ai
                    LEFT JOIN archive_review_decisions ard ON ard.archive_item_id = ai.id
                    WHERE ai.record_id IS NULL
                      AND ai.item_type IN ('call', 'text_message')
                    ORDER BY ai.occurred_at DESC, ai.id DESC
                    """
                ).fetchall()
            )
        rows: list[dict[str, Any]] = [
            {
                "row_type": "summary",
                "title": triage.get("title"),
                "status": triage.get("status"),
                "total": triage.get("total"),
                "unreviewed": triage.get("unreviewed"),
                "report": triage.get("report"),
                "export_url": triage.get("export_url"),
                "safety": triage.get("safety"),
                "message": triage.get("message"),
                "save_boundary": "Open the Archive inspector to save an explicit review status; this export does not save anything.",
            }
        ]
        for lane in triage.get("lane_counts") or []:
            rows.append(
                {
                    "row_type": "lane_summary",
                    "triage_lane": lane.get("triage_lane"),
                    "triage_lane_label": lane.get("triage_lane_label"),
                    "count": lane.get("count"),
                    "suggested_action": lane.get("suggested_action"),
                }
            )
        for status in triage.get("suggested_status_counts") or []:
            rows.append(
                {
                    "row_type": "suggested_status_summary",
                    "suggested_status": status.get("suggested_status"),
                    "suggested_status_label": status.get("suggested_status_label"),
                    "count": status.get("count"),
                }
            )
        for index, group in enumerate(triage.get("top_groups") or [], start=1):
            rows.append(
                {
                    "row_type": "top_group",
                    "rank": index,
                    "triage_lane": group.get("triage_lane"),
                    "triage_lane_label": group.get("triage_lane_label"),
                    "suggested_status": group.get("suggested_status"),
                    "suggested_status_label": group.get("suggested_status_label"),
                    "item_type": group.get("item_type"),
                    "phone_number": group.get("phone_number"),
                    "classification": group.get("classification"),
                    "item_count": group.get("count"),
                    "reviewed_count": group.get("reviewed_count"),
                    "first_at": group.get("first_at"),
                    "last_at": group.get("last_at"),
                    "reason": group.get("reason"),
                    "signals": group.get("signals"),
                    "sample_archive_item_id": group.get("sample_archive_item_id"),
                    "sample_body": group.get("sample_body"),
                    "archive_search": group.get("phone_number"),
                    "archive_preset": "unlinked_communications",
                }
            )

        phone_counts: dict[tuple[str, str], int] = {}
        for item in items:
            key = (str(item.get("item_type") or ""), str(item.get("phone_number") or ""))
            phone_counts[key] = phone_counts.get(key, 0) + 1
        for item in items:
            phone_key = self.normalize_phone_key(item.get("phone_number"))
            matches = phone_index.get(phone_key or "", [])
            classification = self.unlinked_archive_classification(phone_key, matches)
            group_count = phone_counts.get((str(item.get("item_type") or ""), str(item.get("phone_number") or "")), 0)
            item_triage = self.archive_review_triage_for_item(item, classification, group_count)
            review_status = item.get("review_status") or "unreviewed"
            rows.append(
                {
                    "row_type": "archive_item",
                    "archive_item_id": item.get("id"),
                    "item_type": item.get("item_type"),
                    "phone_number": item.get("phone_number"),
                    "classification": classification,
                    "phone_group_count": group_count,
                    "current_review_status": review_status,
                    "current_review_status_label": archive_review_status_label(review_status),
                    "review_note": item.get("review_note"),
                    "triage_lane": item_triage.get("triage_lane"),
                    "triage_lane_label": item_triage.get("triage_lane_label"),
                    "suggested_status": item_triage.get("suggested_status"),
                    "suggested_status_label": item_triage.get("suggested_status_label"),
                    "reason": item_triage.get("reason"),
                    "signals": item_triage.get("signals"),
                    "suggested_action": item_triage.get("suggested_action"),
                    "occurred_at": item.get("occurred_at"),
                    "title": item.get("title"),
                    "body": item.get("body"),
                    "direction": item.get("direction"),
                    "duration_seconds": item.get("duration_seconds"),
                    "url": item.get("url"),
                    "source_collection": item.get("source_collection"),
                    "zendesk_record_id": item.get("zendesk_record_id"),
                    "save_boundary": "Open the Archive inspector to save an explicit review status; this export does not save anything.",
                }
            )
        return rows

