    def export_database_map_rows(self) -> list[dict[str, Any]]:
        def quote_identifier(identifier: str) -> str:
            return '"' + identifier.replace('"', '""') + '"'

        rows: list[dict[str, Any]] = []
        with self.db() as conn:
            objects = rows_to_dicts(
                conn.execute(
                    """
                    SELECT name, type, sql
                    FROM sqlite_master
                    WHERE type IN ('table', 'view')
                      AND name NOT LIKE 'sqlite_%'
                    ORDER BY type, name COLLATE NOCASE
                    """
                ).fetchall()
            )
            tables = [item for item in objects if item.get("type") == "table"]
            views = [item for item in objects if item.get("type") == "view"]
            reports = self.migration_status().get("reports") or []
            export_items = self.export_manifest().get("exports") or []
            rows.append(
                {
                    "row_type": "summary",
                    "database_path": str(self.db_path),
                    "database_bytes": self.db_path.stat().st_size if self.db_path.exists() else 0,
                    "table_count": len(tables),
                    "view_count": len(views),
                    "csv_export_count": len(export_items),
                    "report_count": len(reports),
                    "reports_ready": sum(1 for report in reports if report.get("exists")),
                    "report": "/reports/local_crm_database_map.md",
                    "export_url": "/api/export?type=database_map",
                    "safety": "Read-only database inventory; does not edit records, save decisions, link archive items, resolve cleanup, or update Zendesk Sell.",
                }
            )
            for item in objects:
                table_name = str(item.get("name") or "")
                object_type = str(item.get("type") or "")
                table_rows = None
                if object_type == "table":
                    table_rows = conn.execute(f"SELECT count(*) FROM {quote_identifier(table_name)}").fetchone()[0]
                columns = rows_to_dicts(conn.execute(f"PRAGMA table_info({quote_identifier(table_name)})").fetchall())
                foreign_keys = rows_to_dicts(conn.execute(f"PRAGMA foreign_key_list({quote_identifier(table_name)})").fetchall())
                primary_keys = [column.get("name") for column in columns if column.get("pk")]
                rows.append(
                    {
                        "row_type": "table",
                        "table_name": table_name,
                        "object_type": object_type,
                        "category": self.database_map_table_category(table_name),
                        "purpose": self.database_map_table_purpose(table_name),
                        "row_count": table_rows,
                        "column_count": len(columns),
                        "primary_key_columns": ", ".join(str(value) for value in primary_keys if value),
                        "foreign_key_count": len(foreign_keys),
                    }
                )
                for column in columns:
                    rows.append(
                        {
                            "row_type": "column",
                            "table_name": table_name,
                            "column_name": column.get("name"),
                            "data_type": column.get("type"),
                            "not_null": column.get("notnull"),
                            "primary_key": column.get("pk"),
                            "default_value": column.get("dflt_value"),
                        }
                    )
                for foreign_key in foreign_keys:
                    rows.append(
                        {
                            "row_type": "foreign_key",
                            "table_name": table_name,
                            "from_column": foreign_key.get("from"),
                            "target_table": foreign_key.get("table"),
                            "target_column": foreign_key.get("to"),
                            "on_update": foreign_key.get("on_update"),
                            "on_delete": foreign_key.get("on_delete"),
                        }
                    )
            for item in export_items:
                rows.append(
                    {
                        "row_type": "csv_export",
                        "export_type": item.get("type"),
                        "label": item.get("label"),
                        "url": item.get("url"),
                    }
                )
            for report in reports:
                rows.append(
                    {
                        "row_type": "report",
                        "report_name": report.get("name"),
                        "exists": report.get("exists"),
                        "path": report.get("path"),
                        "bytes": report.get("bytes"),
                    }
                )
        return rows

