    def hosted_database_postgres_type(self, sqlite_type: Any, column_name: str, primary_key: bool) -> tuple[str, str]:
        raw_type = str(sqlite_type or "").strip().upper()
        name = column_name.lower()
        if primary_key and "INT" in raw_type:
            return "bigint", "Preserve existing local IDs during the initial import; add identity behavior only after cutover."
        if name.endswith("_at") or name in {"occurred_at", "due_date", "completed_at", "estimated_close_date"}:
            return "timestamptz", "Normalize stored timestamp/date text into a consistent hosted timestamp format."
        if name.endswith("_json") or name in {"old_value", "new_value", "settings_json"}:
            return "jsonb", "Validate existing text as JSON before loading into hosted jsonb."
        if "INT" in raw_type:
            return "bigint", "Integer-compatible column."
        if any(token in raw_type for token in ["REAL", "FLOA", "DOUB"]):
            return "double precision", "Floating-point numeric column."
        if any(token in raw_type for token in ["NUM", "DEC"]):
            return "numeric", "Decimal/numeric column."
        if "BLOB" in raw_type:
            return "bytea", "Binary-compatible column."
        return "text", "Text column; tighten to enum/boolean/date only after staging validation if useful."

    def hosted_schema_quote_identifier(self, identifier: str) -> str:
        return '"' + str(identifier).replace('"', '""') + '"'

    def hosted_schema_safe_name(self, value: str, prefix: str = "item") -> str:
        name = re.sub(r"[^a-z0-9_]+", "_", str(value).lower()).strip("_")
        name = re.sub(r"_+", "_", name)
        if not name:
            name = prefix
        if name[0].isdigit():
            name = f"{prefix}_{name}"
        return name[:55]

    def hosted_schema_default_sql(self, default_value: Any) -> str:
        if default_value is None:
            return ""
        raw = str(default_value).strip()
        if not raw:
            return ""
        upper = raw.upper()
        if upper in {"NULL"}:
            return " DEFAULT NULL"
        if upper == "CURRENT_TIMESTAMP":
            return " DEFAULT now()"
        if upper == "CURRENT_DATE":
            return " DEFAULT current_date"
        if upper == "CURRENT_TIME":
            return " DEFAULT current_time"
        if re.fullmatch(r"-?\d+(\.\d+)?", raw):
            return f" DEFAULT {raw}"
        if raw.startswith("'") and raw.endswith("'"):
            return f" DEFAULT {raw}"
        return ""

    def hosted_schema_core_table_rows(self) -> tuple[list[dict[str, Any]], list[dict[str, Any]], list[dict[str, Any]], int, int]:
        def quote(identifier: str) -> str:
            return self.hosted_schema_quote_identifier(identifier)

        rows: list[dict[str, Any]] = []
        foreign_key_rows: list[dict[str, Any]] = []
        index_rows: list[dict[str, Any]] = []
        table_count = 0
        column_count = 0
        remote_only_tables = {definition[0] for definition in self.hosted_schema_remote_table_definitions()}
        with self.db() as conn:
            objects = rows_to_dicts(
                conn.execute(
                    """
                    SELECT name
                    FROM sqlite_master
                    WHERE type = 'table'
                      AND name NOT LIKE 'sqlite_%'
                    ORDER BY name COLLATE NOCASE
                    """
                ).fetchall()
            )
            for item in objects:
                table_name = str(item.get("name") or "")
                if table_name in remote_only_tables:
                    continue
                columns = rows_to_dicts(conn.execute(f"PRAGMA table_info({quote(table_name)})").fetchall())
                foreign_keys = rows_to_dicts(conn.execute(f"PRAGMA foreign_key_list({quote(table_name)})").fetchall())
                table_count += 1
                column_count += len(columns)
                column_lines: list[str] = []
                primary_keys: list[str] = []
                index_candidates: set[tuple[str, ...]] = set()
                column_names = {str(column.get("name") or "") for column in columns}
                for column in columns:
                    column_name = str(column.get("name") or "")
                    primary_key = bool(column.get("pk"))
                    postgres_type, note = self.hosted_database_postgres_type(column.get("type"), column_name, primary_key)
                    nullable = "" if primary_key or not column.get("notnull") else " NOT NULL"
                    default_sql = "" if primary_key else self.hosted_schema_default_sql(column.get("dflt_value"))
                    column_lines.append(f"    {quote(column_name)} {postgres_type}{nullable}{default_sql}")
                    if primary_key:
                        primary_keys.append(column_name)
                    if column_name.endswith("_id") and not primary_key:
                        index_candidates.add((column_name,))
                    if column_name.startswith("zendesk_") and column_name.endswith("_id"):
                        index_candidates.add((column_name,))
                    if column_name.endswith("_at") or column_name in {"occurred_at", "due_date", "completed_at"}:
                        index_candidates.add((column_name,))
                    rows.append(
                        {
                            "row_type": "column",
                            "table_name": table_name,
                            "column_name": column_name,
                            "sqlite_type": column.get("type") or "",
                            "postgres_type": postgres_type,
                            "primary_key": "yes" if primary_key else "no",
                            "not_null": "yes" if bool(column.get("notnull")) else "no",
                            "migration_note": note,
                        }
                    )
                if primary_keys:
                    key_sql = ", ".join(quote(key) for key in primary_keys)
                    column_lines.append(f"    PRIMARY KEY ({key_sql})")
                ddl = f"CREATE TABLE IF NOT EXISTS crm.{quote(table_name)} (\n" + ",\n".join(column_lines) + "\n);"
                rows.append(
                    {
                        "row_type": "table_ddl",
                        "table_name": table_name,
                        "category": self.database_map_table_category(table_name),
                        "purpose": self.database_map_table_purpose(table_name),
                        "sql": ddl,
                        "migration_note": "Core local CRM table translated from SQLite; review in staging before production.",
                    }
                )
                if "record_type" in column_names and "record_id" in column_names:
                    index_candidates.add(("record_type", "record_id"))
                if "created_at" in column_names:
                    index_candidates.add(("created_at",))
                if "updated_at" in column_names:
                    index_candidates.add(("updated_at",))
                for foreign_key in foreign_keys:
                    from_column = str(foreign_key.get("from") or "")
                    target_table = str(foreign_key.get("table") or "")
                    target_column = str(foreign_key.get("to") or "id")
                    if not from_column or not target_table:
                        continue
                    constraint = self.hosted_schema_safe_name(f"fk_{table_name}_{from_column}", "fk")
                    on_update = str(foreign_key.get("on_update") or "").upper()
                    on_delete = str(foreign_key.get("on_delete") or "").upper()
                    action_sql = ""
                    if on_update and on_update not in {"NO ACTION", "RESTRICT"}:
                        action_sql += f" ON UPDATE {on_update}"
                    if on_delete and on_delete not in {"NO ACTION", "RESTRICT"}:
                        action_sql += f" ON DELETE {on_delete}"
                    sql = "\n".join(
                        [
                            f"ALTER TABLE crm.{quote(table_name)} DROP CONSTRAINT IF EXISTS {quote(constraint)};",
                            (
                                f"ALTER TABLE crm.{quote(table_name)} ADD CONSTRAINT {quote(constraint)} "
                                f"FOREIGN KEY ({quote(from_column)}) REFERENCES crm.{quote(target_table)} ({quote(target_column)}){action_sql};"
                            ),
                        ]
                    )
                    foreign_key_rows.append(
                        {
                            "row_type": "foreign_key_ddl",
                            "table_name": table_name,
                            "from_column": from_column,
                            "target_table": target_table,
                            "target_column": target_column,
                            "sql": sql,
                            "migration_note": "Apply after all local CRM tables are created.",
                        }
                    )
                for columns_tuple in sorted(index_candidates):
                    index_name = self.hosted_schema_safe_name(f"idx_{table_name}_{'_'.join(columns_tuple)}", "idx")
                    columns_sql = ", ".join(quote(column) for column in columns_tuple)
                    sql = f"CREATE INDEX IF NOT EXISTS {quote(index_name)} ON crm.{quote(table_name)} ({columns_sql});"
                    index_rows.append(
                        {
                            "row_type": "index_ddl",
                            "table_name": table_name,
                            "index_name": index_name,
                            "columns": ", ".join(columns_tuple),
                            "sql": sql,
                            "migration_note": "Draft index for common relationship/filter lookups.",
                        }
                    )
        return rows, foreign_key_rows, index_rows, table_count, column_count

