    def export_hosted_database_migration_readiness_rows(self) -> list[dict[str, Any]]:
        def quote_identifier(identifier: str) -> str:
            return '"' + identifier.replace('"', '""') + '"'

        rows: list[dict[str, Any]] = []
        with self.db() as conn:
            objects = rows_to_dicts(
                conn.execute(
                    """
                    SELECT name, type, sql
                    FROM sqlite_master
                    WHERE type = 'table'
                      AND name NOT LIKE 'sqlite_%'
                    ORDER BY name COLLATE NOCASE
                    """
                ).fetchall()
            )
            table_rows: list[dict[str, Any]] = []
            column_rows: list[dict[str, Any]] = []
            foreign_key_rows: list[dict[str, Any]] = []
            total_rows = 0
            json_candidate_columns = 0
            timestamp_columns = 0
            file_path_columns = 0
            polymorphic_reference_tables: set[str] = set()
            largest_table = {"table_name": "", "row_count": 0}
            for item in objects:
                table_name = str(item.get("name") or "")
                row_count = int(conn.execute(f"SELECT count(*) FROM {quote_identifier(table_name)}").fetchone()[0])
                total_rows += row_count
                if row_count > int(largest_table.get("row_count") or 0):
                    largest_table = {"table_name": table_name, "row_count": row_count}
                columns = rows_to_dicts(conn.execute(f"PRAGMA table_info({quote_identifier(table_name)})").fetchall())
                foreign_keys = rows_to_dicts(conn.execute(f"PRAGMA foreign_key_list({quote_identifier(table_name)})").fetchall())
                category = self.database_map_table_category(table_name)
                priority = self.hosted_database_migration_priority(category)
                primary_keys = [str(column.get("name") or "") for column in columns if column.get("pk")]
                column_names = {str(column.get("name") or "") for column in columns}
                has_polymorphic_reference = "record_type" in column_names and "record_id" in column_names
                if has_polymorphic_reference:
                    polymorphic_reference_tables.add(table_name)
                table_rows.append(
                    {
                        "row_type": "table_migration",
                        "priority": priority,
                        "table_name": table_name,
                        "category": category,
                        "purpose": self.database_map_table_purpose(table_name),
                        "row_count": row_count,
                        "column_count": len(columns),
                        "primary_key_columns": ", ".join(value for value in primary_keys if value),
                        "foreign_key_count": len(foreign_keys),
                        "has_polymorphic_reference": "yes" if has_polymorphic_reference else "no",
                        "migration_note": "Load before dependent detail/history tables." if priority <= 2 else "Load after core/reference records and preserve local IDs.",
                    }
                )
                for column in columns:
                    column_name = str(column.get("name") or "")
                    sqlite_type = column.get("type") or ""
                    primary_key = bool(column.get("pk"))
                    postgres_type, note = self.hosted_database_postgres_type(sqlite_type, column_name, primary_key)
                    lower_name = column_name.lower()
                    if postgres_type == "jsonb":
                        json_candidate_columns += 1
                    if postgres_type == "timestamptz":
                        timestamp_columns += 1
                    if lower_name in {"local_file"} or lower_name.endswith("_file") or lower_name.endswith("_path"):
                        file_path_columns += 1
                    column_rows.append(
                        {
                            "row_type": "column_migration",
                            "table_name": table_name,
                            "column_name": column_name,
                            "sqlite_type": sqlite_type,
                            "postgres_type": postgres_type,
                            "not_null": column.get("notnull"),
                            "primary_key": column.get("pk"),
                            "default_value": column.get("dflt_value"),
                            "migration_note": note,
                        }
                    )
                for foreign_key in foreign_keys:
                    foreign_key_rows.append(
                        {
                            "row_type": "foreign_key",
                            "table_name": table_name,
                            "from_column": foreign_key.get("from"),
                            "target_table": foreign_key.get("table"),
                            "target_column": foreign_key.get("to"),
                            "on_update": foreign_key.get("on_update"),
                            "on_delete": foreign_key.get("on_delete"),
                        }
                    )

        rows.append(
            {
                "row_type": "summary",
                "status": "ready_for_staging_schema_design",
                "source_database": str(self.db_path),
                "target_database": "managed_postgres_recommended",
                "table_count": len(table_rows),
                "column_count": len(column_rows),
                "total_source_rows": total_rows,
                "foreign_key_count": len(foreign_key_rows),
                "largest_table": largest_table.get("table_name"),
                "largest_table_rows": largest_table.get("row_count"),
                "json_candidate_columns": json_candidate_columns,
                "timestamp_text_columns": timestamp_columns,
                "file_path_columns": file_path_columns,
                "polymorphic_reference_tables": len(polymorphic_reference_tables),
                "report": "/reports/hosted_database_migration_readiness.md",
                "export_url": "/api/export?type=hosted_database_migration_readiness",
                "safety": "Read-only schema and data-shape analysis; does not create a remote database, provision hosting, migrate data, or change CRM records.",
            }
        )
        rows.extend(sorted(table_rows, key=lambda row: (int(row.get("priority") or 99), str(row.get("table_name") or ""))))
        rows.extend(sorted(column_rows, key=lambda row: (str(row.get("table_name") or ""), str(row.get("column_name") or ""))))
        rows.extend(sorted(foreign_key_rows, key=lambda row: (str(row.get("table_name") or ""), str(row.get("from_column") or ""))))

        requirements = [
            (
                "schema_migration_script",
                "Hosted schema migration",
                "Create versioned SQL/app migrations for managed Postgres before loading production data.",
                "Required before staging load.",
            ),
            (
                "preserve_local_ids",
                "Preserve local IDs",
                "Initial remote load should preserve current local integer IDs so archive links, tasks, notes, tags, cleanup flags, and audit references remain stable.",
                "Required for count and relationship verification.",
            ),
            (
                "timestamp_normalization",
                "Normalize timestamps",
                "Convert text timestamps/date strings into a consistent hosted timestamptz/date convention during staging.",
                "Required before admin edits begin.",
            ),
            (
                "json_validation",
                "Validate JSON-like columns",
                "Validate settings_json, old_value, and new_value before choosing jsonb for remote storage.",
                "Required before strict hosted schema.",
            ),
            (
                "polymorphic_reference_checks",
                "Protect polymorphic references",
                "Tables with record_type/record_id references need application-level integrity checks because ordinary SQL foreign keys cannot cover all target tables.",
                "Required before remote editing.",
            ),
            (
                "private_file_keys",
                "Replace local file paths with private file keys",
                "Document/call file paths need private object-storage keys plus signed download handling in the hosted app.",
                "Required before remote archive downloads.",
            ),
            (
                "remote_user_identity",
                "Add remote user identity",
                "The current users table is Zendesk owner reference data; hosted admin login needs separate app-user identity and audit attribution.",
                "Required before inviting admins.",
            ),
            (
                "count_verification",
                "Run count and relationship verification",
                "Compare source SQLite row counts, key relationships, exported CSV counts, and archive file coverage after staging load.",
                "Required before production cutover.",
            ),
            (
                "rollback_package",
                "Keep rollback package",
                "Create a final local backup and complete export package immediately before production migration.",
                "Required for cutover approval.",
            ),
        ]
        for order, (key, title, detail, gate) in enumerate(requirements, start=1):
            rows.append(
                {
                    "row_type": "migration_requirement",
                    "order": order,
                    "key": key,
                    "title": title,
                    "detail": detail,
                    "gate": gate,
                }
            )
        risks = [
            (
                "sqlite_typing",
                "SQLite has permissive typing",
                "Staging should validate numeric, date, JSON, and boolean-like values before moving to stricter hosted columns.",
                "Run staged import with reject/error report.",
            ),
            (
                "local_file_paths",
                "Archive file paths are local",
                "The hosted CRM should not point admins at this machine; file references must become private storage keys.",
                "Migrate files and verify signed downloads.",
            ),
            (
                "app_user_audit",
                "Current audit lacks remote app-user attribution",
                "Remote edits need actor identity in addition to the existing local audit event detail.",
                "Add app_user_id or equivalent to future audit writes.",
            ),
            (
                "multi_user_writes",
                "Local app was not designed as a multi-user deployment surface",
                "Remote rollout needs hosted request/auth/session handling, concurrency expectations, and backup discipline.",
                "Use staging smoke tests before inviting admins.",
            ),
        ]
        for order, (key, title, detail, mitigation) in enumerate(risks, start=1):
            rows.append(
                {
                    "row_type": "risk",
                    "order": order,
                    "key": key,
                    "title": title,
                    "detail": detail,
                    "mitigation": mitigation,
                }
            )
        return rows

