            ("AUTH_BOOTSTRAP_ADMIN_EMAIL", "runtime", "partially", "yes", "Owner-approved first admin email.", "Used only for staging seed or first login setup."),
            ("STORAGE_BACKEND", "runtime", "no", "yes", "s3_compatible.", "Switches local file paths to object storage metadata."),
            ("S3_BUCKET", "runtime", "no", "yes", "Provider bucket name.", "Private document object storage."),
            ("S3_ENDPOINT_URL", "runtime", "no", "yes", "DigitalOcean Spaces or Railway bucket endpoint.", "S3-compatible storage endpoint."),
            ("S3_REGION", "runtime", "no", "yes", "Provider region value.", "Bucket client configuration."),
            ("S3_ACCESS_KEY_ID", "runtime", "yes", "yes", "Provider-generated access key.", "Private bucket access."),
            ("S3_SECRET_ACCESS_KEY", "runtime", "yes", "yes", "Provider-generated secret key.", "Private bucket access."),
            ("DOCUMENT_FILE_ACCESS_ENABLED", "runtime", "no", "yes", "false until private storage access is validated.", "Blocks local filesystem document serving during hosted staging."),
