            ("validation_passed", "Production validation passed", "Confirm production counts, files, permissions, audit, and backup checks passed.", "before_handoff", "Migration Operator"),
            ("remote_ready", "Remote CRM ready", "Share hosted URL/login guidance with the owner and any approved internal users, and clarify that remote CRM is now source of truth.", "handoff", "Owner"),
            ("rollback_notice", "Rollback notice", "If a P0 appears, stop using remote and return to local source-of-truth plan.", "rollback_only", "Owner"),
