    def export_lead_person_overlap_spot_check_rows(self) -> list[dict[str, Any]]:
        def compact(value: Any, limit: int = 160) -> str:
            text = " ".join(str(value if value is not None else "").split())
            if len(text) <= limit:
                return text
            return text[: limit - 3].rstrip() + "..."

        def join_unique(values: list[Any], limit: int | None = None) -> str:
            seen: set[str] = set()
            output: list[str] = []
            for value in values:
                text = " ".join(str(value if value is not None else "").split())
                if not text or text in seen:
                    continue
                seen.add(text)
                output.append(text)
                if limit and len(output) >= limit:
                    break
            return " | ".join(output)

        def record_label(record: dict[str, Any]) -> str:
            label = f"{str(record.get('record_type') or 'record').title()} #{record.get('source_id')}: {record.get('name') or '(blank name)'}"
            if record.get("email"):
                label += f" <{record['email']}>"
            phone = record.get("phone") or record.get("mobile")
            if phone:
                label += f" {phone}"
            badges = record.get("badges") or []
            if badges:
                label += f" [{', '.join(str(badge) for badge in badges)}]"
            return compact(label, 220)

        def profile_label(record: dict[str, Any]) -> str:
            profile = record.get("profile_summary") or []
            if not profile:
                return ""
            fields = "; ".join(
                f"{item.get('field_name')}: {compact(item.get('field_value'), 64)}"
                for item in profile
            )
            return compact(f"{str(record.get('record_type') or 'record').title()} #{record.get('source_id')}: {fields}", 260)

        def conflict_label(conflict: dict[str, Any]) -> str:
            alternatives = conflict.get("alternatives") or []
            alternative_text = "; ".join(
                f"{alt.get('record_name') or alt.get('record_key')}: {compact(alt.get('value'), 56)}"
                for alt in alternatives
            )
            return f"{conflict.get('field_name')}: keeper '{compact(conflict.get('keeper_value'), 56)}' vs {alternative_text}"

        def fill_label(suggestion: dict[str, Any]) -> str:
            return (
                f"{suggestion.get('field_name')}: fill from "
                f"{suggestion.get('from_record_name') or suggestion.get('from_record_key')} "
                f"with '{compact(suggestion.get('value'), 56)}'"
            )

        def history_label(item: dict[str, Any]) -> str:
            signals = item.get("signals") or []
            signal_text = ", ".join(f"{signal.get('count')} {signal.get('label')}" for signal in signals)
            return f"{item.get('record_name') or item.get('record_key')}: {signal_text}"

        decision_data = self.project_decisions()
        decision = next(
            (item for item in decision_data.get("decisions", []) if item.get("key") == "lead_person_overlap_policy"),
            {},
        )
        definition = next(item for item in PROJECT_DECISIONS if item["key"] == "lead_person_overlap_policy")
        groups = self.export_cleanup_group_rows(
            {
                "type": ["lead_person_overlap"],
                "status": ["open"],
                "policy_lane": ["policy_review_overlap"],
                "sort": ["policy"],
            }
        )["rows"]
        priority_counts = {"High": 0, "Medium": 0, "Low": 0}
        for group in groups:
            priority = str(group.get("priority") or "Low")
            if priority in priority_counts:
                priority_counts[priority] += 1

        rows: list[dict[str, Any]] = [
            {
                "row_type": "summary",
                "decision_key": "lead_person_overlap_policy",
                "decision_status": decision.get("status") or "pending",
                "current_choice": decision.get("choice") or "",
                "current_choice_label": decision.get("choice_label") or "No saved path",
                "recommendation": "Person keeper, preserve lead history",
                "why": "Use the person as the ongoing client record while preserving lead/application details as history until each overlap group is reviewed.",
                "open_groups": len(groups),
                "high_priority_groups": priority_counts["High"],
                "medium_priority_groups": priority_counts["Medium"],
                "low_priority_groups": priority_counts["Low"],
                "record_count": sum(int(group.get("record_count") or 0) for group in groups),
                "people_count": sum(int(group.get("people_count") or 0) for group in groups),
                "lead_count": sum(int(group.get("lead_count") or 0) for group in groups),
                "person_keeper_drafts": sum(1 for group in groups if group.get("draft_keeper_type") == "person"),
                "blank_field_suggestions": sum(int(group.get("draft_blank_field_suggestions") or 0) for group in groups),
                "manual_review_fields": sum(int(group.get("draft_manual_review_fields") or 0) for group in groups),
                "history_records": sum(int(group.get("draft_history_records") or 0) for group in groups),
                "history_signals": sum(int(group.get("draft_history_signals") or 0) for group in groups),
                "report": "/reports/lead_person_overlap_spot_check.md",
                "export_url": "/api/export?type=lead_person_overlap_spot_check",
                "cleanup_export_url": "/api/export_cleanup_groups?type=lead_person_overlap&status=open&policy_lane=policy_review_overlap&sort=policy",
                "safety": "Read-only spot check; does not save the project decision, merge, delete, resolve cleanup, or rewrite CRM records.",
            }
        ]

        for index, option in enumerate(definition["options"]):
            code = chr(ord("A") + index)
            rows.append(
                {
                    "row_type": "option",
                    "decision_key": definition["key"],
                    "option_code": code,
                    "option_value": option["value"],
                    "option_label": option["label"],
                    "option_display": f"{code}. {option['label']}",
                    "recommended": "yes" if option["value"] == definition["recommendation"] else "",
                    "description": option["description"],
                    "tradeoff": (
                        "Creates a default keeper rule for reviewed overlap groups while retaining lead/application context."
                        if option["value"] == "person_keeper_preserve_lead_history"
                        else "Keeps overlaps visible as separate records unless a group is manually approved."
                        if option["value"] == "keep_lead_and_person_separate"
                        else "Avoids a default rule, but every overlap group needs its own keeper decision."
                    ),
                    "after_save": "Overlap groups can move into group-level review; no merge executes from saving this policy.",
                    "save_boundary": "Saving happens only from Status and creates a local backup first.",
                }
            )

        for group in groups:
            detail = self.cleanup_groups(
                {
                    "type": ["lead_person_overlap"],
                    "status": ["open"],
                    "key": [str(group.get("group_key") or "")],
                }
            )
            draft = detail.get("merge_draft") or {}
            draft_summary = self.cleanup_merge_draft_summary(draft) or {}
            keeper = draft.get("keeper") or {}
            guidance = detail.get("guidance") or {}
            records = detail.get("records") or []
            rows.append(
                {
                    "row_type": "group",
                    "decision_key": "lead_person_overlap_policy",
                    "group_type": "lead_person_overlap",
                    "group_key": group.get("group_key"),
                    "group_label": group.get("group_label"),
                    "priority": group.get("priority"),
                    "review_score": group.get("review_score"),
                    "record_count": group.get("record_count"),
                    "people_count": group.get("people_count"),
                    "lead_count": group.get("lead_count"),
                    "draft_keeper": keeper.get("record_name") or group.get("draft_keeper"),
                    "draft_keeper_type": keeper.get("record_type") or group.get("draft_keeper_type"),
                    "draft_keeper_id": keeper.get("record_id") or group.get("draft_keeper_id"),
                    "draft_keeper_score": keeper.get("completeness_score") or group.get("draft_keeper_score"),
                    "keeper_reason": keeper.get("reason"),
                    "blank_field_suggestions": draft_summary.get("fill_suggestion_count"),
                    "manual_review_fields": draft_summary.get("conflict_count"),
                    "history_records": draft_summary.get("preserve_record_count"),
                    "history_signals": draft_summary.get("preserve_signal_count"),
                    "record_summary": join_unique([record_label(record) for record in records], limit=6),
                    "profile_summary": join_unique([profile_label(record) for record in records if profile_label(record)], limit=5),
                    "conflict_summary": join_unique([conflict_label(conflict) for conflict in draft.get("conflicts") or []], limit=8),
                    "fill_summary": join_unique([fill_label(suggestion) for suggestion in draft.get("fill_suggestions") or []], limit=8),
                    "history_summary": join_unique([history_label(item) for item in draft.get("preserve_signals") or []], limit=8),
                    "warnings": join_unique(draft.get("warnings") or []),
                    "guidance_reasons": join_unique(guidance.get("reasons") or []),
                    "recommended_review_action": "Use the person as the draft keeper only after reviewing conflicts and preserving lead/application history.",
                    "decision": group.get("decision"),
                    "decision_label": group.get("decision_label"),
                    "first_seen": group.get("first_seen"),
                    "last_seen": group.get("last_seen"),
                }
            )
        return rows

    def export_cleanup_policy_spot_check_rows(
        self,
        decision_key: str,
        group_type: str,
        report_name: str,
        export_type: str,
    ) -> list[dict[str, Any]]:
        definition = next(item for item in PROJECT_DECISIONS if item["key"] == decision_key)
        decision_data = self.project_decisions()
        decision = next((item for item in decision_data.get("decisions", []) if item.get("key") == decision_key), {})
        groups = self.export_cleanup_group_rows({"type": [group_type], "status": ["open"], "sort": ["policy"]})["rows"]
        priority_counts = {"High": 0, "Medium": 0, "Low": 0}
        for group in groups:
            priority = str(group.get("priority") or "Low")
            if priority in priority_counts:
                priority_counts[priority] += 1
        queue_label = "Duplicate People" if group_type == "duplicate_people" else "Duplicate Leads"
        rows: list[dict[str, Any]] = [
            {
                "row_type": "summary",
                "decision_key": decision_key,
                "group_type": group_type,
                "queue_label": queue_label,
                "decision_status": decision.get("status") or "pending",
                "current_choice": decision.get("choice") or "",
                "current_choice_label": decision.get("choice_label") or "No saved path",
                "recommendation": (decision.get("recommended_option") or {}).get("label") or "Guided review, then merge",
                "why": (decision.get("impact") or {}).get("summary") or definition.get("question"),
                "open_groups": len(groups),
                "high_priority_groups": priority_counts["High"],
                "medium_priority_groups": priority_counts["Medium"],
                "low_priority_groups": priority_counts["Low"],
                "record_count": sum(int(group.get("record_count") or 0) for group in groups),
                "person_count": sum(int(group.get("people_count") or 0) for group in groups),
                "lead_count": sum(int(group.get("lead_count") or 0) for group in groups),
                "blank_field_suggestions": sum(int(group.get("draft_blank_field_suggestions") or 0) for group in groups),
                "manual_review_fields": sum(int(group.get("draft_manual_review_fields") or 0) for group in groups),
                "history_records": sum(int(group.get("draft_history_records") or 0) for group in groups),
                "history_signals": sum(int(group.get("draft_history_signals") or 0) for group in groups),
                "report": f"/reports/{report_name}",
                "export_url": f"/api/export?type={export_type}",
                "cleanup_export_url": f"/api/export_cleanup_groups?type={group_type}&status=open&sort=policy",
                "safety": "Read-only policy spot check; does not save the project decision, merge, delete, resolve cleanup, or rewrite CRM records.",
            }
        ]
        for index, option in enumerate(definition["options"]):
            code = chr(ord("A") + index)
            rows.append(
                {
                    "row_type": "option",
                    "decision_key": decision_key,
                    "group_type": group_type,
                    "option_code": code,
                    "option_value": option["value"],
                    "option_label": option["label"],
                    "option_display": f"{code}. {option['label']}",
                    "recommended": "yes" if option["value"] == definition["recommendation"] else "",
                    "description": option["description"],
                    "tradeoff": (
                        "Creates a reusable guided-review path, but every group still needs human review before future merge eligibility."
                        if option["value"] == "guided_review_then_merge"
                        else "Keeps execution conservative and pushes more decision work into individual groups."
                    ),
                    "after_save": (
                        "Reviewed duplicate-person groups can be marked Merge Later or kept separate without executing merges."
                        if group_type == "duplicate_people"
                        else "Reviewed duplicate-lead groups can be marked Merge Later or preserved separately."
                    ),
                    "save_boundary": "Saving happens only from Status and creates a local backup first.",
                }
            )
        for group in groups:
            rows.append(
                {
                    "row_type": "group",
                    "decision_key": decision_key,
                    "group_type": group_type,
                    "group_key": group.get("group_key"),
                    "group_label": group.get("group_label"),
                    "priority": group.get("priority"),
                    "review_score": group.get("review_score"),
                    "record_count": group.get("record_count"),
                    "person_count": group.get("people_count"),
                    "lead_count": group.get("lead_count"),
                    "draft_keeper": group.get("draft_keeper"),
                    "draft_keeper_type": group.get("draft_keeper_type"),
                    "draft_keeper_id": group.get("draft_keeper_id"),
                    "draft_keeper_score": group.get("draft_keeper_score"),
                    "blank_field_suggestions": group.get("draft_blank_field_suggestions"),
                    "manual_review_fields": group.get("draft_manual_review_fields"),
                    "history_records": group.get("draft_history_records"),
                    "history_signals": group.get("draft_history_signals"),
                    "sample_names": group.get("sample_names"),
                    "policy_lane": group.get("policy_lane"),
                    "policy_lane_label": group.get("policy_lane_label"),
                    "policy_action": group.get("policy_action"),
                    "policy_reason": group.get("policy_reason"),
                    "headline": group.get("headline"),
                    "reasons": group.get("reasons"),
                    "decision": group.get("decision"),
                    "decision_label": group.get("decision_label"),
                    "first_seen": group.get("first_seen"),
                    "last_seen": group.get("last_seen"),
                }
            )
        return rows

