    def export_cleanup_group_rows(self, params: dict[str, list[str]]) -> dict[str, Any]:
        export_params = {key: list(value) for key, value in params.items() if key not in {"page", "page_size", "key"}}
        page = 1
        rows: list[dict[str, Any]] = []
        while True:
            export_params["page"] = [str(page)]
            export_params["page_size"] = ["50"]
            page_data = self.cleanup_groups(export_params)
            groups = page_data.get("groups", [])
            rows.extend(self.export_cleanup_group_record(group, page_data) for group in groups)
            if len(rows) >= page_data.get("total", 0) or not groups:
                break
            page += 1
        group_type = (export_params.get("type", ["duplicate_people"])[0] or "duplicate_people").lower()
        return {"filename": f"local_crm_cleanup_{group_type}_groups.csv", "rows": rows}

    def export_cleanup_group_record(self, group: dict[str, Any], page_data: dict[str, Any]) -> dict[str, Any]:
        guidance = group.get("guidance") or {}
        merge_summary = group.get("merge_draft_summary") or {}
        decision = group.get("decision") or {}
        policy_lane = group.get("policy_lane") or {}
        return {
            "group_type": page_data.get("type"),
            "status": page_data.get("status"),
            "priority_filter": page_data.get("priority"),
            "policy_lane_filter": page_data.get("policy_lane"),
            "decision_filter": page_data.get("decision"),
            "sort": page_data.get("sort"),
            "group_key": group.get("group_key"),
            "group_label": group.get("display_name") or group.get("group_key"),
            "decision": decision.get("decision"),
            "decision_label": CLEANUP_GROUP_DECISIONS.get(decision.get("decision"), ""),
            "decision_note": decision.get("note"),
            "decision_updated_at": decision.get("updated_at"),
            "priority": guidance.get("priority"),
            "review_score": guidance.get("score"),
            "flag_count": group.get("open_flags"),
            "record_count": group.get("record_count"),
            "people_count": group.get("people_count"),
            "company_count": group.get("company_count"),
            "lead_count": group.get("lead_count"),
            "deal_count": group.get("deal_count"),
            "definition_count": group.get("definition_count"),
            "resource_types": group.get("resource_types"),
            "sample_names": group.get("sample_names"),
            "draft_keeper": merge_summary.get("keeper_name"),
            "draft_keeper_type": merge_summary.get("keeper_record_type"),
            "draft_keeper_id": merge_summary.get("keeper_record_id"),
            "draft_keeper_score": merge_summary.get("keeper_score"),
            "draft_blank_field_suggestions": merge_summary.get("fill_suggestion_count"),
            "draft_manual_review_fields": merge_summary.get("conflict_count"),
            "draft_history_records": merge_summary.get("preserve_record_count"),
            "draft_history_signals": merge_summary.get("preserve_signal_count"),
            "policy_lane": policy_lane.get("lane"),
            "policy_lane_label": policy_lane.get("label"),
            "policy_action": policy_lane.get("action"),
            "policy_reason": policy_lane.get("reason"),
            "headline": guidance.get("headline"),
            "reasons": " | ".join(guidance.get("reasons") or []),
            "first_seen": group.get("first_seen"),
            "last_seen": group.get("last_seen"),
        }

    def export_cleanup_merge_draft_rows(self, status: str = "open") -> list[dict[str, Any]]:
        if status not in {"open", "ignored", "resolved"}:
            status = "open"
        rows: list[dict[str, Any]] = []
        for group_type in ["duplicate_people", "duplicate_leads", "lead_person_overlap"]:
            page = 1
            while True:
                page_data = self.cleanup_groups(
                    {"type": [group_type], "status": [status], "sort": ["priority"], "page": [str(page)], "page_size": ["50"]}
                )
                groups = page_data.get("groups", [])
                for group in groups:
                    detail = self.cleanup_groups({"type": [group_type], "status": [status], "key": [group["group_key"]]})
                    rows.extend(self.export_cleanup_merge_draft_detail_rows(detail))
                if page * page_data.get("page_size", 50) >= page_data.get("total", 0) or not groups:
                    break
                page += 1
        return rows

    def export_cleanup_merge_draft_detail_rows(self, detail: dict[str, Any]) -> list[dict[str, Any]]:
        draft = detail.get("merge_draft")
        if not draft:
            return []
        guidance = detail.get("guidance") or {}
        keeper = draft.get("keeper") or {}
        summary = self.cleanup_merge_draft_summary(draft) or {}
        base = {
            "group_type": detail.get("type"),
            "status": detail.get("status"),
            "group_key": detail.get("group_key"),
            "priority": guidance.get("priority"),
            "review_score": guidance.get("score"),
            "record_count": (detail.get("counts") or {}).get("record_count"),
            "flag_count": len(detail.get("flags") or []),
            "keeper_record_key": keeper.get("record_key"),
            "keeper_record_type": keeper.get("record_type"),
            "keeper_record_id": keeper.get("record_id"),
            "keeper_name": keeper.get("record_name"),
            "keeper_score": keeper.get("completeness_score"),
            "keeper_reason": keeper.get("reason"),
        }
        rows = [
            {
                **base,
                "row_type": "draft_summary",
                "fill_suggestion_count": summary.get("fill_suggestion_count"),
                "manual_review_field_count": summary.get("conflict_count"),
                "history_record_count": summary.get("preserve_record_count"),
                "history_signal_count": summary.get("preserve_signal_count"),
                "warning_count": summary.get("warning_count"),
            }
        ]
        for suggestion in draft.get("fill_suggestions") or []:
            rows.append(
                {
                    **base,
                    "row_type": "blank_field_suggestion",
                    "field_name": suggestion.get("field_name"),
                    "suggested_value": suggestion.get("value"),
                    "source_record_key": suggestion.get("from_record_key"),
                    "source_record_name": suggestion.get("from_record_name"),
                }
            )
        for conflict in draft.get("conflicts") or []:
            for alternative in conflict.get("alternatives") or []:
                rows.append(
                    {
                        **base,
                        "row_type": "manual_review_field",
                        "field_name": conflict.get("field_name"),
                        "keeper_value": conflict.get("keeper_value"),
                        "alternative_value": alternative.get("value"),
                        "source_record_key": alternative.get("record_key"),
                        "source_record_name": alternative.get("record_name"),
                    }
                )
        for item in draft.get("preserve_signals") or []:
            signals = item.get("signals") or []
            rows.append(
                {
                    **base,
                    "row_type": "history_to_preserve",
                    "source_record_key": item.get("record_key"),
                    "source_record_name": item.get("record_name"),
                    "history_signals": " | ".join(f"{signal.get('count')} {signal.get('label')}" for signal in signals),
                }
            )
        for warning in draft.get("warnings") or []:
            rows.append({**base, "row_type": "warning", "warning": warning})
        return rows

    def export_application_profile_rows(self) -> list[dict[str, Any]]:
        rows: list[dict[str, Any]] = []
        with self.db() as conn:
            record_rows = rows_to_dicts(
                conn.execute(
                    """
                    SELECT 'lead' AS record_type, id AS record_id, name, email, phone, mobile,
                           organization_name AS organization, status, created_at, updated_at
                    FROM leads
                    UNION ALL
                    SELECT 'person' AS record_type, id AS record_id, name, email, phone, mobile,
                           NULL AS organization, title AS status, created_at, updated_at
                    FROM people
                    ORDER BY record_type, name COLLATE NOCASE
                    """
                ).fetchall()
            )
            values = rows_to_dicts(
                conn.execute(
                    """
                    SELECT record_type, record_id, field_name, field_value
                    FROM custom_field_values
                    WHERE record_type IN ('lead', 'person')
                      AND field_name IN ({})
                    """.format(",".join("?" for _ in APPLICATION_PROFILE_FIELDS)),
                    APPLICATION_PROFILE_FIELDS,
                ).fetchall()
            )
        by_record: dict[tuple[str, int], dict[str, Any]] = {}
        for value in values:
            by_record.setdefault((value["record_type"], value["record_id"]), {})[value["field_name"]] = value["field_value"]
        for record in record_rows:
            profile = by_record.get((record["record_type"], record["record_id"]), {})
            if not profile:
                continue
            row = dict(record)
            for field_name in APPLICATION_PROFILE_FIELDS:
                row[field_name] = profile.get(field_name)
            rows.append(row)
        return rows

    def export_address_rows(self) -> list[dict[str, Any]]:
        rows: list[dict[str, Any]] = []
        record_queries = [
            ("person", "SELECT id, name, source_json FROM people ORDER BY name COLLATE NOCASE"),
            ("company", "SELECT id, name, source_json FROM companies ORDER BY name COLLATE NOCASE"),
            ("lead", "SELECT id, name, source_json FROM leads ORDER BY name COLLATE NOCASE"),
        ]
        with self.db() as conn:
            for record_type, query in record_queries:
                include_secondary = record_type in {"person", "company"}
                for record in rows_to_dicts(conn.execute(query).fetchall()):
                    address_info = self.addresses_for_record(conn, record_type, record, include_secondary)
                    for address in address_info["addresses"]:
                        if not address.get("has_values") and not address.get("has_local"):
                            continue
                        rows.append(
                            {
                                "record_type": record_type,
                                "record_id": record["id"],
                                "record_name": record["name"],
                                "address_key": address["address_key"],
                                "label": address["label"],
                                "line1": address["line1"],
                                "line2": address["line2"],
                                "city": address["city"],
                                "state": address["state"],
                                "postal_code": address["postal_code"],
                                "country": address["country"],
                                "source": address["source"],
                            }
                        )
        return rows

    def collect_linked_resource_rows(self) -> list[dict[str, Any]]:
        rows: list[dict[str, Any]] = []
        with self.db() as conn:
            custom_field_rows = rows_to_dicts(
                conn.execute(
                    """
                    SELECT cf.record_type, cf.record_id,
                           CASE
                             WHEN cf.record_type = 'person' THEN p.name
                             WHEN cf.record_type = 'company' THEN c.name
                             WHEN cf.record_type = 'lead' THEN l.name
                             WHEN cf.record_type = 'deal' THEN d.name
                             ELSE NULL
                           END AS record_name,
                           cf.field_name, cf.field_value
                    FROM custom_field_values cf
                    LEFT JOIN people p ON cf.record_type = 'person' AND p.id = cf.record_id
                    LEFT JOIN companies c ON cf.record_type = 'company' AND c.id = cf.record_id
                    LEFT JOIN leads l ON cf.record_type = 'lead' AND l.id = cf.record_id
                    LEFT JOIN deals d ON cf.record_type = 'deal' AND d.id = cf.record_id
                    WHERE cf.field_value LIKE '%http%'
                    """
                ).fetchall()
            )
            for row in custom_field_rows:
                value = row.get("field_value") or ""
                for url in self.extract_urls(value):
                    rows.append(
                        {
                            "record_type": row.get("record_type"),
                            "record_id": row.get("record_id"),
                            "record_name": row.get("record_name"),
                            "kind": self.linked_resource_kind(row.get("field_name") or "", url),
                            "source_type": "custom_field",
                            "source_label": row.get("field_name") or "Custom Field",
                            "url": url,
                            "context": self.link_context(value, url),
                            "created_at": None,
                            "updated_at": None,
                        }
                    )
            note_rows = rows_to_dicts(
                conn.execute(
                    """
                    SELECT n.id, n.record_type, n.record_id,
                           CASE
                             WHEN n.record_type = 'person' THEN p.name
                             WHEN n.record_type = 'company' THEN c.name
                             WHEN n.record_type = 'lead' THEN l.name
                             WHEN n.record_type = 'deal' THEN d.name
                             ELSE NULL
                           END AS record_name,
                           n.content, n.created_at, n.updated_at
                    FROM notes n
                    LEFT JOIN people p ON n.record_type = 'person' AND p.id = n.record_id
                    LEFT JOIN companies c ON n.record_type = 'company' AND c.id = n.record_id
                    LEFT JOIN leads l ON n.record_type = 'lead' AND l.id = n.record_id
                    LEFT JOIN deals d ON n.record_type = 'deal' AND d.id = n.record_id
                    WHERE n.content LIKE '%http%'
                    """
                ).fetchall()
            )
            for row in note_rows:
                value = row.get("content") or ""
                for url in self.extract_urls(value):
                    rows.append(
                        {
                            "record_type": row.get("record_type"),
                            "record_id": row.get("record_id"),
                            "record_name": row.get("record_name"),
                            "kind": self.linked_resource_kind("note", url),
                            "source_type": "note",
                            "source_label": f"Note #{row['id']}",
                            "url": url,
                            "context": self.link_context(value, url),
                            "created_at": row.get("created_at"),
                            "updated_at": row.get("updated_at"),
                        }
                    )
        return rows

    def export_linked_resource_rows(self, params: dict[str, list[str]] | None = None) -> list[dict[str, Any]]:
        rows = self.collect_linked_resource_rows()
        return self.filter_linked_resource_rows(rows, params or {})["rows"]

    def export_imported_archive_rows(self, params: dict[str, list[str]] | None = None) -> list[dict[str, Any]]:
        params = params or {}
        q = (params.get("q", [""])[0] or "").strip()
        item_type = (params.get("item_type", [""])[0] or "").strip()
        record_type = (params.get("record_type", [""])[0] or "").strip()
        preset = (params.get("preset", [""])[0] or "").strip()
        review_status = (params.get("review_status", [""])[0] or "").strip()
        if review_status not in {"", "unreviewed", *ARCHIVE_REVIEW_STATUS_LABELS.keys()}:
            review_status = ""
        triage_lane = self.clean_archive_triage_lane(params.get("triage_lane", [""])[0])
        if triage_lane:
            preset = "unlinked_communications"
            item_type = ""
            record_type = ""
        date_from = self.clean_activity_date_filter(params.get("date_from", [""])[0])
        date_to = self.clean_activity_date_filter(params.get("date_to", [""])[0])
        clauses, values = self.archive_filter_clauses(q, item_type, record_type, preset, date_from, date_to, review_status)
        where = f"WHERE {' AND '.join(clauses)}" if clauses else ""
        with self.db() as conn:
            rows = rows_to_dicts(
                conn.execute(
                    f"""
                    {self.archive_select_sql()}
                    {where}
                    ORDER BY ai.occurred_at DESC, ai.id DESC
                    """,
                    values,
                ).fetchall()
            )
            if triage_lane:
                rows = [
                    row
                    for row in self.enrich_archive_triage_rows(conn, rows)
                    if row.get("triage_lane") == triage_lane
                ]
        return [self.export_archive_record(self.format_archive_item(row)) for row in rows]

