    def duplicate_tag_decision_summary(self, recommended_execution_preview: dict[str, Any] | None = None) -> dict[str, Any]:
        rows = self.export_cleanup_group_rows({"type": ["duplicate_tags"], "status": ["open"], "sort": ["policy"]})["rows"]
        priority_counts = {"High": 0, "Medium": 0, "Low": 0}
        for row in rows:
            priority = str(row.get("priority") or "Low")
            if priority in priority_counts:
                priority_counts[priority] += 1
        csv_path = REPORTS_DIR / "duplicate_tag_spot_check.csv"
        exact_alias_groups = 0
        cross_resource_same_alias_groups = 0
        alias_drift_groups = 0
        if csv_path.exists():
            with csv_path.open(newline="", encoding="utf-8") as handle:
                for row in csv.DictReader(handle):
                    note = str(row.get("spot_check_note") or "")
                    if "Aliases match exactly in one resource type" in note:
                        exact_alias_groups += 1
                    elif "Same alias text appears across multiple Zendesk resource types" in note:
                        cross_resource_same_alias_groups += 1
                    else:
                        alias_drift_groups += 1
        recommended_execution_preview = recommended_execution_preview or self.recommended_cleanup_execution_preview()
        simulated_action = next(
            (
                action
                for action in recommended_execution_preview.get("actions", [])
                if action.get("action_type") == "mark_duplicate_tags_handled"
            ),
            {},
        )
        return {
            "recommendation": "Mark normalized tags handled",
            "reason": "Duplicate Zendesk tag definitions are already normalized into single local tags while assignments are preserved.",
            "open_groups": len(rows),
            "affected_assignments": sum(int(row.get("record_count") or 0) for row in rows),
            "definition_count": sum(int(row.get("definition_count") or 0) for row in rows),
            "priority_counts": priority_counts,
            "exact_alias_groups": exact_alias_groups,
            "cross_resource_same_alias_groups": cross_resource_same_alias_groups,
            "alias_drift_groups": alias_drift_groups,
            "recommended_simulated_status": simulated_action.get("status") or "",
            "recommended_simulated_groups": int(simulated_action.get("eligible_groups") or 0),
            "recommended_simulated_records": int(simulated_action.get("eligible_records") or 0),
            "report": "/reports/duplicate_tag_spot_check.md",
            "csv": "/reports/duplicate_tag_spot_check.csv",
            "export_url": "/api/export_cleanup_groups?type=duplicate_tags&status=open&policy_lane=tag_batch_candidate&sort=policy",
        }

    def guided_cleanup_review_queue(self) -> dict[str, Any]:
        queue_defs = [
            {
                "group_type": "lead_person_overlap",
                "label": "Lead/Person Overlap",
                "short_label": "Overlaps",
                "policy_lane": "policy_review_overlap",
                "decision_key": "lead_person_overlap_policy",
                "reason": "Review these first because they decide whether a client should live as a person record while lead/application history is preserved.",
            },
            {
                "group_type": "duplicate_people",
                "label": "Duplicate People",
                "short_label": "People",
                "policy_lane": "",
                "decision_key": "duplicate_people_merge_policy",
                "reason": "Review high-priority duplicate people next, using the draft keeper and history signals as decision aids.",
                "worksheet_report": "/reports/duplicate_people_review_worksheet.md",
                "worksheet_export_url": "/api/export?type=duplicate_people_review_worksheet",
            },
            {
                "group_type": "duplicate_leads",
                "label": "Duplicate Leads",
                "short_label": "Leads",
                "policy_lane": "",
                "decision_key": "duplicate_leads_merge_policy",
                "reason": "Review duplicate leads after overlap and people policy work because same-email leads may represent separate funnel history.",
                "worksheet_report": "/reports/duplicate_leads_review_worksheet.md",
                "worksheet_export_url": "/api/export?type=duplicate_leads_review_worksheet",
            },
        ]
        decision_keys = {item["decision_key"] for item in queue_defs}
        project_decisions = {
            item["key"]: item
            for item in self.project_decisions().get("decisions", [])
            if item.get("key") in decision_keys
        }
        queues = []
        totals = {
            "open_groups": 0,
            "review_remaining": 0,
            "concrete_decisions": 0,
            "merge_later": 0,
            "keep_separate": 0,
            "already_handled": 0,
            "false_positive": 0,
            "needs_review": 0,
            "no_decision": 0,
            "high_remaining": 0,
            "manual_review_fields": 0,
            "history_signals": 0,
        }
        for definition in queue_defs:
            rows = self.export_cleanup_group_rows(
                {"type": [definition["group_type"]], "status": ["open"], "sort": ["policy"]}
            )["rows"]
            decision_counts = {key: 0 for key in CLEANUP_GROUP_DECISIONS}
            decision_counts["no_decision"] = 0
            for row in rows:
                decision = str(row.get("decision") or "")
                if decision in CLEANUP_GROUP_DECISIONS:
                    decision_counts[decision] += 1
                else:
                    decision_counts["no_decision"] += 1
            remaining_rows = [
                row
                for row in rows
                if not row.get("decision") or str(row.get("decision")) == "needs_review"
            ]
            next_group = remaining_rows[0] if remaining_rows else (rows[0] if rows else {})
            review_remaining = len(remaining_rows)
            concrete_decisions = len(rows) - review_remaining
            queue = {
                **definition,
                "project_decision_status": (project_decisions.get(definition["decision_key"]) or {}).get("status") or "pending",
                "project_decision_choice": (project_decisions.get(definition["decision_key"]) or {}).get("choice") or "",
                "project_decision_label": (project_decisions.get(definition["decision_key"]) or {}).get("choice_label") or "",
                "open_groups": len(rows),
                "review_remaining": review_remaining,
                "concrete_decisions": concrete_decisions,
                "decision_counts": decision_counts,
                "high_remaining": sum(
                    1
                    for row in remaining_rows
                    if str(row.get("priority") or "").lower() == "high"
                ),
                "manual_review_fields": sum(int(row.get("draft_manual_review_fields") or 0) for row in rows),
                "history_signals": sum(int(row.get("draft_history_signals") or 0) for row in rows),
                "next_group": {
                    "group_key": next_group.get("group_key") or "",
                    "group_label": next_group.get("group_label") or next_group.get("group_key") or "",
                    "priority": next_group.get("priority") or "",
                    "record_count": int(next_group.get("record_count") or 0),
                    "draft_keeper": next_group.get("draft_keeper") or "",
                    "manual_review_fields": int(next_group.get("draft_manual_review_fields") or 0),
                    "history_signals": int(next_group.get("draft_history_signals") or 0),
                    "decision": next_group.get("decision") or "",
                    "policy_lane": next_group.get("policy_lane") or "",
                }
                if next_group
                else {},
                "export_url": f"/api/export_cleanup_groups?type={definition['group_type']}&status=open&sort=policy",
            }
            for key in ["open_groups", "review_remaining", "concrete_decisions", "high_remaining", "manual_review_fields", "history_signals"]:
                totals[key] += int(queue.get(key) or 0)
            for key in ["merge_later", "keep_separate", "already_handled", "false_positive", "needs_review", "no_decision"]:
                totals[key] += int(decision_counts.get(key) or 0)
            queues.append(queue)
        next_queue = next((queue for queue in queues if queue["review_remaining"]), queues[0] if queues else {})
        return {
            "title": "Guided Review Queue",
            "message": "Work these group-level reviews after the related Project Decisions are saved. Saving a group decision still does not merge, delete, resolve, or rewrite records.",
            "totals": totals,
            "queues": queues,
            "next_queue": next_queue,
            "report": "/reports/cleanup_merge_review_pack.md",
            "export_url": "/api/export?type=cleanup_merge_drafts&status=open",
        }

